window.KANT_WORK_DATA = {"metadata": {"work_id": "aa-IX-logik", "series": "AA", "band": "IX", "title": "Logik (1800)", "short_title": "Logik", "siglum": "AA IX", "edition": "Akademie-Ausgabe (1900–1923) via Kant im Kontext III (2017)", "collection_title": "Digitale Kant-Edition", "citation_systems": ["AA"], "citation_prefix": "AA IX"}, "toc_printed": [{"title": "Logik", "page_kik": 2513, "page_pdf": 2726, "level": 2}, {"title": "[Einleitung.]", "page_kik": 2523, "page_pdf": 2736, "level": 2}, {"title": "[Einleitung.]", "page_kik": 2527, "page_pdf": 2740, "level": 2}, {"title": "[Einleitung.]", "page_kik": 2535, "page_pdf": 2748, "level": 2}, {"title": "[Einleitung.]", "page_kik": 2539, "page_pdf": 2752, "level": 2}, {"title": "[Einleitung.]", "page_kik": 2545, "page_pdf": 2758, "level": 2}, {"title": "[Einleitung.]", "page_kik": 2550, "page_pdf": 2763, "level": 2}, {"title": "[Einleitung.]", "page_kik": 2555, "page_pdf": 2768, "level": 2}, {"title": "[Einleitung.]", "page_kik": 2565, "page_pdf": 2778, "level": 2}, {"title": "[Einleitung.]", "page_kik": 2568, "page_pdf": 2781, "level": 2}, {"title": "[Dritter Abschnitt. Von den Schlüssen.]", "page_kik": 2585, "page_pdf": 2798, "level": 2}, {"title": "[Dritter Abschnitt. Von den Schlüssen.]", "page_kik": 2589, "page_pdf": 2802, "level": 2}, {"title": "[Dritter Abschnitt. Von den Schlüssen.]", "page_kik": 2596, "page_pdf": 2809, "level": 2}, {"title": "[Allgemeine Methodenlehre.]", "page_kik": 2605, "page_pdf": 2818, "level": 2}], "pages": [{"page_pdf": 2726, "page_book": null, "page_kind": "title_page", "sigel": "", "units": [{"type": "paragraph", "text": "Immanuel Kant’s"}, {"type": "heading", "text": "Logik", "level": 2}, {"type": "paragraph", "text": "Ein Handbuch zu Vorlesungen."}, {"type": "paragraph", "text": "[Hrsg.: G.B. Jäsche]"}, {"type": "paragraph", "text": "1800."}]}, {"page_pdf": 2727, "page_book": null, "page_kind": "title_page", "sigel": "", "units": []}, {"page_pdf": 2728, "page_book": 3, "page_kind": "body", "sigel": "AA IX, 3", "units": [{"type": "paragraph", "text": "*Vorrede. [Jäsche]* Es sind bereits anderthalb Jahre, seit mir Kant den Auftrag ertheilte, seine Logik, so wie er sie in öffentlichen Vorlesungen seinen Zuhörern vorgetragen, für den Druck zu bearbeiten, und dieselbe in der Gestalt eines compendiösen Handbuches dem Publicum zu übergeben. Ich erhielt zu diesem Zweck von ihm die selbsteigene Handschrift, deren er sich bei seinen Vorlesungen bedient hatte, mit Äußerung des besondern, ehrenvollen Zutrauens zu mir, daß ich, bekannt mit den Grundsätzen seines Systems überhaupt, auch hier in seinen Ideengang leicht eingehen, seine Gedanken nicht entstellen oder verfälschen, sondern mit der erforderlichen Klarheit und Bestimmtheit und zugleich in der gehörigen Ordnung sie darstellen werde. Da nun auf diese Art, indem ich den ehrenvollen Auftrag übernommen und denselben so gut, als ich vermochte, dem Wunsche und der Erwartung des preißwürdigen Weisen, meines vielverehrten Lehrers und Freundes gemäß, auszuführen gesucht habe, alles, was den Vortrag, die Einkleidung und Ausführung, die Darstellung und Anordnung der Gedanken, betrifft, auf meine Rechnung zum Theil zu setzen ist: so liegt es natürlicher Weise auch mir ob, hierüber den Lesern dieses neuen Kantischen Werkes einige Rechenschaft abzulegen. Über diesen Punkt also hier eine und die andre nähere Erklärung. Seit dem Jahre 1765 hatte Herr Prof. Kant seinen Vorlesungen über die Logik ununterbrochen das Meier’sche Lehrbuch (George Friedrich Meiers Auszug aus der Vernunftlehre, Halle bei Gebauer 1752) als Leitfaden zum Grunde gelegt; aus Gründen, worüber er sich in einem zu Ankündigung seiner Vorlesungen im Jahr 1765 von ihm herausgegebenen Programm erklärte. Das Exemplar des gedachten Compendiums, dessen er sich bei seinen Vorlesungen bediente, ist, wie alle die übrigen Lehrbücher, die er zu gleichem Zwecke brauchte, mit Papier durchschossen; seine allgemeinen Anmerkungen und Erläuterungen so wohl als die speciellern, die sich zunächst auf den Text des Compendiums in den einzelnen §§. beziehen, finden sich theils auf dem durchschossenen Papiere, theils auf dem leeren Rande des Lehrbuches selbst. Und dieses hier und da in zerstreuten Anmerkungen und Erläuterungen schriftlich Aufgezeichnete macht nun zusammen das Materialien-Magazin aus, das Kant hier für seine Vorlesungen anlegte, und das er von Zeit zu Zeit theils durch neue Ideen erweiterte, theils in Ansehung verschiedener einzelner Materien immer wieder von Neuem revidirte und verbesserte. Es enthält also wenigstens das Wesentliche von alle dem, was der berühmte Commentator des Meier’schen Lehrbuches in seinen nach einer freien Manier gehaltenen Vorlesungen seinen Zuhörern über die Logik mitzutheilen pflegte, und das er des Aufzeichnens werth geachtet hatte. Was nun die Darstellung und Anordnung der Sachen in diesem Werke betrifft, so habe ich geglaubt, die Ideen und Grundsätze des großen Mannes am treffendsten auszuführen, wenn ich mich in Absicht auf die Ökonomie und die Eintheilung des Ganzen überhaupt an seine ausdrückliche Erklärung hielte, nach welcher in die eigentliche Abhandlung der Logik und namentlich in die Elementarlehre derselben nichts weiter aufgenommen werden darf als die Theorie von den drei wesentlichen Hauptfunctionen des Denkens: den Begriffen, den Urtheilen und Schlüssen. Alles dasjenige also, was bloß von der Erkenntniß überhaupt und deren logischen Vollkommenheiten handelt und was in dem Meier’schen Lehrbuche der Lehre von den Begriffen vorhergeht und beinahe die Hälfte des Ganzen einnimmt, muß hiernach noch zur Einleitung gerechnet werden. »Vorher war,« bemerkt Kant gleich am Eingange zum achten Abschnitte, worin sein Autor die Lehre von den Begriffen vorträgt – »Vorher war von der Erkenntniß überhaupt gehandelt, als Propädeutik der Logik; jetzt folgt Logik selbst.« Diesem ausdrücklichen Fingerzeige zufolge habe ich daher alles, was bis zu dem erwähnten Abschnitte vorkommt, in die Einleitung herüber genommen, welche aus diesem Grunde einen viel größern Umfang erhalten hat, als sie sonst in andern Handbüchern der Logik einzunehmen pflegt. Die Folge hiervon war denn auch, daß die Methodenlehre, als der andere Haupttheil der Abhandlung, um so viel kürzer ausfallen mußte, je mehr Materien, die übrigens jetzt mit Recht von unsern neuern Logikern in das Gebiet der Methodenlehre gezogen werden, bereits in der Einleitung waren abgehandelt worden, wie z.B. die Lehre von den Beweisen u.dgl.m. Es wäre eine eben so unnöthige als unschickliche Wiederholung gewesen, dieser Materien hier noch einmal an ihrer rechten Stelle Erwähnung zu thun, um nur das Unvollständige vollständig zu machen und alles an seinen gehörigen Ort zu stellen. Das Letztere habe ich indessen doch gethan in Absicht auf die Lehre von den Definitionen und der logischen Eintheilung der Begriffe, welche im Meier’schen Compendium schon zum achten Abschnitte, nämlich zur Elementarlehre von den Begriffen gehört; eine Ordnung, die auch Kant in seinem Vortrage unverändert gelassen hat."}], "markers": [{"system": "AA", "band": "IX", "page": 3, "ref": "IX3"}, {"system": "AA", "band": "IX", "page": 4, "ref": "IX4"}, {"system": "AA", "band": "IX", "page": 5, "ref": "IX5"}], "running_header": "Vorrede: Logik [Jäsche]"}, {"page_pdf": 2729, "page_book": 6, "page_kind": "body", "sigel": "AA IX, 6", "units": [{"type": "paragraph", "text": "Es versteht sich übrigens wohl von selbst, daß der große Reformator der Philosophie und, was die Ökonomie und äußere Form der Logik betrifft, auch dieses Theils der theoretischen Philosophie insbesondre, nach seinem architektonischen Entwurfe, dessen wesentliche Grundlinien in der Kritik der reinen Vernunft verzeichnet sind, die Logik würde bearbeitet haben, wenn es ihm gefallen und wenn sein Geschäft einer wissenschaftlichen Begründung des gesammten Systems der eigentlichen Philosophie, der Philosophie des reellen Wahren und Gewissen, dieses unweit wichtigere und schwerere Geschäft, das nur er zuerst und auch er allein nur in seiner Originalität ausführen konnte, ihm verstattet hätte, an die selbsteigene Bearbeitung einer Logik zu denken. Allein diese Arbeit konnte er recht wohl Andern überlassen, die mit Einsicht und unbefangener Beurtheilung seine architektonischen Ideen zu einer wahrhaft zweckmäßigen und wohlgeordneten Bearbeitung und Behandlung dieser Wissenschaft benutzen konnten. Es war dies von mehreren gründlichen und unbefangenen Denkern unter unsern deutschen Philosophen zu erwarten. Und diese Erwartung hat Kanten und die Freunde seiner Philosophie auch nicht getäuscht. Mehrere neuere Lehrbücher der Logik sind mehr oder weniger, in Betreff der Ökonomie und Disposition des Ganzen, als eine Frucht jener Kantischen Ideen zur Logik anzusehen. Und daß diese Wissenschaft dadurch wirklich gewonnen, daß sie zwar weder reicher noch eigentlich ihrem Gehalte nach solider oder in sich selbst gegründeter, wohl aber gereinigter theils von allen ihr fremdartigen Bestandtheilen, theils von so manchen unnützen Subtilitäten und bloßen dialektischen Spielwerken, daß sie systematischer und doch bei aller scientifischen Strenge der Methode zugleich einfacher geworden: davon muß wohl Jeden, der übrigens nur richtige und klare Begriffe von dem eigenthümlichen Charakter und den gesetzmäßigen Grenzen der Logik hat, auch die flüchtigste Vergleichung der ältern mit den neuern, nach Kantischen Grundsätzen bearbeiteten Lehrbüchern der Logik überzeugen. Denn so sehr sich auch so manche unter den ältern Handbüchern dieser Wissenschaft an wissenschaftlicher Strenge in der Methode, an Klarheit, Bestimmtheit und Präcision in den Erklärungen und an Bündigkeit und Evidenz in den Beweisen auszeichnen mögen: so ist doch fast keines darunter, in welchem nicht die Grenzen der verschiedenen, zur allgemeinen Logik im weitern Umfange gehörigen Gebiete des bloß Propädeutischen, des Dogmatischen und Technischen, des Reinen und Empirischen, so in einander und durch einander liefen, daß sich das eine von dem andern nicht bestimmt unterscheiden läßt. Zwar bemerkt Herr Jakob in der Vorrede zur ersten Auflage seiner Logik: »Wolff habe die Idee einer allgemeinen Logik vortrefflich gefaßt und wenn dieser große Mann darauf gefallen wäre, die reine Logik ganz abgesondert vorzutragen, so hätte er uns gewiß, vermöge seines systematischen Kopfes, ein Meisterstück geliefert, welches alle künftigen Arbeiten dieser Art unnütz gemacht hätte.« Aber er hat diese Idee nun einmal nicht ausgeführt und auch keiner unter seinen Nachfolgern hat sie ausgeführt, so groß und wohlgegründet auch übrigens überhaupt das Verdienst ist, das die Wolffische Schule um das eigentlich Logische, die formale Vollkommenheit in unserm philosophischen Erkenntnisse sich erworben. Aber abgesehen nun von dem, was in Ansehung der äußern Form zu Vervollkommnung der Logik durch die nothwendige Trennung reiner und bloß formaler von empirischen und realen oder metaphysischen Sätzen noch geschehen konnte und geschehen mußte, so ist, wenn es die Beurtheilung und Bestimmung des innern Gehaltes dieser Wissenschaft als Wissenschaft gilt, Kant’s Urtheil über diesen Punkt nicht zweifelhaft. Er hat sich mehreremale bestimmt und ausdrücklich darüber erklärt: daß die Logik als eine abgesonderte, für sich bestehende und in sich selbst gegründete Wissenschaft anzusehen sei, und daß sie mithin auch seit ihrer Entstehung und ersten Ausbildung vom Aristoteles an bis auf unsre Zeiten eigentlich nichts an wissenschaftlicher Begründung habe gewinnen können. Dieser Behauptung gemäß hat also Kant weder an eine Begründung der logischen Principien der Identität und des Widerspruchs selbst durch ein höheres Princip noch an eine Deduction der logischen Formen der Urtheile gedacht. Er hat das Princip des Widerspruchs als einen Satz anerkannt und behandelt, der seine Evidenz in sich selber habe und keiner Ableitung aus einem höhern Grundsatze bedürfe. Nur den Gebrauch, die Gültigkeit dieses Princips hat er eingeschränkt, indem er es aus dem Gebiete der Metaphysik, worin es der Dogmatismus geltend zu machen suchte, verwies und auf den bloß logischen Vernunftgebrauch, als allein gültig nur für diesen Gebrauch, beschränkte. Ob nun aber wirklich der logische Satz der Identität und des Widerspruchs an sich und schlechthin keiner weitern Deduction fähig und bedürftig sei, das ist freilich eine andre Frage, die auf die vielbedeutende Frage führt: ob es überhaupt ein absolut erstes Princip aller Erkenntniß und Wissenschaft gebe, ob ein solches möglich sei und gefunden werden könne?"}], "markers": [{"system": "AA", "band": "IX", "page": 6, "ref": "IX6"}, {"system": "AA", "band": "IX", "page": 7, "ref": "IX7"}], "running_header": "Vorrede: Logik [Jäsche]"}, {"page_pdf": 2730, "page_book": 8, "page_kind": "body", "sigel": "AA IX, 8", "units": [{"type": "paragraph", "text": "Die Wissenschaftslehre glaubt, ein solches Princip in dem reinen, absoluten Ich entdeckt und damit das gesammte philosophische Wissen nicht der bloßen Form, sondern auch dem Gehalte nach vollkommen begründet zu haben. Und unter Voraussetzung der Möglichkeit und apodiktischen Gültigkeit dieses absolut einigen und unbedingten Princips handelt sie daher auch vollkommen consequent, wenn sie die logischen Grundsätze der Identität und des Widerspruches, die Sätze: _A_ = _A_ und _–A_= _–A_ nicht als unbedingt gelten läßt, sondern nur für subalterne Sätze erklärt, die durch sie und ihren obersten Satz: Ich bin, erst erwiesen und bestimmt werden können und müssen. (Siehe Grundl. d.W.L. S.13 etc.) Auf eine gleich consequente Art erklärt sich auch Schelling in seinem System des transscendentalen Idealismus gegen die Voraussetzung der logischen Grundsätze als unbedingter, d.h. von keinen höhern abzuleitender, indem die Logik überhaupt nur durch Abstraction von bestimmten Sätzen und, sofern sie auf wissenschaftliche Art entsteht, nur durch Abstraction von den obersten Grundsätzen des Wissens entstehen könne, und folglich diese höchsten Grundsätze des Wissens und mit ihnen die Wissenschaftslehre selbst schon voraussetze. Da aber von der andern Seite diese höchsten Grundsätze des Wissens, als Grundsätze betrachtet, eben so nothwendig die logische Form schon voraussetzen: so entsteht eben hieraus jener Zirkel, der sich zwar für die Wissenschaft nicht auflösen, aber doch erklären läßt, erklären durch Anerkennung eines zugleich der Form und dem Gehalte nach (formellen und materiellen) ersten Princips der Philosophie, in welchem beides, Form und Gehalt, sich wechselseitig bedingt und begründet. In diesem Princip läge sodann der Punkt, in welchem das Subjective und das Objective, das identische und das synthetische Wissen, eines und dasselbe wären. Unter Voraussetzung einer solchen Dignität, wie sie einem solchen Princip ohne Zweifel zukommen muß, würde demnach die Logik, so wie jede andre Wissenschaft, der Wissenschaftslehre und deren Principien subordinirt sein müssen. Welche Bewandtniß es nun aber auch immer hiermit haben möge, so viel ist ausgemacht: in jedem Falle bleibt die Logik im Innern ihres Bezirkes, was das Wesentliche betrifft, unverändert; und die transscendentale Frage: ob die logischen Sätze noch einer Ableitung aus einem höhern, absoluten Princip fähig und bedürftig sind, kann auf sie selbst und die Gültigkeit und Evidenz ihrer Gesetze so wenig Einfluß haben, als auf die reine Mathematik in Ansehung ihres wissenschaftlichen Gehalts die transscendentale Aufgabe hat: Wie sind synthetische Urtheile _a priori_ in der Mathematik möglich? So wie der Mathematiker als Mathematiker, so kann auch der Logiker als Logiker innerhalb des Bezirks seiner Wissenschaft beim Erklären und Beweisen seinen Gang ruhig und sicher fortgehen, ohne sich um die außer seiner Sphäre liegende transscendentale Frage des Transscendental-Philosophen und Wissenschaftslehrers bekümmern zu dürfen: Wie reine Mathematik oder reine Logik als Wissenschaft möglich sei? Bei dieser allgemeinen Anerkennung der Richtigkeit der allgemeinen Logik ist daher auch der Streit zwischen den Skeptikern und den Dogmatikern über die letzten Gründe des philosophischen Wissens, nie auf dem Gebiete der Logik, deren Regeln jeder vernünftige Skeptiker so gut als der Dogmatiker für gültig anerkannte, sondern jederzeit auf dem Gebiete der Metaphysik geführt worden. Und wie konnte es anders sein? Die höchste Aufgabe der eigentlichen Philosophie betrifft ja keinesweges das subjective, sondern das objective, nicht das identische, sondern das synthetische Wissen. Hierbei bleibt also die Logik als solche gänzlich aus dem Spiele, und es hat weder der Kritik noch der Wissenschaftslehre einfallen können – noch wird es überall einer Philosophie, die den transscendentalen Standpunkt von dem bloß logischen bestimmt zu unterscheiden weiß, einfallen können – die letzten Gründe des realen philosophischen Wissens innerhalb des Gebiets der bloßen Logik zu suchen und aus einem Satze der Logik, bloß als solchem betrachtet, ein reales Object herausklauben zu wollen. Wer den himmelweiten Unterschied zwischen der eigentlichen (allgemeinen) Logik, als einer bloß formalen Wissenschaft, der Wissenschaft des bloßen Denkens als Denkens betrachtet, und der Transscendental-Philosophie, dieser einigen materialen oder realen reinen Vernunftwissenschaft, der Wissenschaft des eigentlichen Wissens, bestimmt ins Auge gefaßt hat und nie wieder aus der Acht läßt, wird daher leicht beurtheilen können, was von dem neuern Versuche zu halten sei, den Herr Bardili neuerdings (in seinem Grundrisse der ersten Logik) unternommen hat, der Logik selbst noch ihr _Prius_ auszumachen, in der Erwartung, auf dem Wege dieser Untersuchung zu finden: »ein reales Object, entweder durch sie (die bloße Logik) gesetzt oder sonst überall keines setzbar; den Schlüssel zum Wesen der Natur entweder durch sie gegeben oder sonst überall keine Logik und keine Philosophie möglich.« Es ist doch in Wahrheit nicht abzusehen, auf welche mögliche Art Herr Bardili aus seinem aufgestellten _Prius_ der Logik, dem The doctrine of science believes to have discovered such a principle in the pure, absolute I and thus to have completely founded the entire philosophical knowledge not only in form but also in content. And under the condition of the possibility and apodictic validity of this absolutely uniﬁed and unconditional principle, it therefore also acts completely consequently when it excludes the logical principles of dentity and contradiction, the propositions: A = A and -A= -A as unconditional, but declares them only as subaltern propositions, which can and must ﬁrst be proven and determined by them and their supreme proposition: I am. (See Grundl. d.W.L. p.13 etc.) In an equally consequent way, Schelling, too, in his System of Transcendental Idealism, declares himself against the presupposition of logical principles as unconditional, i.e. not to be derived from any higher ones, in that logic in general can only arise through abstraction from certain propositions and, insofar as it arises in a scientiﬁc way, only through abstraction from the highest principles of knowledge, and consequently already presupposes these highest principles of knowledge and, with them, the theory of science itself. But since, from the other side, these highest principles of knowledge, considered as principles, just as necessarily already presuppose the ogical form, from this arises that circle which, though t cannot be resolved for science, can nevertheless be explained by recognizing a ﬁrst principle of philosophy, both in form and content (formal and material), in which both form and content mutually condition and justify each other. In this principle would then lie the point in which the subjective and the objective, the identical and the synthetic knowledge, would be one and the same. On the condition of such a dignity as must undoubtedly belong to such a principle, logic, like every other science, would have to be subordinated to the doctrine of science and its principles. Whatever may be the meaning of this, however, this much is certain: in every case, logic remains unchanged in the interior of its domain, as far as the essential is concerned; and the transcendental question: whether the logical propositions are still capable of and in need of a derivation from a higher, absolute principle, can have as little inﬂuence on it and the validity and evidence of its laws as the transcendental task has on pure mathematics in view of its scientiﬁc content: How are synthetic judgments a priori possible in mathematics? Just as the mathematician as a mathematician, so also the ogician as a logician can go on his way calmly and safely within the sphere of his science in explaining and proving, without being allowed to worry about the transcendental question of the transcendental philosopher and science teacher, which lies outside his sphere: How pure mathematics or pure logic is possible as science? With this general recognition of the correctness of the general logic, therefore, the dispute between the skeptics and the dogmatists about the last reasons of philosophical knowledge, has never been conducted n the ﬁeld of logic, whose rules every reasonable skeptic recognized as valid as the dogmatist, but at any time in the ﬁeld of metaphysics. And how could it be otherwise? The highest task of philosophy proper does not concern the subjective, but the objective, not the identical, but the synthetic knowledge. Here, therefore, logic as such remains entirely out of the picture, and it could not have occurred to either criticism or science - nor will it ever occur to a philosophy that knows how to distinguish the transcendental point of view from the merely logical one - to seek the ultimate grounds of real philosophical knowledge within the domain of mere ogic and to want to pick out a real object from a proposition of logic considered merely as such. Translated with www.DeepL.com/Translator (free version)"}], "markers": [{"system": "AA", "band": "IX", "page": 8, "ref": "IX8"}, {"system": "AA", "band": "IX", "page": 9, "ref": "IX9"}], "running_header": "Vorrede: Logik [Jäsche]"}, {"page_pdf": 2731, "page_book": 10, "page_kind": "body", "sigel": "AA IX, 10", "units": [{"type": "paragraph", "text": "Princip der absoluten Möglichkeit des Denkens, nach welchem wir Eines als Eines und Ebendasselbe im Vielen (nicht Mannigfaltigen) unendlichemal wiederholen können, ein reales Object herausfinden könne. Dieses vermeintlich neu entdeckte _Prius_ der Logik ist ja offenbar nichts mehr und nichts weniger als das alte längst anerkannte, innerhalb des Gebiets der Logik gelegene und an die Spitze dieser Wissenschaft gestellte Princip der Identität: Was ich denke, denke ich, und eben dieses und nichts anders kann ich nun eben ins Unendliche wiederholt denken. – Wer wird denn auch bei dem wohl verstandenen logischen Satze der Identität an ein Mannigfaltiges und nicht an ein bloßes Vieles denken, das allerdings durch nichts anders entsteht noch entstehen kann, als durch bloße Wiederholung Eines und Ebendesselben Denkens, das bloße wiederholte Setzen eines _A_ = _A_ = _A_ und so weiter ins Unendliche fort. Schwerlich dürfte sich daher wohl auf dem Wege, den Herr Bardili dazu eingeschlagen und nach derjenigen heuristischen Methode, deren er sich hierzu bedient hat, dasjenige finden lassen, woran der philosophirenden Vernunft gelegen ist, der Anfangs- und Endpunkt, wovon sie bei ihren Untersuchungen ausgehen und wohin sie wiederum zurückkehren könne. Die hauptsächlichsten und bedeutendsten Einwürfe, die Herr Bardili Kanten und seiner Methode des Philosophirens entgegensetzt, könnten also auch nicht so wohl Kanten den Logiker, als vielmehr Kanten den Transscendental-Philosophen und Metaphysiker treffen. Wir können sie daher hier insgesammt an ihren gehörigen Ort dahin gestellt sein lassen. Schließlich will ich hier noch bemerken: daß ich die Kantische Metaphysik, wozu ich die Handschrift auch bereits in den Händen habe, so bald es die Muße mir verstattet, nach derselben Manier bearbeiten und herausgeben werde. Königsberg, den 20sten September 1800."}, {"type": "paragraph", "text": "Gottlob Benjamin Jäsche, Doctor und Privatdocent der Philosophie auf der Universität in Königsberg, Mitglied der gelehrten Gesellschaft zu Frankfurt an der Oder."}], "markers": [{"system": "AA", "band": "IX", "page": 10, "ref": "IX10"}], "running_header": "Vorrede: Logik [Jäsche]"}, {"page_pdf": 2732, "page_book": 11, "page_kind": "body", "sigel": "AA IX, 11", "units": [{"type": "paragraph", "text": "Einleitung. I. Begriff der Logik. Alles in der Natur, sowohl in der leblosen als auch in der belebten Welt, geschieht nach Regeln, ob wir gleich diese Regeln nicht immer kennen. – Das Wasser fällt nach Gesetzen der Schwere, und bei den Thieren geschieht die Bewegung des Gehens auch nach Regeln. Der Fisch im Wasser, der Vogel in der Luft bewegt sich nach Regeln. Die ganze Natur überhaupt ist eigentlich nichts anders als ein Zusammenhang von Erscheinungen nach Regeln; und es giebt überall keine Regellosigkeit. Wenn wir eine solche zu finden meinen, so können wir in diesem Falle nur sagen: daß uns die Regeln unbekannt sind. Auch die Ausübung unsrer Kräfte geschieht nach gewissen Regeln, die wir befolgen, zuerst derselben unbewußt, bis wir zu ihrer Erkenntniß allmählig durch Versuche und einen längern Gebrauch unsrer Kräfte gelangen, ja uns am Ende dieselben so geläufig machen, daß es uns viele Mühe kostet, sie _in abstracto_ zu denken. So ist z.B. die allgemeine Grammatik die Form einer Sprache überhaupt. Man spricht aber auch, ohne Grammatik zu kennen; und der, welcher, ohne sie zu kennen, spricht, hat wirklich eine Grammatik und spricht nach Regeln, deren er sich aber nicht bewußt ist. So wie nun alle unsre Kräfte insgesammt, so ist auch insbesondre der Verstand bei seinen Handlungen an Regeln gebunden, die wir untersuchen können. Ja, der Verstand ist als der Quell und das Vermögen anzusehen, Regeln überhaupt zu denken. Denn so wie die Sinnlichkeit das Vermögen der Anschauungen ist, so ist der Verstand das Vermögen zu denken, d.h. die Vorstellungen der Sinne unter Regeln zu bringen. Er ist daher begierig, Regeln zu suchen, und befriedigt, wenn er sie gefunden hat. Es frägt sich also, da der Verstand die Quelle der Regeln ist, nach welchen Regeln er selber verfahre? Denn es leidet gar keinen Zweifel: wir können nicht denken oder unsern Verstand nicht anders gebrauchen als nach gewissen Regeln. Diese Regeln können wir nun aber wieder für sich selbst denken, d.h. wir können sie ohne ihre Anwendung oder _in abstracto_ denken. Welches sind nun diese Regeln?"}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Alle Regeln, nach denen der Verstand verfährt, sind entweder nothwendig oder zufällig. Die erstern sind solche, ohne welche gar kein Gebrauch des Verstandes möglich wäre; die letztern solche, ohne welche ein gewisser bestimmter Verstandesgebrauch nicht stattfinden würde. Die zufälligen Regeln, welche von einem bestimmten Object der Erkenntniß abhängen, sind so vielfältig als diese Objecte selbst. So giebt es z.B. einen Verstandesgebrauch in der Mathematik, der Metaphysik, Moral u.s.w. Die Regeln dieses besondern bestimmten Verstandesgebrauches in den gedachten Wissenschaften sind zufällig, weil es zufällig ist, ob ich dieses oder jenes Object denke, worauf sich diese besondern Regeln beziehen. Wenn wir nun aber alle Erkenntniß, die wir bloß von den Gegenständen entlehnen müssen, bei Seite setzen und lediglich auf den Verstandesgebrauch überhaupt reflectiren: so entdecken wir diejenigen Regeln desselben, die in aller Absicht und unangesehen aller besondern Objecte des Denkens schlechthin nothwendig sind, weil wir ohne sie gar nicht denken würden. Diese Regeln können daher auch _a priori_ d.i. unabhängig von aller Erfahrung eingesehen werden, weil sie, ohne Unterschied der Gegenstände, bloß die Bedingungen des Verstandesgebrauchs überhaupt, er mag rein oder empirisch sein, enthalten. Und hieraus folgt zugleich: daß die allgemeinen und nothwendigen Regeln des Denkens überhaupt lediglich die Form, keinesweges die Materie desselben betreffen können. Demnach ist die Wissenschaft, die diese allgemeinen und nothwendigen Regeln enthält, bloß eine Wissenschaft von der Form unsers"}], "markers": [{"system": "AA", "band": "IX", "page": 11, "ref": "IX11"}, {"system": "AA", "band": "IX", "page": 12, "ref": "IX12"}], "running_header": "I. Begriff der Logik"}, {"page_pdf": 2733, "page_book": 13, "page_kind": "body", "sigel": "AA IX, 13", "units": [{"type": "paragraph", "text": "Verstandeserkenntnisses oder des Denkens. Und wir können uns also eine Idee von der Möglichkeit einer solchen Wissenschaft machen, so wie von einer allgemeinen Grammatik, die nichts weiter als die bloße Form der Sprache überhaupt enthält, ohne Wörter, die zur Materie der Sprache gehören. Diese Wissenschaft von den nothwendigen Gesetzen des Verstandes und der Vernunft überhaupt oder, welches einerlei ist, von der bloßen Form des Denkens überhaupt, nennen wir nun Logik."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Als eine Wissenschaft, die auf alles Denken überhaupt geht, unangesehen der Objecte als der Materie des Denkens ist die Logik 1) als Grundlage zu allen andern Wissenschaften und als die Propädeutik alles Verstandesgebrauchs anzusehen. Sie kann aber auch eben darum, weil sie von allen Objecten gänzlich abstrahirt, 2) kein Organon der Wissenschaften sein. Unter einem Organon verstehen wir nämlich eine Anweisung, wie ein gewisses Erkenntniß zu Stande gebracht werden solle. Dazu aber gehört, daß ich das Object der nach gewissen Regeln hervorzubringenden Erkenntniß schon kenne. Ein Organon der Wissenschaften ist daher nicht bloße Logik, weil es die genaue Kenntniß der Wissenschaften, ihrer Objecte und Quellen voraussetzt. So ist z.B. die Mathematik ein vortreffliches Organon, als eine Wissenschaft, die den Grund der Erweiterung unserer Erkenntniß in Ansehung eines gewissen Vernunftgebrauches enthält. Die Logik hingegen, da sie als allgemeine Propädeutik alles Verstandes- und Vernunftgebrauchs überhaupt, nicht in die Wissenschaften gehen und deren Materie anticipiren darf, ist nur eine allgemeine Vernunftkunst (_canonica Epicuri_), Erkenntnisse überhaupt der Form des Verstandes gemäß zu machen, und also nur in so fern ein Organon zu nennen, das aber freilich nicht zur Erweiterung, sondern bloß zur Beurtheilung und Berichtigung unsers Erkenntnisses dient. 3) Als eine Wissenschaft der nothwendigen Gesetze des Denkens, ohne welche gar kein Gebrauch des Verstandes und der Vernunft stattfindet, die folglich die Bedingungen sind, unter denen der Verstand einzig mit sich selbst zusammen stimmen kann und soll, – die nothwendigen Gesetze und Bedingungen seines richtigen Gebrauchs – ist aber die Logik ein Kanon. Und als ein Kanon des Verstandes und der Vernunft darf sie daher auch keine Principien weder aus irgend einer Wissenschaft noch aus irgend einer Erfahrung borgen; sie muß lauter Gesetze _a priori_, welche nothwendig sind und auf den Verstand überhaupt gehen, enthalten. Einige Logiker setzen zwar in der Logik psychologische Principien voraus. Dergleichen Principien aber in die Logik zu bringen, ist eben so ungereimt als Moral vom Leben herzunehmen. Nähmen wir die Principien aus der Psychologie, d.h. aus den Beobachtungen über unsern Verstand, so würden wir bloß sehen, wie das Denken vor sich geht und wie es ist unter den mancherlei subjectiven Hindernissen und Bedingungen; dieses würde also zur Erkenntniß bloß zufälliger Gesetze führen. In der Logik ist aber die Frage nicht nach zufälligen, sondern nach nothwendigen Regeln; nicht, wie wir denken, sondern, wie wir denken sollen. Die Regeln der Logik müssen daher nicht vom zufälligen, sondern vom nothwendigen Verstandesgebrauche hergenommen sein, den man ohne alle Psychologie bei sich findet. Wir wollen in der Logik nicht wissen: wie der Verstand ist und denkt und wie er bisher im Denken verfahren ist, sondern wie er im Denken verfahren sollte. Sie soll uns den richtigen, d.h. den mit sich selbst übereinstimmenden Gebrauch des Verstandes lehren."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Aus der gegebenen Erklärung der Logik lassen sich nun auch noch die übrigen wesentlichen"}], "markers": [{"system": "AA", "band": "IX", "page": 13, "ref": "IX13"}, {"system": "AA", "band": "IX", "page": 14, "ref": "IX14"}], "running_header": "I. Begriff der Logik"}, {"page_pdf": 2734, "page_book": 15, "page_kind": "body", "sigel": "AA IX, 15", "units": [{"type": "paragraph", "text": "Eigenschaften dieser Wissenschaft herleiten; nämlich daß sie 4) eine Vernunftwissenschaft sei nicht der bloßen Form, sondern der Materie nach, da ihre Regeln nicht aus der Erfahrung hergenommen sind und da sie zugleich die Vernunft zu ihrem Objecte hat. Die Logik ist daher eine Selbsterkenntniß des Verstandes und der Vernunft, aber nicht nach den Vermögen derselben in Ansehung der Objecte, sondern lediglich der Form nach. Ich werde in der Logik nicht fragen: Was erkennt der Verstand und wie viel kann er erkennen oder wie weit geht seine Erkenntniß? Denn das wäre Selbsterkenntniß in Ansehung seines materiellen Gebrauchs und gehört also in die Metaphysik. In der Logik ist nur die Frage: Wie wird sich der Verstand selbst erkennen? Als eine der Materie und der Form nach rationale Wissenschaft ist die Logik endlich auch 5) eine Doctrin oder demonstrirte Theorie. Denn da sie sich nicht mit dem gemeinen und als solchem bloß empirischen Verstandes- und Vernunftgebrauche, sondern lediglich mit den allgemeinen und nothwendigen Gesetzen des Denkens überhaupt beschäftigt: so beruht sie auf Principien _a priori_, aus denen alle ihre Regeln abgeleitet und bewiesen werden können, als solche, denen alle Erkenntniß der Vernunft gemäß sein müßte. Dadurch daß die Logik als eine Wissenschaft _a priori_ oder als eine Doctrin für einen Kanon des Verstandes- und Vernunftgebrauchs zu halten ist, unterscheidet sie sich wesentlich von der Ästhetik, die als bloße Kritik des Geschmacks keinen Kanon (Gesetz), sondern nur eine Norm (Muster oder Richtschnur bloß zur Beurtheilung) hat, welche in der allgemeinen Einstimmung besteht. Die Ästhetik nämlich enthält die Regeln der Übereinstimmung des Erkenntnisses mit den Gesetzen der Sinnlichkeit; die Logik dagegen die Regeln der Übereinstimmung des Erkenntnisses mit den Gesetzen des Verstandes und der Vernunft. Jene hat nur empirische Principien und kann also nie Wissenschaft oder Doctrin sein, wofern man unter Doctrin eine dogmatische Unterweisung aus Principien _a priori_ versteht, wo man alles durch den Verstand ohne anderweitige, von der Erfahrung erhaltene Belehrungen einsieht, und die uns Regeln giebt, deren Befolgung die verlangte Vollkommenheit verschafft. Manche, besonders Redner und Dichter haben versucht, über den Geschmack zu vernünfteln, aber nie haben sie ein entscheidendes Urtheil darüber fällen können. Der Philosoph Baumgarten in Frankfurt hatte den Plan zu einer Ästhetik, als Wissenschaft, gemacht. Allein richtiger hat Home die Ästhetik Kritik genannt, da sie keine Regeln _a priori_ giebt, die das Urtheil hinreichend bestimmen, wie die Logik, sondern ihre Regeln _a posteriori_ hernimmt, und die empirischen Gesetze, nach denen wir das Unvollkommnere und Vollkommnere (Schöne) erkennen, nur durch die Vergleichung allgemeiner macht. Die Logik ist also mehr als bloße Kritik; sie ist ein Kanon, der nachher zur Kritik dient, d.h. zum Princip der Beurtheilung alles Verstandesgebrauchs überhaupt, wiewohl nur seiner Richtigkeit in Ansehung der bloßen Form, da sie kein Organon ist, so wenig als die allgemeine Grammatik. Als Propädeutik alles Verstandesgebrauchs überhaupt unterscheidet sich die allgemeine Logik nun auch zugleich von einer andern Seite von der transscendentalen Logik, in welcher der Gegenstand selbst als ein Gegenstand des bloßen Verstandes vorgestellt wird; dagegen die allgemeine Logik auf alle Gegenstände überhaupt geht. Fassen wir nun alle wesentlichen Merkmale zusammen, die zu ausführlicher Bestimmung des Begriffs der Logik gehören, so werden wir also folgenden Begriff von ihr aufstellen müssen: Die Logik ist eine Vernunftwissenschaft nicht der bloßen Form, sondern der Materie nach; eine Wissenschaft _a priori_ von den nothwendigen Gesetzen des Denkens, aber nicht in Ansehung besonderer Gegenstände, sondern aller Gegenstände überhaupt; – also eine Wissenschaft des richtigen Verstandes- und Vernunftgebrauchs überhaupt, aber nicht subjectiv, d.h. nicht nach empirischen (psychologischen) Principien, wie der Verstand denkt, sondern objectiv, d.i."}], "markers": [{"system": "AA", "band": "IX", "page": 15, "ref": "IX15"}, {"system": "AA", "band": "IX", "page": 16, "ref": "IX16"}], "running_header": "I. Begriff der Logik"}, {"page_pdf": 2735, "page_book": 15, "page_kind": "body", "sigel": "AA IX, 15", "units": [{"type": "paragraph", "text": "nach Principien _a priori_, wie er denken soll."}], "running_header": "I. Begriff der Logik"}, {"page_pdf": 2736, "page_book": 16, "page_kind": "body", "sigel": "AA IX, 16", "units": [{"type": "heading", "text": "[Einleitung.]", "level": 2}, {"type": "paragraph", "text": "II. Haupteintheilungen der Logik. – Vortrag. – Nutzen dieser Wissenschaft. – Abriß einer Geschichte derselben. Die Logik wird eingetheilt 1) in die Analytik und in die Dialektik. Die Analytik entdeckt durch Zergliederung alle Handlungen der Vernunft, die wir beim Denken überhaupt ausüben. Sie ist also eine Analytik der Verstandes- und Vernunftform und heißt auch mit Recht die Logik der Wahrheit, weil sie die nothwendigen Regeln aller (formalen) Wahrheit enthält, ohne welche unser Erkenntniß, unangesehen der Objecte, auch in sich selbst unwahr ist. Sie ist also auch weiter nichts als ein Kanon zur Dijudication (der formalen Richtigkeit unsers Erkenntnisses). Wollte man diese bloß theoretische und allgemeine Doctrin zu einer praktischen Kunst, d.i. zu einem Organon brauchen: so würde sie Dialektik werden. Eine Logik des Scheins (_ars _ _sophistica_, _disputatoria_), die aus einem bloßen Mißbrauche der Analytik entspringt, sofern nach der bloßen logischen Form der Schein einer wahren Erkenntniß, deren Merkmale doch von der Übereinstimmung mit den Objecten, also vom Inhalte hergenommen sein müssen, erkünstelt wird. In den vorigen Zeiten wurde die Dialektik mit großem Fleiße studirt. Diese Kunst trug falsche Grundsätze unter dem Scheine der Wahrheit vor und suchte diesen gemäß, Dinge dem Scheine nach zu behaupten. Bei den Griechen waren die Dialektiker die Sachwalter und Redner, welche das Volk leiten konnten, wohin sie wollten, weil sich das Volk durch den Schein hintergehen läßt. Dialektik war also damals die Kunst des Scheins. In der Logik wurde sie auch eine Zeitlang unter dem Namen der Disputirkunst vorgetragen, und so lange war alle Logik und Philosophie die Cultur gewisser geschwätziger Köpfe, jeden Schein zu erkünsteln. Nichts aber kann eines Philosophen unwürdiger sein als die Cultur einer solchen Kunst. Sie muß daher in dieser Bedeutung gänzlich wegfallen und statt derselben vielmehr eine Kritik dieses Scheines in die Logik eingeführt werden. Wir würden demnach zwei Theile der Logik haben: die Analytik, welche die formalen Kriterien der Wahrheit vortrüge und die Dialektik, welche die Merkmale und Regeln enthielte, wonach wir erkennen könnten, daß etwas mit den formalen Kriterien der Wahrheit nicht übereinstimmt, ob es gleich mit denselben übereinzustimmen scheint. Die Dialektik in dieser Bedeutung würde also ihren guten Nutzen haben als Katharktikon des Verstandes. Man pflegt die Logik ferner einzutheilen 2) in die natürliche oder populare und in die künstliche oder wissenschaftliche Logik (_logica naturalis_, _log. scholastica_ _s. artificialis_). Aber diese Eintheilung ist unstatthaft. Denn die natürliche Logik oder die Logik der gemeinen Vernunft (_sensus communis_) ist eigentlich keine Logik, sondern eine anthropologische Wissenschaft, die nur empirische Principien hat, indem sie von den Regeln des natürlichen Verstandes- und Vernunftgebrauchs handelt, die nur _in concreto_, also ohne Bewußtsein derselben _in abstracto_, erkannt werden. – Die künstliche oder wissenschaftliche Logik verdient daher allein diesen Namen, als eine Wissenschaft der nothwendigen und allgemeinen Regeln des Denkens, die unabhängig von dem natürlichen Verstandes- und Vernunftgebrauche _in concreto_ _a priori_ erkannt werden können und müssen, ob sie gleich zuerst nur durch Beobachtung jenes natürlichen Gebrauchs gefunden werden können. 3) Noch eine andre Eintheilung der Logik ist die in theoretische und praktische Logik. Allein auch diese Eintheilung ist unrichtig. Die allgemeine Logik, die, als ein bloßer Kanon, von allen Objecten abstrahirt, kann keinen"}], "markers": [{"system": "AA", "band": "IX", "page": 16, "ref": "IX16"}, {"system": "AA", "band": "IX", "page": 17, "ref": "IX17"}], "running_header": "II. Haupteinteilungen der Logik"}, {"page_pdf": 2737, "page_book": 18, "page_kind": "body", "sigel": "AA IX, 18", "units": [{"type": "paragraph", "text": "praktischen Theil haben. Dieses wäre eine _contradictio in adjecto_, weil eine praktische Logik die Kenntniß einer gewissen Art von Gegenständen, worauf sie angewandt wird, voraussetzt. Wir können daher jede Wissenschaft eine praktische Logik nennen; denn in jeder müssen wir eine Form des Denkens haben. Die allgemeine Logik, als praktisch betrachtet, kann daher nichts weiter sein als eine Technik der Gelehrsamkeit überhaupt, ein Organon der Schulmethode. Dieser Eintheilung zufolge würde also die Logik einen dogmatischen und einen technischen Theil haben. Der erste würde die Elementarlehre, der andere die Methodenlehre heißen können. Der praktische oder technische Theil der Logik wäre eine logische Kunst in Ansehung der Anordnung und der logischen Kunstausdrücke und Unterschiede, um dem Verstande dadurch sein Handeln zu erleichtern. In beiden Theilen, dem technischen so wohl als dem dogmatischen, würde aber weder auf Objecte noch auf das Subject des Denkens die mindeste Rücksicht genommen werden dürfen. In der letztern Beziehung würde die Logik eingetheilt werden können 4) in die reine und in die angewandte Logik. In der reinen Logik sondern wir den Verstand von den übrigen Gemüthskräften ab und betrachten, was er für sich allein thut. Die angewandte Logik betrachtet den Verstand, sofern er mit den andern Gemüthskräften vermischt ist, die auf seine Handlungen einfließen und ihm eine schiefe Richtung geben, so daß er nicht nach den Gesetzen verfährt, von denen er wohl selbst einsieht, daß sie die richtigen sind. Die angewandte Logik sollte eigentlich nicht Logik heißen. Es ist eine Psychologie, in welcher wir betrachten, wie es bei unserm Denken zuzugehen pflegt, nicht, wie es zugehen soll. Am Ende sagt sie zwar, was man thun soll, um unter mancherlei subjectiven Hindernissen und Einschränkungen einen richtigen Gebrauch vom Verstande zu machen; auch können wir von ihr lernen, was den richtigen Verstandesgebrauch befördert, die Hülfsmittel desselben oder die Heilungsmittel von logischen Fehlern und Irrthümern. Aber Propädeutik ist sie doch nicht. Denn die Psychologie, aus welcher in der angewandten Logik alles genommen werden muß, ist ein Theil der philosophischen Wissenschaften, zu denen die Logik die Propädeutik sein soll. Zwar sagt man: die Technik, oder die Art und Weise, eine Wissenschaft zu bauen, solle in der angewandten Logik vorgetragen werden. Das ist aber vergeblich, ja sogar schädlich. Man fängt dann an zu bauen, ehe man Materialien hat und giebt wohl die Form, es fehlt aber am Inhalte. Die Technik muß bei jeder Wissenschaft vorgetragen werden. Was endlich 5) die Eintheilung der Logik in die Logik des gemeinen und die des speculativen Verstandes betrifft: so bemerken wir hierbei, daß diese Wissenschaft gar nicht so eingetheilt werden kann. Sie kann keine Wissenschaft des speculativen Verstandes sein. Denn als eine Logik des speculativen Erkenntnisses oder des speculativen Vernunftgebrauchs wäre sie ein Organon andrer Wissenschaften und keine bloße Propädeutik, die auf allen möglichen Gebrauch des Verstandes und der Vernunft gehen soll. Eben so wenig kann die Logik ein Product des gemeinen Verstandes sein. Der gemeine Verstand nämlich ist das Vermögen, die Regeln des Erkenntnisses _in concreto_ einzusehen. Die Logik soll aber eine Wissenschaft von den Regeln des Denkens _in abstracto_ sein. Man kann indessen den allgemeinen Menschenverstand zum Object der Logik annehmen, und in so fern wird sie von den besonderen Regeln der speculativen Vernunft abstrahiren und sich also von der Logik des speculativen Verstandes unterscheiden."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Was den Vortrag der Logik betrifft: so kann derselbe entweder scholastisch oder"}], "markers": [{"system": "AA", "band": "IX", "page": 18, "ref": "IX18"}, {"system": "AA", "band": "IX", "page": 19, "ref": "IX19"}], "running_header": "II. Haupteinteilungen der Logik"}, {"page_pdf": 2738, "page_book": 20, "page_kind": "body", "sigel": "AA IX, 20", "units": [{"type": "paragraph", "text": "popular sein. Scholastisch ist er, sofern er angemessen ist der Wißbegierde, den Fähigkeiten und der Cultur derer, die das Erkenntniß der logischen Regeln als eine Wissenschaft behandeln wollen. Popular aber, wenn er zu den Fähigkeiten und Bedürfnissen derjenigen sich herabläßt, welche die Logik nicht als Wissenschaft studiren, sondern sie nur brauchen wollen, um ihren Verstand aufzuklären. – Im scholastischen Vortrage müssen die Regeln in ihrer Allgemeinheit oder _in _ _abstracto_; im popularen dagegen im Besondern oder _in concreto_ dargestellt werden. Der scholastische Vortrag ist das Fundament des popularen; denn nur derjenige kann etwas auf eine populare Weise vortragen, der es auch gründlicher vortragen könnte. Wir unterscheiden übrigens hier Vortrag von Methode. Unter Methode nämlich ist die Art und Weise zu verstehen, wie ein gewisses Object, zu dessen Erkenntniß sie anzuwenden ist, vollständig zu erkennen sei. Sie muß aus der Natur der Wissenschaft selbst hergenommen werden und läßt sich also, als eine dadurch bestimmte und nothwendige Ordnung des Denkens, nicht ändern. Vortrag bedeutet nur die Manier, seine Gedanken andern mitzutheilen, um eine Doctrin verständlich zu machen."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Aus dem, was wir über das Wesen und den Zweck der Logik bisher gesagt haben, läßt sich nunmehr der Werth dieser Wissenschaft und der Nutzen ihres Studiums nach einem richtigen und bestimmten Maaßstabe schätzen. Die Logik ist also zwar keine allgemeine Erfindungskunst und kein Organon der Wahrheit – keine Algebra, mit deren Hülfe sich verborgene Wahrheiten entdecken ließen. Wohl aber ist sie nützlich und unentbehrlich als eine Kritik der Erkenntniß, oder zu Beurtheilung der gemeinen so wohl als der speculativen Vernunft, nicht um sie zu lehren, sondern nur um sie correct und mit sich selbst übereinstimmend zu machen. Denn das logische Princip der Wahrheit ist Übereinstimmung des Verstandes mit seinen eigenen allgemeinen Gesetzen."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Was endlich die Geschichte der Logik betrifft, so wollen wir hierüber nur Folgendes anführen: Die jetzige Logik schreibt sich her von Aristoteles’ Analytik. Dieser Philosoph kann als der Vater der Logik angesehen werden. Er trug sie als Organon vor und theilte sie ein in Analytik und Dialektik. Seine Lehrart ist sehr scholastisch und geht auf die Entwickelung der allgemeinsten Begriffe, die der Logik zum Grunde liegen, wovon man indessen keinen Nutzen hat, weil fast alles auf bloße Subtilitäten hinausläuft, außer daß man die Benennungen verschiedener Verstandeshandlungen daraus gezogen. Übrigens hat die Logik von Aristoteles’ Zeiten her an Inhalt nicht viel gewonnen und das kann sie ihrer Natur nach auch nicht. Aber sie kann wohl gewinnen in Ansehung der Genauigkeit, Bestimmtheit und Deutlichkeit. Es giebt nur wenige Wissenschaften, die in einen beharrlichen Zustand kommen können, wo sie nicht mehr verändert werden. Zu diesen gehört die Logik und auch die Metaphysik. Aristoteles hatte keinen Moment des Verstandes ausgelassen; wir sind darin nur genauer, methodischer und ordentlicher. Von Lamberts Organon glaubte man zwar, daß es die Logik sehr vermehren würde. Aber es enthält weiter nichts mehr als nur subtilere Eintheilungen, die, wie alle richtigen Subtilitäten wohl den Verstand schärfen, aber von keinem wesentlichen Gebrauche sind. Unter den neuern Weltweisen giebt es zwei, welche die allgemeine Logik in Gang gebracht haben: Leibniz und Wolff. Malebranche und Locke haben keine eigentliche Logik abgehandelt, da sie auch vom Inhalte der Erkenntniß und vom Ursprunge der Begriffe handeln. Die allgemeine Logik von Wolff ist die beste, welche man hat. Einige haben sie mit der"}], "markers": [{"system": "AA", "band": "IX", "page": 20, "ref": "IX20"}, {"system": "AA", "band": "IX", "page": 21, "ref": "IX21"}], "running_header": "II. Haupteinteilungen der Logik"}, {"page_pdf": 2739, "page_book": 20, "page_kind": "body", "sigel": "AA IX, 20", "units": [{"type": "paragraph", "text": "Aristotelischen verbunden, wie z.B. Reusch. Baumgarten, ein Mann, der hierin viel Verdienst hat, concentrirte die Wolffische Logik, und Meier commentirte dann wieder über Baumgarten. Zu den neuern Logikern gehört auch Crusius, der aber nicht bedachte, was es mit der Logik für eine Bewandtniß habe. Denn seine Logik enthält metaphysische Grundsätze und überschreitet also in so fern die Grenzen dieser Wissenschaft; überdies stellt sie ein Kriterium der Wahrheit auf, das kein Kriterium sein kann, und läßt also in so fern allen Schwärmereien freien Lauf. In den jetzigen Zeiten hat es eben keinen berühmten Logiker gegeben, und wir brauchen auch zur Logik keine neuen Erfindungen, weil sie bloß die Form des Denkens enthält."}, {"type": "paragraph", "text": "——————"}], "running_header": "II. Haupteinteilungen der Logik"}, {"page_pdf": 2740, "page_book": 21, "page_kind": "body", "sigel": "AA IX, 21", "units": [{"type": "heading", "text": "[Einleitung.]", "level": 2}, {"type": "paragraph", "text": "III. Begriff von der Philosophie überhaupt. – Philosophie nach dem Schulbegriffe und nach dem Weltbegriffe betrachtet. – Wesentliche Erfordernisse und Zwecke des Philosophirens. – Allgemeinste und höchste Aufgaben dieser Wissenschaft. Es ist zuweilen schwer, das, was unter einer Wissenschaft verstanden wird, zu erklären. Aber die Wissenschaft gewinnt an Präcision durch Festsetzung ihres bestimmten Begriffs, und es werden so manche Fehler aus gewissen Gründen vermieden, die sich sonst einschleichen, wenn man die Wissenschaft noch nicht von den mit ihr verwandten Wissenschaften unterscheiden kann. Ehe wir indessen eine Definition von Philosophie zu geben versuchen, müssen wir zuvor den Charakter der verschiedenen Erkenntnisse selbst untersuchen und, da philosophische Erkenntnisse zu den Vernunfterkenntnissen gehören, insbesondre erklären, was unter diesen letztern zu verstehen sei. Vernunfterkenntnisse werden den historischen Erkenntnissen entgegengesetzt. Jene sind Erkenntnisse aus Principien (_ex principiis_); diese Erkenntnisse aus Daten (ex datis). – Eine Erkenntniß kann aber aus der Vernunft entstanden und demohngeachtet historisch sein; wie wenn z.B. ein bloßer Literator die Producte fremder Vernunft lernt, so ist sein Erkenntniß von dergleichen Vernunftproducten bloß historisch. Man kann nämlich Erkenntnisse unterscheiden 1) nach ihrem objectiven Ursprunge, d.i. nach den Quellen, woraus eine Erkenntniß allein möglich ist. In dieser Rücksicht sind alle Erkenntnisse entweder rational oder empirisch; 2) nach ihrem subjectiven Ursprunge, d.i. nach der Art, wie eine Erkenntniß von den Menschen kann erworben werden. Aus diesem letztern Gesichtspunkte betrachtet, sind die Erkenntnisse entweder rational oder historisch, sie mögen an sich entstanden sein, wie sie wollen. Es kann also objectiv etwas ein Vernunfterkenntniß sein, was subjectiv doch nur historisch ist. Bei einigen rationalen Erkenntnissen ist es schädlich, sie bloß historisch zu wissen, bei andern hingegen ist dieses gleichgültig. So weiß z.B. der Schiffer die Regeln der Schiffahrt historisch aus seinen Tabellen; und das ist für ihn genug. Wenn aber der Rechtsgelehrte die Rechtsgelehrsamkeit bloß historisch weiß, so ist er zum ächten Richter und noch mehr zum Gesetzgeber völlig verdorben. Aus dem angegebenen Unterschiede zwischen objectiv und subjectiv rationalen Erkenntnissen erhellt nun auch, daß man Philosophie in gewissem Betracht lernen könne, ohne philosophiren zu können. Der also eigentlich Philosoph werden will, muß sich üben, von seiner Vernunft einen freien und keinen bloß nachahmenden und, so zu sagen, mechanischen Gebrauch zu machen."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Wir haben die Vernunfterkenntnisse für Erkenntnisse aus Principien erklärt und hieraus folgt: daß sie _a priori_ sein müssen. Es giebt aber zwei Arten von Erkenntnissen, die beide _a priori_ sind, dennoch aber viele namhafte Unterschiede haben, nämlich Mathematik und Philosophie. Man pflegt zu behaupten, daß Mathematik und Philosophie dem Objecte nach von einander unterschieden wären, indem die erstere von der Quantität, die letztere von der Qualität handele. Alles dieses ist falsch. Der Unterschied dieser Wissenschaften kann nicht auf dem Objecte beruhen, denn Philosophie geht auf alles, also auch auf _quanta_, und Mathematik zum Theil auch, sofern alles eine Größe hat. Nur die verschiedene Art des Vernunfterkenntnisses oder Vernunftgebrauches in der Mathematik und Philosophie"}], "markers": [{"system": "AA", "band": "IX", "page": 21, "ref": "IX21"}, {"system": "AA", "band": "IX", "page": 22, "ref": "IX22"}, {"system": "AA", "band": "IX", "page": 23, "ref": "IX23"}], "running_header": "III. Begriff von der Philosophie überhaupt"}, {"page_pdf": 2741, "page_book": 24, "page_kind": "body", "sigel": "AA IX, 24", "units": [{"type": "paragraph", "text": "macht allein den specifischen Unterschied zwischen diesen beiden Wissenschaften aus. Philosophie nämlich ist die Vernunfterkenntniß aus bloßen Begriffen, Mathematik hingegen die Vernunfterkenntniß aus der Construction der Begriffe. Wir construiren Begriffe, wenn wir sie in der Anschauung _a priori_ ohne Erfahrung darstellen oder, wenn wir den Gegenstand in der Anschauung darstellen, der unserm Begriffe von demselben entspricht. – Der Mathematiker kann sich nie seiner Vernunft nach bloßen Begriffen, der Philosoph ihrer nie durch Construction der Begriffe bedienen. In der Mathematik braucht man die Vernunft _in concreto_, die Anschauung ist aber nicht empirisch, sondern man macht sich hier etwas _a priori_ zum Gegenstande der Anschauung. Und hierin hat also, wie wir sehen, die Mathematik einen Vorzug vor der Philosophie, daß die Erkenntnisse der erstern intuitive, die der letztern hingegen nur discursive Erkenntnisse sind. Die Ursache aber, warum wir in der Mathematik mehr die Größen erwägen, liegt darin, daß die Größen in der Anschauung _a priori_ können construirt werden, die Qualitäten dagegen sich nicht in der Anschauung darstellen lassen."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Philosophie ist also das System der philosophischen Erkenntnisse oder der Vernunfterkenntnisse aus Begriffen. Das ist der Schulbegriff von dieser Wissenschaft. Nach dem Weltbegriffe ist sie die Wissenschaft von den letzten Zwecken der menschlichen Vernunft. Dieser hohe Begriff giebt der Philosophie Würde, d.i. einen absoluten Werth. Und wirklich ist sie es auch, die allein nur innern Werth hat, und allen andern Erkenntnissen erst einen Werth giebt. Man frägt doch immer am Ende, wozu dient das Philosophiren und der Endzweck desselben die Philosophie selbst als Wissenschaft nach dem Schulbegriffe betrachtet? In dieser scholastischen Bedeutung des Worts geht Philosophie nur auf Geschicklichkeit; in Beziehung auf den Weltbegriff dagegen auf die Nützlichkeit. In der erstern Rücksicht ist sie also eine Lehre der Geschicklichkeit; in der letztern, eine Lehre der Weisheit : die Gesetzgeberin der Vernunft und der Philosoph in so fern nicht Vernunftkünstler, sondern Gesetzgeber. Der Vernunftkünstler oder, wie Sokrates ihn nennt, der Philodox, strebt bloß nach speculativem Wissen, ohne darauf zu sehen, wie viel das Wissen zum letzten Zwecke der menschlichen Vernunft beitrage; er giebt Regeln für den Gebrauch der Vernunft zu allerlei beliebigen Zwecken. Der praktische Philosoph, der Lehrer der Weisheit durch Lehre und Beispiel, ist der eigentliche Philosoph. Denn Philosophie ist die Idee einer vollkommenen Weisheit, die uns die letzten Zwecke der menschlichen Vernunft zeigt. Zur Philosophie nach dem Schulbegriffe gehören zwei Stücke: Erstlich ein zureichender Vorrath von Vernunfterkenntnissen, für’s Andre: ein systematischer Zusammenhang dieser Erkenntnisse oder eine Verbindung derselben in der Idee eines Ganzen. Einen solchen streng systematischen Zusammenhang verstattet nicht nur die Philosophie, sondern sie ist sogar die einzige Wissenschaft, die im eigentlichsten Verstande einen systematischen Zusammenhang hat und allen andern Wissenschaften systematische Einheit giebt. Was aber Philosophie nach dem Weltbegriffe (_ in sensu cosmico_) betrifft: so kann man sie auch eine Wissenschaft von der höchsten Maxime des Gebrauchs unserer Vernunft nennen, sofern man unter Maxime das innere Princip der Wahl unter verschiedenen Zwecken versteht. Denn Philosophie in der letztern Bedeutung ist ja die Wissenschaft der Beziehung alles Erkenntnisses und Vernunftgebrauchs auf den Endzweck der menschlichen Vernunft, dem, als"}], "markers": [{"system": "AA", "band": "IX", "page": 24, "ref": "IX24"}], "running_header": "III. Begriff von der Philosophie überhaupt"}, {"page_pdf": 2742, "page_book": 25, "page_kind": "body", "sigel": "AA IX, 25", "units": [{"type": "paragraph", "text": "dem obersten, alle andern Zwecke subordinirt sind und sich in ihm zur Einheit vereinigen müssen. Das Feld der Philosophie in dieser weltbürgerlichen Bedeutung läßt sich auf folgende Fragen bringen: 1) Was kann ich wissen? 2) Was soll ich thun? 3) Was darf ich hoffen? 4) Was ist der Mensch? Die erste Frage beantwortet die Metaphysik, die zweite die Moral, die dritte die Religion und die vierte die Anthropologie. Im Grunde könnte man aber alles dieses zur Anthropologie rechnen, weil sich die drei ersten Fragen auf die letzte beziehen. Der Philosoph muß also bestimmen können 1) die Quellen des menschlichen Wissens, 2) den Umfang des möglichen und nützlichen Gebrauchs alles Wissens und endlich 3) die Grenzen der Vernunft. Das letztere ist das nöthigste aber auch das schwerste, um das sich aber der Philodox nicht bekümmert. Zu einem Philosophen gehören hauptsächlich zwei Dinge: 1) Cultur des Talents und der Geschicklichkeit, um sie zu allerlei Zwecken zu gebrauchen. 2) Fertigkeit im Gebrauch aller Mittel zu beliebigen Zwecken. Beides muß vereinigt sein; denn ohne Kenntnisse wird man nie ein Philosoph werden, aber nie werden auch Kenntnisse allein den Philosophen ausmachen, wofern nicht eine zweckmäßige Verbindung aller Erkenntnisse und Geschicklichkeiten zur Einheit hinzukommt und eine Einsicht in die Übereinstimmung derselben mit den höchsten Zwecken der menschlichen Vernunft. Es kann sich überhaupt keiner einen Philosophen nennen, der nicht philosophiren kann. Philosophiren läßt sich aber nur durch Übung und selbsteigenen Gebrauch der Vernunft lernen. Wie sollte sich auch Philosophie eigentlich lernen lassen? Jeder philosophische Denker baut, so zu sagen, auf den Trümmern eines Andern sein eigenes Werk, nie aber ist eines zu Stande gekommen, das in allen seinen Theilen beständig gewesen wäre. Man kann daher schon aus dem Grunde Philosophie nicht lernen, weil sie noch nicht gegeben ist. Gesetzt aber auch, es wäre eine wirklich vorhanden: so würde doch keiner, der sie auch lernte, von sich sagen können, daß er ein Philosoph sei, denn seine Kenntniß davon wäre doch immer nur subjectiv-historisch. In der Mathematik verhält sich die Sache anders. Diese Wissenschaft kann man wohl gewissermaßen lernen, denn die Beweise sind hier so evident, daß ein jeder davon überzeugt werden kann; auch kann sie ihrer Evidenz wegen als eine gewisse und beständige Lehre gleichsam aufbehalten werden. Der philosophiren lernen will, darf dagegen alle Systeme der Philosophie nur als Geschichte des Gebrauchs der Vernunft ansehen und als Objecte der Übung seines philosophischen Talents. Der wahre Philosoph muß also als Selbstdenker einen freien und selbsteigenen, keinen sklavisch nachahmenden Gebrauch von seiner Vernunft machen. Aber auch keinen dialektischen, d.i. keinen solchen Gebrauch, der nur darauf abzweckt, den Erkenntnissen einen Schein von Wahrheit und Weisheit zu geben. Dieses ist das Geschäft des bloßen Sophisten, aber mit der Würde des Philosophen, als eines Kenners und Lehrers der Weisheit, durchaus unverträglich. Denn Wissenschaft hat einen innern, wahren Werth nur als Organ der Weisheit. Als solches ist sie ihr aber auch unentbehrlich, so daß man wohl behaupten darf: Weisheit ohne Wissenschaft sei ein Schattenriß von einer Vollkommenheit, zu der wir nie gelangen werden. Der die Wissenschaft haßt, um desto mehr aber die Weisheit liebt, den nennt man einen Misologen. Die Misologie entspringt gemeiniglich aus einer Leerheit von wissenschaftlichen"}], "markers": [{"system": "AA", "band": "IX", "page": 25, "ref": "IX25"}, {"system": "AA", "band": "IX", "page": 26, "ref": "IX26"}], "running_header": "III. Begriff von der Philosophie überhaupt"}, {"page_pdf": 2743, "page_book": 25, "page_kind": "body", "sigel": "AA IX, 25", "units": [{"type": "paragraph", "text": "Kenntnissen und einer gewissen damit verbundenen Art von Eitelkeit. Zuweilen verfallen aber auch diejenigen in den Fehler der Misologie, welche anfangs mit großem Fleiße und Glücke den Wissenschaften nachgegangen waren, am Ende aber in ihrem ganzen Wissen keine Befriedigung fanden. Philosophie ist die einzige Wissenschaft, die uns diese innere Genugthuung zu verschaffen weiß, denn sie schließt gleichsam den wissenschaftlichen Zirkel und durch sie erhalten sodann erst die Wissenschaften Ordnung und Zusammenhang. Wir werden also zum Behuf der Übung im Selbstdenken oder Philosophiren mehr auf die Methode unsers Vernunftgebrauchs zu sehen haben als auf die Sätze selbst, zu denen wir durch dieselbe gekommen sind."}], "running_header": "III. Begriff von der Philosophie überhaupt"}, {"page_pdf": 2744, "page_book": 27, "page_kind": "body", "sigel": "AA IX, 27", "units": [{"type": "paragraph", "text": "[Einleitung.] IV. Kurzer Abriß einer Geschichte der Philosophie. Es macht einige Schwierigkeit, die Grenzen zu bestimmen, wo der gemeine Verstandesgebrauch aufhört und der speculative anfängt, oder, wo gemeine Vernunfterkenntniß Philosophie wird. Indessen giebt es doch hier ein ziemlich sicheres Unterscheidungsmerkmal, nämlich folgendes: Die Erkenntniß des Allgemeinen _in abstracto_ ist speculative Erkenntniß, die Erkenntniß des Allgemeinen _in concreto_ gemeine Erkenntniß. Philosophische Erkenntniß ist speculative Erkenntniß der Vernunft und sie fängt also da an, wo der gemeine Vernunftgebrauch anhebt, Versuche in der Erkenntniß des Allgemeinen _in abstracto_ zu machen. Aus dieser Bestimmung des Unterschiedes zwischen gemeinem und speculativem Vernunftgebrauche läßt sich nun beurtheilen, von welchem Volke man den Anfang des Philosophirens datiren müsse. Unter allen Völkern haben also die Griechen erst angefangen zu philosophiren. Denn sie haben zuerst versucht, nicht an dem Leitfaden der Bilder die Vernunfterkenntnisse zu cultiviren, sondern _in abstracto_; statt daß die andern Völker sich die Begriffe immer nur durch Bilder _in concreto_ verständlich zu machen suchten. So giebt es noch heutiges Tages Völker, wie die Chineser und einige Indianer, die zwar von Dingen, welche bloß aus der Vernunft hergenommen sind, als von Gott, der Unsterblichkeit der Seele u.dgl.m. handeln, aber doch die Natur dieser Gegenstände nicht nach Begriffen und Regeln _in abstracto_ zu erforschen suchen. Sie machen hier keine Trennung zwischen dem Vernunftgebrauche _in concreto_ und dem _in abstracto_. Bei den Persern und Arabern findet sich zwar einiger speculativer Vernunftgebrauch, allein die Regeln dazu haben sie vom Aristoteles, also doch von den Griechen entlehnt. In Zoroasters Zendavesta entdeckt man nicht die geringste Spur von Philosophie. Eben dieses gilt auch von der gepriesenen ägyptischen Weisheit, die in Vergleichung mit der griechischen Philosophie ein bloßes Kinderspiel gewesen ist. Wie in der Philosophie, so sind auch in Ansehung der Mathematik die Griechen die ersten gewesen, welche diesen Theil des Vernunfterkenntnisses nach einer speculativen, wissenschaftlichen Methode cultivirten, indem sie jeden Lehrsatz aus Elementen demonstrirt haben. Wenn und Wo aber unter den Griechen der philosophische Geist zuerst entsprungen sei, das kann man eigentlich nicht bestimmen. Der erste, welcher den Gebrauch der speculativen Vernunft einführte, und von dem man auch die ersten Schritte des menschlichen Verstandes zur wissenschaftlichen Cultur herleitete, ist Thales, der Urheber der ionischen Secte. Er führte den Beinamen Physiker, wiewohl er auch Mathematiker war; so wie überhaupt Mathematik der Philosophie immer vorangegangen ist. Übrigens kleideten die ersten Philosophen alles in Bilder ein. Denn Poesie, die nichts anderes ist als eine Einkleidung der Gedanken in Bilder, ist älter als die Prose. Man mußte sich daher anfangs selbst bei Dingen, die lediglich Objecte der reinen Vernunft sind, der Bildersprache und poetischen Schreibart bedienen. Pherekydes soll der erste prosaische Schriftsteller gewesen sein. Auf die Ionier folgten die Eleatiker. Der Grundsatz der eleatischen Philosophie und ihres Stifters Xenophanes war: in den Sinnen ist Täuschung und Schein, nur im Verstande allein liegt die Quelle der Wahrheit. Unter den Philosophen dieser Schule zeichnete sich Zeno als ein Mann von großem Verstande und Scharfsinne und als ein subtiler Dialektiker aus. Die Dialektik bedeutete anfangs die Kunst des reinen Verstandesgebrauchs in Ansehung abstracter, von aller Sinnlichkeit abgesonderter Begriffe. Daher die vielen Lobeserhebungen dieser Kunst bei den Alten. In der Folge, als diejenigen Philosophen, welche gänzlich das"}], "markers": [{"system": "AA", "band": "IX", "page": 27, "ref": "IX27"}, {"system": "AA", "band": "IX", "page": 28, "ref": "IX28"}], "running_header": "IV. Kurzer Abriß einer Geschichte der Philosophie"}, {"page_pdf": 2745, "page_book": 29, "page_kind": "body", "sigel": "AA IX, 29", "units": [{"type": "paragraph", "text": "Zeugniß der Sinne verwarfen, bei dieser Behauptung nothwendig auf viele Subtilitäten verfallen mußten, artete Dialektik in die Kunst aus, jeden Satz zu behaupten und zu bestreiten. Und so ward sie eine bloße Übung für die Sophisten, die über alles raisonniren wollten und sich darauf legten, dem Scheine den Anstrich des Wahren zu geben und schwarz weiß zu machen. Deswegen wurde auch der Name Sophist, unter dem man sich sonst einen Mann dachte, der über alle Sachen vernünftig und einsichtsvoll reden konnte, jetzt so verhaßt und verächtlich und statt desselben der Name Philosoph eingeführt."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Um die Zeit der ionischen Schule stand in Groß-Griechenland ein Mann von seltsamen Genie auf, welcher nicht nur auch eine Schule errichtete, sondern zugleich ein Project entwarf und zu Stande brachte, das seines Gleichen noch nie gehabt hatte. Dieser Mann war Pythagoras, zu Samos geboren. Er stiftete nämlich eine Societät von Philosophen, die durch das Gesetz der Verschwiegenheit zu einem Bunde unter sich vereinigt waren. Seine Zuhörer theilte er in zwei Klassen ein: in die der Akusmatiker (Âkousmajðikoi), die bloß hören mußten, und die der Akroamatiker (Âkroamajðikoi), die auch fragen durften. Unter seinen Lehren gab es einige exoterische, die er dem ganzen Volke vortrug; die übrigen waren geheim und esoterisch, nur für die Mitglieder seines Bundes bestimmt, von denen er einige in seine vertrauteste Freundschaft aufnahm und von den übrigen ganz absonderte. Zum Vehikel seiner geheimen Lehren machte er Physik und Theologie, also die Lehre des Sichtbaren und des Unsichtbaren. Auch hatte er verschiedene Symbole, die vermuthlich nichts anders als gewisse Zeichen gewesen sind, welche den Pythagoräern dazu gedient haben, sich untereinander zu verständigen. Der Zweck seines Bundes scheint kein anderer gewesen zu sein, als: die Religion von dem Wahn des Volks zu reinigen, die Tyrannei zu mäßigen und mehrere Gesetzmäßigkeit in die Staaten einzuführen. Dieser Bund aber, den die Tyrannen zu fürchten anfingen, wurde kurz vor Pythagoras’ Tode zerstört, und diese philosophische Gesellschaft aufgelöst, theils durch Hinrichtung, theils durch die Flucht und Verbannung des größten Theils der Verbündeten. Die Wenigen, welche noch übrig blieben, waren Novizen. Und da diese nicht viel von des Pythagoras eigenthümlichen Lehren wußten, so kann man davon auch nichts Gewisses und Bestimmtes sagen. In der Folge hat man dem Pythagoras, der übrigens auch ein sehr mathematischer Kopf war, viele Lehren zugeschrieben, die aber gewiß nur erdichtet sind."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Die wichtigste Epoche der griechischen Philosophie hebt endlich mit dem Sokrates an. Denn er war es, welcher dem philosophischen Geiste und allen speculativen Köpfen eine ganz neue praktische Richtung gab. Auch ist er fast unter allen Menschen der einzige gewesen, dessen Verhalten der Idee eines Weisen am nächsten kommt. Unter seinen Schülern ist Plato, der sich mehr mit den praktischen Lehren des Sokrates beschäftigte, und unter den Schülern des Plato Aristoteles, welcher die speculative Philosophie wieder höher brachte, der berühmteste. Auf Plato und Aristoteles folgten die Epikuräer und die Stoiker, welche beide die abgesagtesten Feinde von einander waren. Jene setzten das höchste Gut in ein fröhliches Herz, das sie die Wollust nannten; diese fanden es einzig in der Hoheit und Stärke der Seele, bei welcher man alle Annehmlichkeiten des Lebens entbehren könne. Die Stoiker waren übrigens in der speculativen Philosophie dialektisch, in der Moralphilosophie dogmatisch und zeigten in ihren praktischen Principien, wodurch sie den Samen zu den erhabensten Gesinnungen, die je existirten, ausgestreut haben, ungemein viel Würde. Der Stifter der stoischen Schule ist Zeno aus Citium. Die berühmtesten Männer aus"}], "markers": [{"system": "AA", "band": "IX", "page": 29, "ref": "IX29"}, {"system": "AA", "band": "IX", "page": 30, "ref": "IX30"}], "running_header": "IV. Kurzer Abriß einer Geschichte der Philosophie"}, {"page_pdf": 2746, "page_book": 31, "page_kind": "body", "sigel": "AA IX, 31", "units": [{"type": "paragraph", "text": "dieser Schule unter den griechischen Weltweisen sind Kleanth und Chrysipp. Die epikurische Schule hat nie in den Ruf kommen können, worin die stoische war. Was man aber auch immer von den Epikuräern sagen mag, so viel ist gewiß: sie bewiesen die größte Mäßigung im Genusse und waren die besten Naturphilosophen unter allen Denkern Griechenlands. Noch merken wir hier an, daß die vornehmsten griechischen Schulen besondere Namen führten. So hieß die Schule des Plato Akademie, die des Aristoteles Lyceum, die Schule der Stoiker _Porticus_ (stoa), ein bedeckter Gang, wovon der Name Stoiker sich herschreibt, die Schule des Epikurs _horti_, weil Epikur in Gärten lehrte. Auf Platos Akademie folgten noch drei andere Akademien, die von seinen Schülern gestiftet wurden. Die erste stiftete Speusippus, die zweite Arkesilaus und die dritte Karneades. Diese Akademien neigten sich zum Skepticismus hin. Speusippus und Arkesilaus, beide stimmten ihre Denkart zur Skepsis und Karneades trieb es darin noch höher. Um deswillen werden die Skeptiker, diese subtilen, dialektischen Philosophen, auch Akademiker genannt. Die Akademiker folgten also dem ersten großen Zweifler Pyrrho und dessen Nachfolgern. Dazu hatte ihnen ihr Lehrer Plato selbst Anlaß gegeben, indem er viele seiner Lehren dialogisch vortrug, so daß Gründe _pro_ und _contra_ angeführt wurden, ohne daß er selbst darüber entschied, ob er gleich sonst sehr dogmatisch war. Fängt man die Epoche des Skepticismus mit dem Pyrrho an, so bekommt man eine ganze Schule von Skeptikern, die sich in ihrer Denkart und Methode des Philosophirens von den Dogmatikern wesentlich unterschieden, indem sie es zur ersten Maxime alles philosophirenden Vernunftgebrauchs machten: auch selbst bei dem größten Scheine der Wahrheit sein Urtheil zurückzuhalten, und das Princip aufstellten: die Philosophie bestehe im Gleichgewichte des Urtheilens und lehre uns den falschen Schein aufzudecken. Von diesen Skeptikern ist uns aber weiter nichts übrig geblieben als die beiden Werke des Sextus Empiricus, worin er alle Zweifel zusammengebracht hat."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Als in der Folge die Philosophie von den Griechen zu den Römern überging, hat sie sich nicht erweitert; denn die Römer blieben immer nur Schüler. Cicero war in der speculativen Philosophie ein Schüler des Plato, in der Moral ein Stoiker. Zur stoischen Secte gehörten Epiktet, Antonin der Philosoph und Seneca, als die berühmtesten. Naturlehrer gab es unter den Römern nicht, außer Plinius dem jüngern, der eine Naturbeschreibung hinterlassen hat. Endlich verschwand die Cultur auch bei den Römern und es entstand Barbarei, bis die Araber im 6ten und 7ten Jahrhundert anfingen, sich auf die Wissenschaften zu legen und den Aristoteles wieder in Flor zu bringen. Nun kamen also die Wissenschaften im Occident wieder empor und insbesondere das Ansehen des Aristoteles, dem man aber auf eine sklavische Weise folgte. Im 11ten und 12ten Jahrhundert traten die Scholastiker auf; sie erläuterten den Aristoteles und trieben seine Subtilitäten ins Unendliche. Man beschäftigte sich mit nichts als lauter Abstractionen. Diese scholastische Methode des After-Philosophirens wurde zur Zeit der Reformation verdrängt, und nun gab es Eklektiker in der Philosophie, d.i. solche Selbstdenker, die sich zu keiner Schule bekannten, sondern die Wahrheit suchten und annahmen, wo sie sie fanden. Ihre Verbesserung in den neueren Zeiten verdankt aber die Philosophie theils dem größeren Studium der Natur, theils der Verbindung der Mathematik mit der Naturwissenschaft. Die Ordnung, welche durch das Studium dieser Wissenschaften im Denken entstand, breitete sich auch über die besonderen Zweige und Theile der eigentlichen Weltweisheit aus. Der erste und größte"}], "markers": [{"system": "AA", "band": "IX", "page": 31, "ref": "IX31"}, {"system": "AA", "band": "IX", "page": 32, "ref": "IX32"}], "running_header": "IV. Kurzer Abriß einer Geschichte der Philosophie"}, {"page_pdf": 2747, "page_book": 33, "page_kind": "body", "sigel": "AA IX, 33", "units": [{"type": "paragraph", "text": "Naturforscher der neuern Zeit war Baco von Verulam. Er betrat bei seinen Untersuchungen den Weg der Erfahrung und machte auf die Wichtigkeit und Unentbehrlichkeit der Beobachtungen und Versuche zur Entdeckung der Wahrheit aufmerksam. Es ist übrigens schwer zu sagen, von wo die Verbesserung der speculativen Philosophie eigentlich herkommt. Ein nicht geringes Verdienst um dieselbe erwarb sich Descartes, indem er viel dazu beitrug, dem Denken Deutlichkeit zu geben durch sein aufgestelltes Kriterium der Wahrheit, das er in die Klarheit und Evidenz der Erkenntniß setzte. Unter die größten und verdienstvollsten Reformatoren der Philosophie zu unsern Zeiten ist aber Leibniz und Locke zu rechnen. Der letztere suchte den menschlichen Verstand zu zergliedern und zu zeigen, welche Seelenkräfte und welche Operationen derselben zu dieser oder jener Erkenntniß gehörten. Aber er hat das Werk seiner Untersuchung nicht vollendet, auch ist sein Verfahren dogmatisch, wiewohl er den Nutzen stiftete, daß man anfing, die Natur der Seele besser und gründlicher zu studiren. Was die besondre, Leibnizen und Wolffen eigene, dogmatische Methode des Philosophirens betrifft, so war dieselbe sehr fehlerhaft. Auch liegt darin so viel Täuschendes, daß es wohl nöthig ist, das ganze Verfahren zu suspendiren und statt dessen ein anderes, die Methode des kritischen Philosophirens, in Gang zu bringen, die darin besteht, das Verfahren der Vernunft selbst zu untersuchen, das gesammte menschliche Erkenntnißvermögen zu zergliedern und zu prüfen: wie weit die Grenzen desselben wohl gehen mögen. In unserm Zeitalter ist Naturphilosophie im blühendsten Zustande, und unter den Naturforschern giebt es große Namen z.B. Newton. Neuere Philosophen lassen sich jetzt als ausgezeichnete und bleibende Namen eigentlich nicht nennen, weil hier alles gleichsam im Flusse fortgeht. Was der eine baut, reißt der andere nieder. In der Moralphilosophie sind wir nicht weiter gekommen als die Alten. Was aber Metaphysik betrifft: so scheint es, als wären wir bei Untersuchung metaphysischer Wahrheiten stutzig geworden. Es zeigt sich jetzt eine Art von Indifferentism gegen diese Wissenschaft, da man es sich zur Ehre zu machen scheint, von metaphysischen Nachforschungen als von bloßen Grübeleien verächtlich zu reden. Und doch ist Metaphysik die eigentliche, wahre Philosophie! Unser Zeitalter ist das Zeitalter der Kritik, und man muß sehen, was aus den kritischen Versuchen unsrer Zeit, in Absicht auf Philosophie und Metaphysik insbesondre, werden wird."}], "markers": [{"system": "AA", "band": "IX", "page": 33, "ref": "IX33"}], "running_header": "IV. Kurzer Abriß einer Geschichte der Philosophie"}, {"page_pdf": 2748, "page_book": 33, "page_kind": "body", "sigel": "AA IX, 33", "units": [{"type": "heading", "text": "[Einleitung.]", "level": 2}, {"type": "paragraph", "text": "V. Erkenntniß überhaupt. – Intuitive und discursive Erkenntniß; Anschauung und Begriff und deren Unterschied insbesondre. – Logische und ästhetische Vollkommenheit des Erkenntnisses. Alle unsre Erkenntniß hat eine zwiefache Beziehung: erstlich eine Beziehung auf das Object, zweitens eine Beziehung auf das Subject. In der erstern Rücksicht bezieht sie sich auf Vorstellung, in der letztern aufs Bewußtsein, die allgemeine Bedingung alles Erkenntnisses überhaupt. – (Eigentlich ist das Bewußtsein eine Vorstellung, daß eine andre Vorstellung in mir ist.) In jeder Erkenntniß muß unterschieden werden Materie, d.i. der Gegenstand, und Form, d.i. die Art, wie wir den Gegenstand erkennen. – Sieht z.B. ein Wilder ein Haus aus der Ferne, dessen Gebrauch er nicht kennt: so hat er zwar eben dasselbe Object wie ein Anderer, der es bestimmt als eine für Menschen eingerichtete Wohnung kennt, in der Vorstellung vor sich. Aber der Form nach ist dieses Erkenntniß eines und desselben Objects in beiden verschieden. Bei dem Einen ist es bloße Anschauung, bei dem Andern Anschauung und Begriff zugleich. Die Verschiedenheit der Form des Erkenntnisses beruht auf einer Bedingung, die alles Erkennen begleitet, auf dem Bewußtsein. Bin ich mir der Vorstellung bewußt: so ist sie klar; bin ich mir derselben nicht bewußt, dunkel. Da das Bewußtsein die wesentliche Bedingung aller logischen Form der Erkenntnisse ist: so kann und darf sich die Logik auch nur mit klaren, nicht aber mit dunkeln Vorstellungen beschäftigen. Wir sehen in der Logik nicht, wie Vorstellungen entspringen, sondern lediglich, wie dieselben mit der logischen Form übereinstimmen. – Überhaupt kann die Logik auch gar nicht von den bloßen Vorstellungen und deren Möglichkeit handeln. Das überläßt sie der Metaphysik. Sie selbst beschäftigt sich bloß mit den Regeln des Denkens bei Begriffen, Urtheilen und Schlüssen, als wodurch alles Denken geschieht. Freilich geht etwas vorher, ehe eine Vorstellung Begriff wird. Das werden wir an seinem Orte auch anzeigen. Wir werden aber nicht untersuchen: Wie Vorstellungen entspringen? Zwar handelt die Logik auch vom Erkennen, weil beim Erkennen schon Denken stattfindet. Aber Vorstellung ist noch nicht Erkenntniß, sondern Erkenntniß setzt immer Vorstellung voraus. Und diese letztere läßt sich auch durchaus nicht erklären. Denn man müßte, was Vor stellung sei? doch immer wiederum durch eine andere Vorstellung erklären. Alle klaren Vorstellungen, auf die sich allein die logischen Regeln anwenden lassen, können nun unterschieden werden in Ansehung der Deutlichkeit und Undeutlichkeit. Sind wir uns der ganzen Vorstellung bewußt, nicht aber des Mannigfaltigen, das in ihr enthalten ist: so ist die Vorstellung undeutlich. Zur Erläuterung der Sache zuerst ein Beispiel in der Anschauung. Wir erblicken in der Ferne ein Landhaus. Sind wir uns bewußt, daß der angeschaute Gegenstand ein Haus ist, so müssen wir nothwendig doch auch eine Vorstellung von den verschiedenen Theilen dieses Hauses, den Fenstern, Thüren u.s.w. haben. Denn sähen wir die Theile nicht, so würden wir auch das Haus selbst nicht sehen. Aber wir sind uns dieser Vorstellung von dem Mannigfaltigen seiner Theile nicht bewußt und unsre Vorstellung von dem gedachten Gegenstande selbst ist daher eine undeutliche Vorstellung. Wollen wir ferner ein Beispiel von Undeutlichkeit in Begriffen: so möge der Begriff der Schönheit dazu dienen. Ein jeder hat von der Schönheit einen klaren Begriff. Allein es kommen in diesem Begriffe verschiedene Merkmale vor, unter andern, daß das Schöne etwas sein müsse, das 1) in die Sinne fällt und das 2) allgemein gefällt. Können wir uns nun das Mannigfaltige dieser und andrer Merkmale des Schönen nicht auseinandersetzen, so ist unser Begriff davon doch immer noch undeutlich. Die undeutliche Vorstellung nennen Wolffs Schüler eine verworrene. Allein dieser"}], "markers": [{"system": "AA", "band": "IX", "page": 33, "ref": "IX33"}, {"system": "AA", "band": "IX", "page": 34, "ref": "IX34"}], "running_header": "V. Erkenntniß überhaupt"}, {"page_pdf": 2749, "page_book": 35, "page_kind": "body", "sigel": "AA IX, 35", "units": [{"type": "paragraph", "text": "Ausdruck ist nicht passend, weil das Gegentheil von Verwirrung nicht Deutlichkeit, sondern Ordnung ist. Zwar ist Deutlichkeit eine Wirkung der Ordnung und Undeutlichkeit eine Wirkung der Verwirrung; und es ist also jede verworrene Erkenntniß auch eine undeutliche. Aber der Satz gilt nicht umgekehrt; nicht alle undeutliche Erkenntniß ist eine verworrene. Denn bei Erkenntnissen, in denen kein Mannigfaltiges vorhanden ist, findet keine Ordnung, aber auch keine Verwirrung statt. Diese Bewandtniß hat es mit allen einfachen Vorstellungen, die nie deutlich werden; nicht, weil in ihnen Verwirrung, sondern weil in ihnen kein Mannigfaltiges anzutreffen ist. Man muß sie daher undeutlich, aber nicht verworren nennen. Und auch selbst bei den zusammengesetzten Vorstellungen, in denen sich ein Mannigfaltiges von Merkmalen unterscheiden läßt, rührt die Undeutlichkeit oft nicht her von Verwirrung, sondern von Schwäche des Bewußtseins. Es kann nämlich etwas deutlich sein der Form nach, d.h. ich kann mir des Mannigfaltigen in der Vorstellung bewußt sein; aber der Materie nach kann die Deutlichkeit abnehmen, wenn der Grad des Bewußtseins kleiner wird, obgleich alle Ordnung da ist. Dieses ist der Fall mit abstracten Vorstellungen. Die Deutlichkeit selbst kann eine zwiefache sein: Erstlich, eine sinnliche. Diese besteht in dem Bewußtsein des Mannigfaltigen in der Anschauung. Ich sehe z.B. die Milchstraße als einen weißlichten Streifen; die Lichtstrahlen von den einzelnen in demselben befindlichen Sternen müssen nothwendig in mein Auge gekommen sein. Aber die Vorstellung davon war nur klar und wird durch das Teleskop erst deutlich, weil ich jetzt die einzelnen in jenem Milchstreifen enthaltenen Sterne erblicke. Zweitens, eine intellectuelle; Deutlichkeit in Begriffen oder Verstandesdeutlichkeit. Diese beruht auf der Zergliederung des Begriffs in Ansehung des Mannigfaltigen, das in ihm enthalten liegt. So sind z.B. in dem Begriffe der Tugend als Merkmale enthalten 1) der Begriff der Freiheit, 2) der Begriff der Anhänglichkeit an Regeln (der Pflicht), 3) der Begriff von Überwältigung der Macht der Neigungen, wofern sie jenen Regeln widerstreiten. Lösen wir nun so den Begriff der Tugend in seine einzelnen Bestandtheile auf, so machen wir ihn eben durch diese Analyse uns deutlich. Durch diese Deutlichmachung selbst aber setzen wir zu einem Begriffe nichts hinzu; wir erklären ihn nur. Es werden daher bei der Deutlichkeit die Begriffe nicht der Materie, sondern nur der Form nach verbessert."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Reflectiren wir auf unsre Erkenntnisse in Ansehung der beiden wesentlich verschiedenen Grundvermögen der Sinnlichkeit und des Verstandes, woraus sie entspringen: so treffen wir hier auf den Unterschied zwischen Anschauungen und Begriffen. Alle unsre Erkenntnisse nämlich sind, in dieser Rücksicht betrachtet, entweder Anschauungen oder Begriffe. Die erstern haben ihre Quelle in der Sinnlichkeit, dem Vermögen der Anschauungen, die letztern im Verstande, dem Vermögen der Begriffe. Dieses ist der logische Unterschied zwischen Verstand und Sinnlichkeit, nach welchem diese nichts als Anschauungen, jener hingegen nichts als Begriffe liefert. Beide Grundvermögen lassen sich freilich auch noch von einer andern Seite betrachten und auf eine andre Art definiren; nämlich die Sinnlichkeit als ein Vermögen der Receptivität, der Verstand als ein Vermögen der Spontaneität. Allein diese Erklärungsart ist nicht logisch, sondern metaphysisch. Man pflegt die Sinnlichkeit auch das niedere, den Verstand dagegen das obere Vermögen zu nennen, aus dem Grunde, weil die Sinnlichkeit den bloßen Stoff zum Denken giebt, der Verstand aber über diesen Stoff disponirt und denselben unter Regeln oder Begriffe bringt. Auf den hier angegebenen Unterschied zwischen intuitiven und discursiven Erkenntnissen, oder zwischen Anschauungen und Begriffen gründet sich die Verschiedenheit der ästhetischen und der logischen Vollkommenheit des Erkenntnisses."}], "markers": [{"system": "AA", "band": "IX", "page": 35, "ref": "IX35"}, {"system": "AA", "band": "IX", "page": 36, "ref": "IX36"}], "running_header": "V. Erkenntniß überhaupt"}, {"page_pdf": 2750, "page_book": 37, "page_kind": "body", "sigel": "AA IX, 37", "units": [{"type": "paragraph", "text": "Ein Erkenntniß kann vollkommen sein, entweder nach Gesetzen der Sinnlichkeit, oder nach Gesetzen des Verstandes; im erstern Falle ist es ästhetisch, im andern logisch vollkommen. Beide, die ästhetische und die logische Vollkommenheit, sind also von verschiedener Art, die erstere bezieht sich auf die Sinnlichkeit, die letztere auf den Verstand. Die logische Vollkommenheit des Erkenntnisses beruht auf seiner Übereinstimmung mit dem Objecte; also auf allgemeingültigen Gesetzen, und läßt sich mithin auch nach Normen _a priori_ beurtheilen. Die ästhetische Vollkommenheit besteht in der Übereinstimmung des Erkenntnisses mit dem Subjecte und gründet sich auf die besondere Sinnlichkeit des Menschen. Es finden daher bei der ästhetischen Vollkommenheit keine objectiv- und allgemeingültigen Gesetze statt, in Beziehung auf welche sie sich _a priori_ auf eine für alle denkenden Wesen überhaupt allgemeingeltende Weise beurtheilen ließe. Sofern es indessen auch allgemeine Gesetze der Sinnlichkeit giebt, die, obgleich nicht objectiv und für alle denkenden Wesen überhaupt, doch subjectiv für die gesammte Menschheit Gültigkeit haben: läßt sich auch eine ästhetische Vollkommenheit denken, die den Grund eines subjectiv-allgemeinen Wohlgefallens enthält. Dieses ist die Schönheit, das, was den Sinnen in der Anschauung gefällt und eben darum der Gegenstand eines allgemeinen Wohlgefallens sein kann, weil die Gesetze der Anschauung allgemeine Gesetze der Sinnlichkeit sind. Durch diese Übereinstimmung mit den allgemeinen Gesetzen der Sinnlichkeit unterscheidet sich der Art nach das eigentliche, selbstständige Schöne, dessen Wesen in der bloßen Form besteht, von dem Angenehmen, das lediglich in der Empfindung durch Reiz oder Rührung gefällt, und um deswillen auch nur der Grund eines bloßen Privat-Wohlgefallens sein kann. Diese wesentliche ästhetische Vollkommenheit ist es auch, welche unter allen mit der logischen Vollkommenheit sich verträgt und am besten mit ihr verbinden läßt. Von dieser Seite betrachtet kann also die ästhetische Vollkommenheit in Ansehung jenes wesentlich Schönen der logischen Vollkommenheit vortheilhaft sein. In einer anderen Rücksicht ist sie ihr aber auch nachtheilig, sofern wir bei der ästhetischen Vollkommenheit nur auf das außerwesentlich Schöne sehen, das Reizende oder Rührende, was den Sinnen in der bloßen Empfindung gefällt und nicht auf die bloße Form, sondern die Materie der Sinnlichkeit sich bezieht. Denn Reiz und Rührung können die logische Vollkommenheit in unsern Erkenntnissen und Urtheilen am meisten verderben. Überhaupt bleibt wohl freilich zwischen der ästhetischen und der logischen Vollkommenheit unsers Erkenntnisses immer eine Art von Widerstreit, der nicht völlig gehoben werden kann. Der Verstand will belehrt, die Sinnlichkeit belebt sein, der erste begehrt Einsicht, die zweite Faßlichkeit. Sollen Erkenntnisse unterrichten, so müssen sie in so fern gründlich sein; sollen sie zugleich unterhalten, so müssen sie auch schön sein. Ist ein Vortrag schön, aber seicht, so kann er nur der Sinnlichkeit, aber nicht dem Verstande, ist er umgekehrt gründlich, aber trocken, nur dem Verstande, aber nicht auch der Sinnlichkeit gefallen. Da es indessen das Bedürfniß der menschlichen Natur und der Zweck der Popularität des Erkenntnisses erfordert, daß wir beide Vollkommenheiten mit einander zu vereinigen suchen: so müssen wir es uns auch angelegen sein lassen, denjenigen Erkenntnissen, die überhaupt einer ästhetischen Vollkommenheit fähig sind, dieselbe zu verschaffen und eine schulgerechte, logisch vollkommene Erkenntniß durch die ästhetische Form populär zu machen. Bei diesem Bestreben, die ästhetische mit der logischen Vollkommenheit in unsern Erkenntnissen zu verbinden, müssen wir aber folgende Regeln nicht aus der Acht lassen: nämlich 1) daß die logische Vollkommenheit die Basis aller übrigen Vollkommenheiten sei und daher keiner andern gänzlich nachstehen oder aufgeopfert werden dürfe; 2) daß man hauptsächlich auf die formale ästhetische Vollkommenheit sehe; die Übereinstimmung einer Erkenntniß mit den Gesetzen der Anschauung, weil gerade hierin das wesentlich Schöne besteht, das mit der logischen Vollkommenheit sich am besten vereinigen läßt; 3) daß man mit Reiz und Rührung,"}], "markers": [{"system": "AA", "band": "IX", "page": 37, "ref": "IX37"}, {"system": "AA", "band": "IX", "page": 38, "ref": "IX38"}], "running_header": "V. Erkenntniß überhaupt"}, {"page_pdf": 2751, "page_book": 39, "page_kind": "body", "sigel": "AA IX, 39", "units": [{"type": "paragraph", "text": "wodurch ein Erkenntniß auf die Empfindung wirkt und für dieselbe ein Interesse erhält, sehr behutsam sein müsse, weil hierdurch so leicht die Aufmerksamkeit vom Object auf das Subject kann gezogen werden, woraus denn augenscheinlich ein sehr nachtheiliger Einfluß auf die logische Vollkommenheit des Erkenntnisses entstehen muß."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Um die wesentlichen Verschiedenheiten, die zwischen der logischen und der ästhetischen Vollkommenheit des Erkenntnisses stattfinden, nicht bloß im Allgemeinen, sondern von mehreren besondern Seiten noch kenntlicher zu machen, wollen wir sie beide unter einander vergleichen in Rücksicht auf die vier Hauptmomente der Quantität, der Qualität, der Relation und der Modalität, worauf es bei Beurtheilung der Vollkommenheit des Erkenntnisses ankommt. Ein Erkenntniß ist vollkommen 1) der Quantität nach, wenn es allgemein ist; 2) der Qualität nach, wenn es deutlich ist; 3) der Relation nach, wenn es wahr ist, und endlich 4) der Modalität nach, wenn es gewiß ist. Aus diesen angegebenen Gesichtspunkten betrachtet, wird also ein Erkenntniß logisch vollkommen sein der Quantität nach: wenn es objective Allgemeinheit (Allgemeinheit des Begriffs oder der Regel), der Qualität nach: wenn es objective Deutlichkeit (Deutlichkeit im Begriffe), der Relation nach: wenn es objective Wahrheit, und endlich der Modalität nach: wenn es objective Gewißheit hat. Diesen logischen Vollkommenheiten entsprechen nun folgende ästhetische Vollkommenheiten in Beziehung auf jene vier Hauptmomente; nämlich 1) die ästhetische Allgemeinheit. Diese besteht in der Anwendbarkeit einer Erkenntniß auf eine Menge von Objecten, die zu Beispielen dienen, an denen sich die Anwendung von ihr machen läßt, und wodurch sie zugleich für den Zweck der Popularität brauchbar wird; 2) die ästhetische Deutlichkeit. Dieses ist die Deutlichkeit in der Anschauung, worin durch Beispiele ein abstract gedachter Begriff _in concreto_ dargestellt oder erläutert wird; 3) die ästhetische Wahrheit. Eine bloß subjective Wahrheit, die nur in der Übereinstimmung des Erkenntnisses mit dem Subject und den Gesetzen des Sinnen-Scheines besteht und folglich nichts weiter als ein allgemeiner Schein ist; 4) die ästhetische Gewißheit. Diese beruht auf dem, was dem Zeugnisse der Sinne zufolge nothwendig ist, d.i. was durch Empfindung und Erfahrung bestätigt wird."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Bei den so eben genannten Vollkommenheiten kommen immer zwei Stücke vor, die in ihrer harmonischen Vereinigung die Vollkommenheit überhaupt ausmachen, nämlich: Mannigfaltigkeit und Einheit. Beim Verstande liegt die Einheit im Begriffe, bei den Sinnen in der Anschauung. Bloße Mannigfaltigkeit ohne Einheit kann uns nicht befriedigen. Und daher ist unter allen die Wahrheit die Hauptvollkommenheit, weil sie der Grund der Einheit ist durch die Beziehung unsers Erkenntnisses auf das Object. Auch selbst bei der ästhetischen Vollkommenheit bleibt die Wahrheit immer die _conditio sine qua non_, die vornehmste negative Bedingung, ohne welche etwas nicht allgemein dem Geschmacke gefallen kann. Es darf daher niemand hoffen, in schönen Wissenschaften fortzukommen, wenn er nicht logische Vollkommenheit in seinem Erkenntnisse zum Grunde gelegt hat. In der größten möglichen Vereinbarung der logischen mit der ästhetischen Vollkommenheit überhaupt in Rücksicht auf solche Kenntnisse, die beides, zugleich unterrichten und unterhalten sollen, zeigt sich auch wirklich der Charakter und die Kunst des Genies."}], "markers": [{"system": "AA", "band": "IX", "page": 39, "ref": "IX39"}], "running_header": "V. Erkenntniß überhaupt"}, {"page_pdf": 2752, "page_book": 40, "page_kind": "body", "sigel": "AA IX, 40", "units": [{"type": "heading", "text": "[Einleitung.]", "level": 2}, {"type": "paragraph", "text": "VI. Besondre logische Vollkommenheiten des Erkenntnisses. A) Logische Vollkommenheit des Erkenntnisses der Quantität nach. – Größe. – Extensive und intensive Größe. – Weitläuftigkeit und Gründlichkeit oder Wichtigkeit und Fruchtbarkeit des Erkenntnisses. – Bestimmung des Horizonts unsrer Erkenntnisse. Die Größe der Erkenntniß kann in einem zwiefachen Verstande genommen werden, entweder als extensive oder als intensive Größe. Die erstere bezieht sich auf den Umfang der Erkenntniß und besteht also in der Menge und Mannigfaltigkeit derselben; die letztere bezieht sich auf ihren Gehalt, welcher die Vielgültigkeit oder die logische Wichtigkeit und Fruchtbarkeit einer Erkenntniß betrifft, sofern sie als Grund von vielen und großen Folgen betrachtet wird (_non _ _multa sed multum_). Bei Erweiterung unsrer Erkenntnisse oder bei Vervollkommnung derselben ihrer extensiven Größe nach, ist es gut sich einen Überschlag zu machen, in wie weit ein Erkenntniß mit unsern Zwecken und Fähigkeiten zusammenstimme. Diese Überlegung betrifft die Bestimmung des Horizonts unsrer Erkenntnisse, unter welchem die Angemessenheit der Größe der gesammten Erkenntnisse mit den Fähigkeiten und Zwecken des Subjects zu verstehen ist. Der Horizont läßt sich bestimmen 1) logisch, nach dem Vermögen oder den Erkenntnißkräften in Beziehung auf das Interesse des Verstandes. Hier haben wir zu beurtheilen: wie weit wir in unsern Erkenntnissen kommen können, wie weit wir darin gehen müssen und in wie fern gewisse Erkenntnisse in logischer Absicht als Mittel zu diesen oder jenen Haupterkenntnissen, als unsern Zwecken, dienen; 2) ästhetisch, nach dem Geschmack in Beziehung auf das Interesse des Gefühls. Der seinen Horizont ästhetisch bestimmt, sucht die Wissenschaft nach dem Geschmacke des Publicums einzurichten, d.h. sie populär zu machen, oder überhaupt nur solche Erkenntnisse sich zu erwerben, die sich allgemein mittheilen lassen und an denen auch die Klasse der Nichtgelehrten Gefallen und Interesse findet; 3) praktisch, nach dem Nutzen in Beziehung auf das Interesse des Willens. Der praktische Horizont, sofern er bestimmt wird nach dem Einflusse, den ein Erkenntniß auf unsre Sittlichkeit hat, ist pragmatisch und von der größten Wichtigkeit. Der Horizont betrifft also die Beurtheilung und Bestimmung dessen, was der Mensch wissen kann, was er wissen darf, und was er wissen soll."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Was nun insbesondre den theoretisch oder logisch bestimmten Horizont betrifft – und von diesem kann hier allein die Rede sein –, so können wir denselben entweder aus dem objectiven oder aus dem subjectiven Gesichtspunkte betrachten. In Ansehung der Objecte ist der Horizont entweder historisch oder rational. Der erstere ist viel weiter als der andre, ja er ist unermeßlich groß, denn unsre historische Erkenntniß hat keine Grenzen. Der rationale Horizont dagegen läßt sich fixiren, es läßt sich z.B. bestimmen, auf welche Art von Objecten das mathematische Erkenntniß nicht ausgedehnt werden könne. So auch in Absicht auf das philosophische Vernunfterkenntniß, wie weit hier die Vernunft _a priori_ ohne alle Erfahrung wohl gehen könne? In Beziehung aufs Subject ist der Horizont entweder der allgemeine und absolute, oder ein besondrer und bedingter (Privat-Horizont). Unter dem absoluten und allgemeinen Horizont ist die Congruenz der Grenzen der"}], "markers": [{"system": "AA", "band": "IX", "page": 40, "ref": "IX40"}, {"system": "AA", "band": "IX", "page": 41, "ref": "IX41"}], "running_header": "VI. Besondre logische Vollkommenheiten des Erkenntnisses [A)]"}, {"page_pdf": 2753, "page_book": 42, "page_kind": "body", "sigel": "AA IX, 42", "units": [{"type": "paragraph", "text": "menschlichen Erkenntnisse mit den Grenzen der gesammten menschlichen Vollkommenheit überhaupt zu verstehen. Und hier ist also die Frage: Was kann der Mensch als Mensch überhaupt wissen? Die Bestimmung des Privat-Horizonts hängt ab von mancherlei empirischen und speciellen Rücksichten, z.B. des Alters, des Geschlechts, Standes, der Lebensart u.dgl.m. Jede besondre Klasse von Menschen hat also in Beziehung auf ihre speciellen Erkenntnißkräfte, Zwecke und Standpunkte, ihren besondern, jeder Kopf nach Maaßgabe der Individualität seiner Kräfte und seines Standpunktes seinen eigenen Horizont. Endlich können wir uns auch noch einen Horizont der gesunden Vernunft und einen Horizont der Wissenschaft denken, welcher letztere noch Principien bedarf, um nach denselben zu bestimmen, was wir wissen und nicht wissen können. Was wir nicht wissen können, ist über unsern Horizont, was wir nicht wissen dürfen oder nicht zu wissen brauchen, außer unserm Horizonte. Dieses letztere kann jedoch nur relativ gelten in Beziehung auf diese oder jene besondren Privatzwecke, zu deren Erreichung gewisse Erkenntnisse nicht nur nichts beitragen, sondern ihr sogar hinderlich sein könnten. Denn schlechthin und in aller Absicht unnütz und unbrauchbar ist doch kein Erkenntniß, ob wir gleich seinen Nutzen nicht immer einsehen können. Es ist daher ein eben so unweiser als ungerechter Vorwurf, der großen Männern, welche mit mühsamem Fleiße die Wissenschaften bearbeiten, von schalen Köpfen gemacht wird, wenn diese hierbei fragen: wozu ist das nütze? Diese Frage muß man, indem man sich mit Wissenschaften beschäftigen will, gar nicht einmal aufwerfen. Gesetzt, eine Wissenschaft könnte nur über irgend ein mögliches Object Aufschlüsse geben, so wäre sie um deswillen schon nützlich genug. Jede logisch vollkommene Erkenntniß hat immer irgend einen möglichen Nutzen, der, obgleich uns bis jetzt unbekannt, doch vielleicht von der Nachkommenschaft wird gefunden werden. Hätte man bei Cultur der Wissenschaften immer nur auf den materiellen Gewinn, den Nutzen derselben gesehen, so würden wir keine Arithmetik und Geometrie haben. Unser Verstand ist auch überdies so eingerichtet, daß er in der bloßen Einsicht Befriedigung findet und mehr noch als in dem Nutzen, der daraus entspringt. Dieses merkte schon Plato an. Der Mensch fühlt seine eigene Vortrefflichkeit dabei, er empfindet, was es heiße, Verstand haben. Menschen, die das nicht empfinden, müssen die Thiere beneiden. Der innere Werth, den Erkenntnisse durch logische Vollkommenheit haben, ist mit ihrem äußern, dem Werthe in der Anwendung, nicht zu vergleichen. Wie das, was außer unserm Horizonte liegt, sofern wir es nach unsern Absichten, als entbehrlich für uns, nicht wissen dürfen, so ist auch das, was unter unserm Horizont liegt, sofern wir es, als schädlich für uns, nicht wissen sollen, nur in einem relativen, keinesweges aber im absoluten Sinne zu verstehen."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "In Absicht auf die Erweiterung und Demarcation unserer Erkenntniß sind folgende Regeln zu empfehlen: Man muß sich seinen Horizont 1) zwar frühzeitig bestimmen, aber freilich doch erst alsdann, wenn man ihn sich selbst bestimmen kann, welches gewöhnlich vor dem 20ten Jahre nicht stattfindet; 2) ihn nicht leicht und oft verändern (nicht von einem auf das andre fallen); 3) den Horizont Anderer nicht nach dem seinigen messen, und nicht das für unnütz halten, was uns zu Nichts nützt; es würde verwegen sein, den Horizont Anderer bestimmen zu wollen, weil man theils ihre Fähigkeiten, theils ihre Absichten nicht genug kennt; 4) ihn weder zu sehr ausdehnen, noch zu sehr einschränken. Denn der zu viel wissen will, weiß am Ende nichts, und der umgekehrt von einigen Dingen glaubt, daß sie ihn nichts angehen, betrügt sich oft; wie wenn z.B. der Philosoph von der Geschichte glaubte, daß"}], "markers": [{"system": "AA", "band": "IX", "page": 42, "ref": "IX42"}, {"system": "AA", "band": "IX", "page": 43, "ref": "IX43"}], "running_header": "VI. Besondre logische Vollkommenheiten des Erkenntnisses [A)]"}, {"page_pdf": 2754, "page_book": 44, "page_kind": "body", "sigel": "AA IX, 44", "units": [{"type": "paragraph", "text": "sie ihm entbehrlich sei. Auch suche man 5) den absoluten Horizont des ganzen menschlichen Geschlechts (der vergangenen und künftigen Zeit nach) zum voraus zu bestimmen, so wie insbesondre auch 6) die Stelle zu bestimmen, die unsre Wissenschaft im Horizonte der gesammten Erkenntniß einnimmt. Dazu dient die Universal-Encyklopädie als eine Universalcharte (_Mappe-monde_) der Wissenschaften. 7) Bei Bestimmung seines besondern Horizonts selbst prüfe man sorgfältig: zu welchem Theile des Erkenntnisses man die größte Fähigkeit und Wohlgefallen habe, was in Ansehung gewisser Pflichten mehr oder weniger nöthig sei, was mit den nothwendigen Pflichten nicht zusammen bestehen könne und endlich 8) suche man seinen Horizont immer doch mehr zu erweitern als zu verengen. Es ist überhaupt von der Erweiterung des Erkenntnisses das nicht zu besorgen, was _d’Alembert_ von ihr besorgt. Denn uns drückt nicht die Last, sondern uns verengt das Volumen des Raums für unsre Erkenntnisse. Kritik der Vernunft, der Geschichte und historischen Schriften, ein allgemeiner Geist, der auf das menschliche Erkenntniß _en gros_ und nicht bloß im _detail_ geht, werden immer den Umfang kleiner machen, ohne im Inhalte etwas zu vermindern. Bloß die Schlacke fällt vom Metalle weg oder das unedlere Vehikel, die Hülle, welche bis so lange nöthig war. Mit der Erweiterung der Naturgeschichte, der Mathematik u.s.w. werden neue Methoden erfunden werden, die das Alte verkürzen und die Menge der Bücher entbehrlich machen. Auf Erfindung solcher neuen Methoden und Principien wird es beruhen, daß wir, ohne das Gedächtniß zu belästigen, alles mit Hülfe derselben nach Belieben selbst finden können. Daher macht sich der um die Geschichte wie ein Genie verdient, welcher sie unter Ideen faßt, die immer bleiben können."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Der logischen Vollkommenheit des Erkenntnisses in Ansehung seines Umfanges steht die Unwissenheit entgegen. Eine negative Unvollkommenheit oder Unvollkommenheit des Mangels, die wegen der Schranken des Verstandes von unserm Erkenntnisse unzertrennlich bleibt. Wir können die Unwissenheit aus einem objectiven und aus einem subjectiven Gesichtspunkte betrachten. 1) Objectiv genommen, ist die Unwissenheit entweder eine materiale oder eine formale. Die erstere besteht in einem Mangel an historischen, die andere in einem Mangel an rationalen Erkenntnissen. Man muß in keinem Fache ganz ignorant sein, aber wohl kann man das historische Wissen einschränken, um sich desto mehr auf das rationale zu legen, oder umgekehrt. 2) In subjectiver Bedeutung ist die Unwissenheit entweder eine gelehrte, scientifische oder eine gemeine. Der die Schranken der Erkenntniß, also das Feld der Unwissenheit, von wo es anhebt, deutlich einsieht, der Philosoph z.B., der es einsieht und beweist, wie wenig man aus Mangel an den dazu erforderlichen Datis in Ansehung der Structur des Goldes wissen könne, ist kunstmäßig oder auf eine gelehrte Art unwissend. Der hingegen unwissend ist, ohne die Gründe von den Grenzen der Unwissenheit einzusehen und sich darum zu bekümmern, ist es auf eine gemeine, nicht wissenschaftliche Weise. Ein solcher weiß nicht einmal, daß er nichts wisse. Denn man kann sich seine Unwissenheit niemals anders vorstellen als durch die Wissenschaft, so wie ein Blinder sich die Finsterniß nicht vorstellen kann, als bis er sehend geworden. Die Kenntniß seiner Unwissenheit setzt also Wissenschaft voraus und macht zugleich bescheiden, dagegen das eingebildete Wissen aufbläht. So war Sokrates’ Nichtwissen eine rühmliche Unwissenheit, eigentlich ein Wissen des Nichtwissens nach seinem eigenen Geständnisse. Diejenigen also, die sehr viele"}], "markers": [{"system": "AA", "band": "IX", "page": 44, "ref": "IX44"}, {"system": "AA", "band": "IX", "page": 45, "ref": "IX45"}], "running_header": "VI. Besondre logische Vollkommenheiten des Erkenntnisses [A)]"}, {"page_pdf": 2755, "page_book": 46, "page_kind": "body", "sigel": "AA IX, 46", "units": [{"type": "paragraph", "text": "Kenntnisse besitzen und bei alle dem doch über die Menge dessen, was sie nicht wissen, erstaunen, kann der Vorwurf der Unwissenheit eben nicht treffen. Untadelhaft (_inculpabilis_) ist überhaupt die Unwissenheit in Dingen, deren Erkenntniß über unsern Horizont geht, und erlaubt (wiewohl auch nur im relativen Sinne) kann sie sein in Ansehung des speculativen Gebrauchs unserer Erkenntnißvermögen, sofern die Gegenstände hier, obgleich nicht über, aber doch außer unserm Horizonte liegen. Schändlich aber ist sie in Dingen, die zu wissen uns sehr nöthig und auch leicht ist. Es ist ein Unterschied, etwas nicht wissen und etwas ignoriren, d.i. keine Notiz wovon nehmen. Es ist gut viel zu ignoriren, was uns nicht gut ist zu wissen. Von beidem ist noch unterschieden das Abstrahiren. Man abstrahirt aber von einer Erkenntniß, wenn man die Anwendung derselben ignorirt, wodurch man sie _in abstracto_ bekommt und im Allgemeinen als Princip sodann besser betrachten kann. Ein solches Abstrahiren von dem, was bei Erkenntniß einer Sache zu unserer Absicht nicht gehört, ist nützlich und lobenswerth. Historisch unwissend sind gemeiniglich Vernunftlehrer. Das historische Wissen ohne bestimmte Grenzen ist Polyhistorie; diese bläht auf. Polymathie geht auf das Vernunfterkenntniß. Beides, das ohne bestimmte Grenzen ausgedehnte historische so wohl als rationale Wissen kann Pansophie heißen. Zum historischen Wissen gehört die Wissenschaft von den Werkzeugen der Gelehrsamkeit – die Philologie, die eine kritische Kenntniß der Bücher und Sprachen (Literatur und Linguistik) in sich faßt. Die bloße Polyhistorie ist eine cyklopische Gelehrsamkeit, der ein Auge fehlt, das Auge der Philosophie, und ein Cyklop von Mathematiker, Historiker, Naturbeschreiber, Philolog und Sprachkundiger ist ein Gelehrter, der groß in allen diesen Stücken ist, aber alle Philosophie darüber für entbehrlich hält. Einen Theil der Philologie machen die _Humaniora_ aus, worunter man die Kenntniß der Alten versteht, welche die Vereinigung der Wissenschaft mit Geschmack befördert, die Rauhigkeit abschleift und die Communicabilität und Urbanität, worin Humanität besteht, befördert. Die _Humaniora_ betreffen also eine Unterweisung in dem, was zur Cultur des Geschmacks dient, den Mustern der Alten gemäß. Dahin gehört z.B. Beredsamkeit, Poesie, Belesenheit in den classischen Autoren u.dgl.m. Alle diese humanistischen Kenntnisse kann man zum praktischen, auf die Bildung des Geschmacks zunächst abzweckenden Theile der Philologie rechnen. Trennen wir aber den bloßen Philologen noch vom Humanisten, so würden sich beide darin von einander unterscheiden, daß jener die Werkzeuge der Gelehrsamkeit bei den Alten sucht, dieser hingegen die Werkzeuge der Bildung des Geschmacks. Der Belletrist oder _bel esprit_ ist ein Humanist nach gleichzeitigen Mustern in lebenden Sprachen. Er ist also kein Gelehrter, denn nur todte Sprachen sind jetzt gelehrte Sprachen, sondern ein bloßer Dilettant der Geschmackskenntnisse nach der Mode, ohne der Alten zu bedürfen. Man könnte ihn den Affen des Humanisten nennen. Der Polyhistor muß als Philolog Linguist und Literator und als Humanist muß er Klassiker und ihr Ausleger sein. Als Philolog ist er cultivirt, als Humanist civilisirt."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "In Ansehung der Wissenschaften giebt es zwei Ausartungen des herrschenden Geschmacks: Pedanterie und Galanterie. Die eine treibt die Wissenschaften bloß für die Schule und schränkt sie dadurch ein in Rücksicht ihres Gebrauches, die andre treibt sie bloß für den Umgang oder die Welt und beschränkt sie dadurch in Absicht auf ihren Inhalt. Der Pedant ist entweder als Gelehrter dem Weltmanne entgegengesetzt und ist in so fern der aufgeblasene Gelehrte ohne Weltkenntniß, d.i. ohne Kenntniß der Art und Weise, seine Wissenschaft an den Mann zu bringen, oder er ist zwar als der Mann von Geschicklichkeit"}], "markers": [{"system": "AA", "band": "IX", "page": 46, "ref": "IX46"}], "running_header": "VI. Besondre logische Vollkommenheiten des Erkenntnisses [A)]"}, {"page_pdf": 2756, "page_book": 47, "page_kind": "body", "sigel": "AA IX, 47", "units": [{"type": "paragraph", "text": "überhaupt zu betrachten, aber nur in Formalien, nicht dem Wesen und Zwecke nach. In der letztern Bedeutung ist er ein Formalienklauber; eingeschränkt in Ansehung des Kerns der Sachen, sieht er nur auf das Kleid und die Schale. Er ist die verunglückte Nachahmung oder Caricatur vom methodischen Kopfe. Man kann daher die Pedanterie auch die grüblerische Peinlichkeit und unnütze Genauigkeit (Mikrologie) in Formalien nennen. Und ein solches Formale der Schulmethode außer der Schule ist nicht bloß bei Gelehrten und im gelehrten Wesen, sondern auch bei andern Ständen und in andern Dingen anzutreffen. Das Ceremoniell an Höfen, im Umgange, was ist es anders als Formalienjagd und Klauberei? Im Militär ist es nicht völlig so, ob es gleich so scheint. Aber im Gespräche, in der Kleidung, in der Diät, in der Religion herrscht oft viel Pedanterie. Eine zweckmäßige Genauigkeit in Formalien ist Gründlichkeit (schulgerechte, scholastische Vollkommenheit). Pedanterie ist also eine affectirte Gründlichkeit, so wie Galanterie, als eine bloße Buhlerin um den Beifall des Geschmacks, nichts als eine affectirte Popularität ist. Denn die Galanterie ist nur bemüht, sich dem Leser gewogen zu machen und ihn daher auch nicht einmal durch ein schweres Wort zu beleidigen. Pedanterie zu vermeiden, dazu werden ausgebreitete Kenntnisse nicht nur in den Wissenschaften selbst, sondern auch in Ansehung des Gebrauches derselben erfordert. Daher kann sich nur der wahre Gelehrte von der Pedanterie losmachen, die immer die Eigenschaft eines eingeschränkten Kopfes ist. Bei dem Bestreben, unserm Erkenntnisse die Vollkommenheit der scholastischen Gründlichkeit und zugleich der Popularität zu verschaffen, ohne darüber in die gedachten Fehler einer affectirten Gründlichkeit oder einer affectirten Popularität zu gerathen, müssen wir vor Allem auf die scholastische Vollkommenheit unsers Erkenntnisses, die schulgerechte Form der Gründlichkeit, sehen und sodann erst dafür sorgen, wie wir die methodisch in der Schule gelernte Erkenntniß wahrhaft populär, d.i. Andern so leicht und allgemein mittheilbar machen, daß doch die Gründlichkeit nicht durch die Popularität verdrängt werde. Denn um der populären Vollkommenheit willen, dem Volke zu Gefallen, muß die scholastische Vollkommenheit nicht aufgeopfert werden, ohne welche alle Wissenschaft nichts als Spielwerk und Tändelei wäre. Um aber wahre Popularität zu lernen, muß man die Alten lesen, z.B. Cicero’s philosophische Schriften, die Dichter Horaz, Virgil u.s.w., unter den Neuern Hume, Shaftesbury u.a.m. Männer, die alle vielen Umgang mit der verfeinerten Welt gehabt haben, ohne den man nicht populär sein kann. Denn wahre Popularität erfordert viele praktische Welt- und Menschenkenntniß, Kenntniß von den Begriffen, dem Geschmacke und den Neigungen der Menschen, worauf bei der Darstellung und selbst der Wahl schicklicher, der Popularität angemessener Ausdrücke beständige Rücksicht zu nehmen ist. Eine solche Herablassung (Condescendenz) zu der Fassungskraft des Publicums und den gewohnten Ausdrücken, wobei die scholastische Vollkommenheit nicht hintenan gesetzt, sondern nur die Einkleidung der Gedanken so eingerichtet wird, daß man das Gerüst, das Schulgerechte und Technische von jener Vollkommenheit nicht sehen läßt (so wie man mit Bleistift Linien zieht, auf die man schreibt und sie nachher wegwischt), diese wahrhaft populäre Vollkommenheit des Erkenntnisses ist in der That eine große und seltene Vollkommenheit, die von vieler Einsicht in die Wissenschaft zeigt. Auch hat sie außer vielen andern Verdiensten noch dieses, daß sie einen Beweis für die vollständige Einsicht in eine Sache geben kann. Denn die bloß scholastische Prüfung einer Erkenntniß läßt noch den Zweifel übrig: ob die Prüfung nicht einseitig sei, und ob die Erkenntniß selbst auch wohl einen von allen Menschen ihr zugestandenen Werth habe? Die Schule hat ihre Vorurtheile so wie der gemeine Verstand. Eines verbessert hier das andre. Es ist daher wichtig, ein Erkenntniß an Menschen zu prüfen, deren Verstand an keiner Schule hängt. Diese Vollkommenheit der Erkenntniß, wodurch sich dieselbe zu einer leichten und"}], "markers": [{"system": "AA", "band": "IX", "page": 47, "ref": "IX47"}, {"system": "AA", "band": "IX", "page": 48, "ref": "IX48"}], "running_header": "VI. Besondre logische Vollkommenheiten des Erkenntnisses [A)]"}, {"page_pdf": 2757, "page_book": 49, "page_kind": "body", "sigel": "AA IX, 49", "units": [{"type": "paragraph", "text": "allgemeinen Mittheilung qualificirt, könnte man auch die äußere Extension oder die extensive Größe eines Erkenntnisses nennen, sofern es äußerlich unter viele Menschen ausgebreitet ist."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Da es so viele und mannigfaltige Erkenntnisse giebt, so wird man wohl thun, sich einen Plan zu machen, nach welchem man die Wissenschaften so ordnet, wie sie am besten zu seinen Zwecken zusammen stimmen und zu Beförderung derselben beitragen. Alle Erkenntnisse stehen unter einander in einer gewissen natürlichen Verknüpfung. Sieht man nun bei dem Bestreben nach Erweiterung der Erkenntnisse nicht auf diesen ihren Zusammenhang: so wird aus allem Vielwissen doch weiter nichts als bloße Rhapsodie. Macht man sich aber eine Hauptwissenschaft zum Zweck und betrachtet alle andern Erkenntnisse nur als Mittel, um zu derselben zu gelangen: so bringt man in sein Wissen einen gewissen systematischen Charakter. Und um nach einem solchen wohlgeordneten und zweckmäßigen Plane bei Erweiterung seiner Erkenntnisse zu Werke zu gehen, muß man also jenen Zusammenhang der Erkenntnisse unter einander kennen zu lernen suchen. Dazu giebt die Architektonik der Wissenschaften Anleitung, die ein System nach Ideen ist, in welchem die Wissenschaften in Ansehung ihrer Verwandtschaft und systematischen Verbindung in einem Ganzen der die Menschheit interessirenden Erkenntniß betrachtet werden."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Was nun insbesondre aber die intensive Größe des Erkenntnisses, d.h. ihren Gehalt, oder ihre Vielgültigkeit und Wichtigkeit betrifft, die sich, wie wir oben bemerkten, von der extensiven Größe, der bloßen Weitläuftigkeit desselben wesentlich unterscheidet: so wollen wir hierüber nur noch folgende wenige Bemerkungen machen: 1) Eine Erkenntniß, die aufs Große, d.i. das Ganze im Gebrauch des Verstandes geht, ist von der Subtilität im Kleinen (Mikrologie) zu unterscheiden. 2) Logisch wichtig ist jedes Erkenntniß zu nennen, das die logische Vollkommenheit der Form nach befördert, z.B. jeder mathematische Satz, jedes deutlich eingesehene Gesetz der Natur, jede richtige philosophische Erklärung. Die praktische Wichtigkeit kann man nicht voraussehen, sondern man muß sie abwarten. 3) Man muß die Wichtigkeit nicht mit der Schwere verwechseln. Ein Erkenntniß kann schwer sein, ohne wichtig zu sein, und umgekehrt. Schwere entscheidet daher weder für noch auch wider den Werth und die Wichtigkeit eines Erkenntnisses. Diese beruht auf der Größe oder Vielheit der Folgen. Je mehr oder je größere Folgen ein Erkenntniß hat, je mehr Gebrauch sich von ihm machen läßt, desto wichtiger ist es. Eine Erkenntniß ohne wichtige Folgen heißt eine Grübelei; dergleichen z.B. die scholastische Philosophie war."}], "markers": [{"system": "AA", "band": "IX", "page": 49, "ref": "IX49"}], "running_header": "VI. Besondre logische Vollkommenheiten des Erkenntnisses [A)]"}, {"page_pdf": 2758, "page_book": 49, "page_kind": "body", "sigel": "AA IX, 49", "units": [{"type": "heading", "text": "[Einleitung.]", "level": 2}, {"type": "paragraph", "text": "VII. _B_) Logische Vollkommenheit des Erkenntnisses der Relation nach. – Wahrheit. – Materiale und formale oder logische Wahrheit. – Kriterien der logischen Wahrheit. –Falschheit und Irrthum. – Schein, als Quelle des Irrthums. – Mittel zu Vermeidung der Irrthümer. Eine Hauptvollkommenheit des Erkenntnisses, ja die wesentliche und unzertrennliche Bedingung aller Vollkommenheit desselben, ist die Wahrheit. Wahrheit, sagt man, besteht in der Übereinstimmung der Erkenntniß mit dem Gegenstande. Dieser bloßen Worterklärung zufolge soll also mein Erkenntniß, um als wahr zu gelten, mit dem Object übereinstimmen. Nun kann ich aber das Object nur mit meinem Erkenntnisse vergleichen, dadurch daß ich es erkenne. Meine Erkenntniß soll sich also selbst bestätigen, welches aber zur Wahrheit noch lange nicht hinreichend ist. Denn da das Object außer mir und die Erkenntniß in mir ist, so kann ich immer doch nur beurtheilen: ob meine Erkenntniß vom Object mit meiner Erkenntniß vom Object übereinstimme. Einen solchen Cirkel im Erklären nannten die Alten Diallele. Und wirklich wurde dieser Fehler auch immer den Logikern von den Skeptikern vorgeworfen, welche bemerkten: es verhalte sich mit jener Erklärung der Wahrheit eben so, wie wenn jemand vor Gericht eine Aussage thue und sich dabei auf einen Zeugen berufe, den niemand kenne, der sich aber dadurch glaubwürdig machen wolle, daß er behaupte, der, welcher ihn zum Zeugen aufgerufen, sei ein ehrlicher Mann. Die Beschuldigung war allerdings gegründet. Nur ist die Auflösung der gedachten Aufgabe schlechthin und für jeden Menschen unmöglich. Es frägt sich nämlich hier: Ob und in wie fern es ein sicheres, allgemeines und in der Anwendung brauchbares Kriterium der Wahrheit gebe? Denn das soll die Frage: Was ist Wahrheit? bedeuten. Um diese wichtige Frage entscheiden zu können, müssen wir das, was in unserm Erkenntnisse zur Materie desselben gehört und auf das Object sich bezieht, von dem, was die bloße Form, als diejenige Bedingung betrifft, ohne welche ein Erkenntniß gar kein Erkenntniß überhaupt sein würde, wohl unterscheiden. Mit Rücksicht auf diesen Unterschied zwischen der objectiven, materialen und der subjectiven, formalen Beziehung in unserm Erkenntnisse, zerfällt daher die obige Frage in die zwei besondern: 1) Giebt es ein allgemeines materiales, und 2) Giebt es ein allgemeines formales Kriterium der Wahrheit? Ein allgemeines materiales Kriterium der Wahrheit ist nicht möglich; es ist sogar in sich selbst widersprechend. Denn als ein allgemeines, für alle Objecte überhaupt gültiges, müßte es von allem Unterschiede derselben völlig abstrahiren und doch auch zugleich als ein materiales Kriterium eben auf diesen Unterschied gehen, um bestimmen zu können, ob ein Erkenntniß gerade mit demjenigen Objecte, worauf es bezogen wird, und nicht mit irgend einem Object überhaupt – womit eigentlich gar nichts gesagt wäre – übereinstimme. In dieser Übereinstimmung einer Erkenntniß mit demjenigen bestimmten Objecte, worauf sie bezogen wird, muß aber die materiale Wahrheit bestehen. Denn ein Erkenntniß, welches in Ansehung Eines Objectes wahr ist, kann in Beziehung auf andre Objecte falsch sein. Es ist daher ungereimt, ein allgemeines materiales Kriterium der Wahrheit zu fordern, das von allem Unterschiede der Objecte zugleich abstrahiren und auch nicht abstrahiren solle. Ist nun aber die Frage nach allgemeinen formalen Kriterien der Wahrheit, so ist die Entscheidung hier leicht, daß es dergleichen allerdings geben könne. Denn die formale Wahrheit besteht lediglich in der Zusammenstimmung der Erkenntniß mit sich selbst bei gänzlicher Abstraction von allen Objecten insgesammt und von allem Unterschiede derselben. Und die allgemeinen formalen Kriterien der Wahrheit sind demnach nichts anders als allgemeine logische"}], "markers": [{"system": "AA", "band": "IX", "page": 49, "ref": "IX49"}, {"system": "AA", "band": "IX", "page": 50, "ref": "IX50"}, {"system": "AA", "band": "IX", "page": 51, "ref": "IX51"}], "running_header": "VII. B) Logische Vollkommenheit des Erkenntnisses der Relation nach"}, {"page_pdf": 2759, "page_book": 52, "page_kind": "body", "sigel": "AA IX, 52", "units": [{"type": "paragraph", "text": "Merkmale der Übereinstimmung der Erkenntniß mit sich selbst oder – welches einerlei ist – mit den allgemeinen Gesetzen des Verstandes und der Vernunft. Diese formalen, allgemeinen Kriterien sind zwar freilich zur objectiven Wahrheit nicht hinreichend, aber sie sind doch als die _conditio sine qua non_ derselben anzusehen. Denn vor der Frage: ob die Erkenntniß mit dem Object zusammenstimme, muß die Frage vorhergehen, ob sie mit sich selbst (der Form nach) zusammenstimme? Und dies ist Sache der Logik. Die formalen Kriterien der Wahrheit in der Logik sind 1) der Satz des Widerspruchs, 2) der Satz des zureichenden Grundes. Durch den erstern ist die logische Möglichkeit, durch den letztern die logische Wirklichkeit eines Erkenntnisses bestimmt. Zur logischen Wahrheit eines Erkenntnisses gehört nämlich Erstlich: daß es logisch möglich sei, d.h. sich nicht widerspreche. Dieses Kennzeichen der innerlichen logischen Wahrheit ist aber nur negativ; denn ein Erkenntniß, welches sich widerspricht, ist zwar falsch, wenn es sich aber nicht widerspricht, nicht allemal wahr. Zweitens: daß es logisch gegründet sei, d.h. daß es _a_) Gründe habe und _b_) nicht falsche Folgen habe. Dieses zweite, den logischen Zusammenhang eines Erkenntnisses mit Gründen und Folgen betreffende Kriterium der äußerlichen logischen Wahrheit oder der Rationabilität des Erkenntnisses ist positiv. Und hier gelten folgende Regeln: 1) Aus der Wahrheit der Folge läßt sich auf die Wahrheit des Erkenntnisses als Grundes schließen, aber nur negativ: wenn Eine falsche Folge aus einer Erkenntniß fließt, so ist die Erkenntniß selbst falsch. Denn wenn der Grund wahr wäre, so müßte die Folge auch wahr sein, weil die Folge durch den Grund bestimmt wird. – Man kann aber nicht umgekehrt schließen: wenn keine falsche Folge aus einem Erkenntnisse fließt, so ist es wahr; denn man kann aus einem falschen Grunde wahre Folgen ziehen. 2) Wenn alle Folgen eines Erkenntnisses wahr sind: so ist das Erkenntniß auch wahr. Denn wäre nur etwas Falsches im Erkenntnisse, so müßte auch eine falsche Folge stattfinden. Aus der Folge läßt sich also zwar auf einen Grund schließen, aber ohne diesen Grund bestimmen zu können. Nur aus dem Inbegriffe aller Folgen allein kann man auf einen bestimmten Grund schließen, daß dieser der wahre sei. Die erstere Schlußart, nach welcher die Folge nur ein negativ und indirect zureichendes Kriterium der Wahrheit eines Erkenntnisses sein kann, heißt in der Logik die apagogische (_modus tollens_). Dieses Verfahren, wovon in der Geometrie häufig Gebrauch gemacht wird, hat den Vortheil, daß ich aus einem Erkenntnisse nur Eine falsche Folge herleiten darf, um seine Falschheit zu beweisen. Um z.B. darzuthun, daß die Erde nicht platt sei, darf ich, ohne positive und directe Gründe vorzubringen, apagogisch und indirect nur so schließen: Wäre die Erde platt, so müßte der Polarstern immer gleich hoch sein; nun ist dieses aber nicht der Fall, folglich ist sie nicht platt. Bei der andern, der positiven und directen Schlußart (_modus ponens_) tritt die Schwierigkeit ein, daß sich die Allheit der Folgen nicht apodiktisch erkennen läßt, und daß man daher durch die gedachte Schlußart nur zu einer wahrscheinlichen und hypothetisch-wahren Erkenntniß (Hypothesen) geführt wird, nach der Voraussetzung: daß da, wo viele Folgen wahr sind, die übrigen auch alle wahr sein mögen. Wir werden also hier drei Grundsätze, als allgemeine, bloß formale oder logische Kriterien der Wahrheit aufstellen können; diese sind 1) der Satz des Widerspruchs und der Identität (_principium contradictionis _und"}], "markers": [{"system": "AA", "band": "IX", "page": 52, "ref": "IX52"}], "running_header": "VII. B) Logische Vollkommenheit des Erkenntnisses der Relation nach"}, {"page_pdf": 2760, "page_book": 53, "page_kind": "body", "sigel": "AA IX, 53", "units": [{"type": "paragraph", "text": "_identitatis_), durch welchen die innere Möglichkeit eines Erkenntnisses für problematische Urtheile bestimmt ist; 2) der Satz des zureichenden Grundes (_principium rationis sufficientis_), auf welchem die (logische) Wirklichkeit einer Erkenntniß beruht, daß sie gegründet sei, als Stoff zu assertorischen Urtheilen; 3) der Satz des ausschließenden Dritten (_principium exclusi medii inter duo _ _contradictoria_), worauf sich die (logische) Nothwendigkeit eines Erkenntnisses gründet – daß nothwendig so und nicht anders geurtheilt werden müsse, d.i. daß das Gegentheil falsch sei – für apodiktische Urtheile."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Das Gegentheil von der Wahrheit ist die Falschheit, welche, sofern sie für Wahrheit gehalten wird, Irrthum heißt. Ein irriges Urtheil – denn Irrthum sowohl als Wahrheit ist nur im Urtheile – ist also ein solches, welches den Schein der Wahrheit mit der Wahrheit selbst verwechselt. Wie Wahrheit möglich sei, das ist leicht einzusehen, da hier der Verstand nach seinen wesentlichen Gesetzen handelt. Wie aber Irrthum in formaler Bedeutung des Worts, d.h. wie die verstandeswidrige Form des Denkens möglich sei, das ist schwer zu begreifen, so wie es überhaupt nicht zu begreifen ist, wie irgend eine Kraft von ihren eigenen wesentlichen Gesetzen abweichen solle. Im Verstande selbst und dessen wesentlichen Gesetzen können wir also den Grund der Irrthümer nicht suchen, so wenig als in den Schranken des Verstandes, in denen zwar die Ursache der Unwissenheit, keinesweges aber des Irrthumes liegt. Hätten wir nun keine andre Erkenntnißkraft als den Verstand: so würden wir nie irren. Allein es liegt, außer dem Verstande, noch eine andre unentbehrliche Erkenntnißquelle in uns. Das ist die Sinnlichkeit, die uns den Stoff zum Denken giebt und dabei nach andern Gesetzen wirkt als der Verstand. Aus der Sinnlichkeit an und für sich selbst betrachtet kann aber der Irrthum auch nicht entspringen, weil die Sinne gar nicht urtheilen. Der Entstehungsgrund alles Irrthums wird daher einzig und allein in dem unvermerkten Einflusse der Sinnlichkeit auf den Verstand, oder genauer zu reden, auf das Urtheil, gesucht werden müssen. Dieser Einfluß nämlich macht, daß wir im Urtheilen bloß subjective Gründe für objective halten und folglich den bloßen Schein der Wahrheit mit der Wahrheit selbst verwechseln. Denn darin besteht eben das Wesen des Scheins, der um deswillen als ein Grund anzusehen ist, eine falsche Erkenntniß für wahr zu halten. Was den Irrthum möglich macht, ist also der Schein, nach welchem im Urtheile das bloß Subjective mit dem Objectiven verwechselt wird. In gewissem Sinne kann man wohl den Verstand auch zum Urheber der Irrthümer machen, sofern er nämlich aus Mangel an erforderlicher Aufmerksamkeit auf jenen Einfluß der Sinnlichkeit sich durch den hieraus entsprungenen Schein verleiten läßt, bloß subjective Bestimmungsgründe des Urtheils für objective zu halten, oder das, was nur nach Gesetzen der Sinnlichkeit wahr ist, für wahr nach seinen eigenen Gesetzen gelten zu lassen. Nur die Schuld der Unwissenheit liegt demnach in den Schranken des Verstandes, die Schuld des Irrthums haben wir uns selbst beizumessen. Die Natur hat uns zwar viele Kenntnisse versagt, sie läßt uns über so Manches in einer unvermeidlichen Unwissenheit, aber den Irrthum verursacht sie doch nicht. Zu diesem verleitet uns unser eigener Hang zu urtheilen und zu entscheiden, auch da, wo wir wegen unsrer Begrenztheit zu urtheilen und zu entscheiden nicht vermögend sind."}, {"type": "paragraph", "text": "——————"}], "markers": [{"system": "AA", "band": "IX", "page": 53, "ref": "IX53"}, {"system": "AA", "band": "IX", "page": 54, "ref": "IX54"}], "running_header": "VII. B) Logische Vollkommenheit des Erkenntnisses der Relation nach"}, {"page_pdf": 2761, "page_book": 55, "page_kind": "body", "sigel": "AA IX, 55", "units": [{"type": "paragraph", "text": "Aller Irrthum, in welchen der menschliche Verstand gerathen kann, ist aber nur partial, und in jedem irrigen Urtheile muß immer etwas Wahres liegen. Denn ein totaler Irrthum wäre ein gänzlicher Widerstreit wider die Gesetze des Verstandes und der Vernunft. Wie könnte er, als solcher, auf irgend eine Weise aus dem Verstande kommen, und, sofern er doch ein Urtheil ist, für ein Product des Verstandes gehalten werden! In Rücksicht auf das Wahre und Irrige in unserer Erkenntniß unterscheiden wir ein genaues von einem rohen Erkenntnisse. Genau ist das Erkenntniß, wenn es seinem Object angemessen ist, oder wenn in Ansehung seines Objects nicht der mindeste Irrthum stattfindet, roh ist es, wenn Irrthümer darin sein können, ohne eben der Absicht hinderlich zu sein. Dieser Unterschied betrifft die weitere oder engere Bestimmtheit unsers Erkenntnisses (_cognitio late vel stricte determinata_). Anfangs ist es zuweilen nöthig, ein Erkenntniß in einem weitern Umfange zu bestimmen (_late determinare_), besonders in historischen Dingen. In Vernunfterkenntnissen aber muß alles genau (_stricte_) bestimmt sein. Bei der laten Determination sagt man: ein Erkenntniß sei _praeter propter_ determinirt. Es kommt immer auf die Absicht eines Erkenntnisses an, ob es roh oder genau bestimmt sein soll. Die late Determination läßt noch immer einen Spielraum für den Irrthum übrig, der aber doch seine bestimmten Grenzen haben kann. Irrthum findet besonders da statt, wo eine late Determination für eine stricte genommen wird, z.B. in Sachen der Moralität, wo alles stricte determinirt sein muß. Die das nicht thun, werden von den Engländern Latitudinarier genannt. Von der Genauigkeit, als einer objectiven Vollkommenheit des Erkenntnisses – da das Erkenntniß hier völlig mit dem Object congruirt – kann man noch die Subtilität als eine subjective Vollkommenheit desselben unterscheiden. Ein Erkenntniß von einer Sache ist subtil, wenn man darin dasjenige entdeckt, was Anderer Aufmerksamkeit zu entgehen pflegt. Es erfordert also einen höhern Grad von Aufmerksamkeit und einen größern Aufwand von Verstandeskraft. Viele tadeln alle Subtilität, weil sie sie nicht erreichen können. Aber sie macht an sich immer dem Verstande Ehre und ist sogar verdienstlich und nothwendig, sofern sie auf einen der Beobachtung würdigen Gegenstand angewandt wird. Wenn man aber mit einer geringern Aufmerksamkeit und Anstrengung des Verstandes denselben Zweck hätte erreichen können, und man verwendet doch mehr darauf: so macht man unnützen Aufwand und verfällt in Subtilitäten, die zwar schwer sind, aber zu nichts nützen (_nugae difficiles_). So wie dem Genauen das Rohe, so ist dem Subtilen das Grobe entgegengesetzt."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Aus der Natur des Irrthums, in dessen Begriffe, wie wir bemerkten, außer der Falschheit, noch der Schein der Wahrheit als ein wesentliches Merkmal enthalten ist, ergiebt sich für die Wahrheit unsers Erkenntnisses folgende wichtige Regel: Um Irrthümer zu vermeiden – und unvermeidlich ist wenigstens absolut oder schlechthin kein Irrthum, ob er es gleich beziehungsweise sein kann für die Fälle, da es, selbst auf die Gefahr zu irren, unvermeidlich für uns ist, zu urtheilen – also um Irrthümer zu vermeiden, muß man die Quelle derselben, den Schein, zu entdecken und zu erklären suchen. Das haben aber die wenigsten Philosophen gethan. Sie haben nur die Irrthümer selbst zu widerlegen gesucht, ohne den Schein anzugeben, woraus sie entspringen. Diese Aufdeckung und Auflösung des Scheines ist aber ein weit größeres Verdienst um die Wahrheit als die directe Widerlegung der Irrthümer selbst, wodurch man die Quelle derselben nicht verstopfen und es nicht verhüten kann, daß nicht der nämliche Schein, weil man ihn nicht kennt, in andern Fällen wiederum zu Irrthümern verleite. Denn sind wir auch überzeugt worden, daß wir geirrt haben: so bleiben uns doch, im Fall der Schein selbst, der unserm Irrthume zum Grunde liegt, nicht gehoben ist, noch Scrupel übrig, so"}], "markers": [{"system": "AA", "band": "IX", "page": 55, "ref": "IX55"}, {"system": "AA", "band": "IX", "page": 56, "ref": "IX56"}], "running_header": "VII. B) Logische Vollkommenheit des Erkenntnisses der Relation nach"}, {"page_pdf": 2762, "page_book": 57, "page_kind": "body", "sigel": "AA IX, 57", "units": [{"type": "paragraph", "text": "wenig wir auch zu deren Rechtfertigung vorbringen können. Durch Erklärung des Scheins läßt man überdies auch dem Irrenden eine Art von Billigkeit widerfahren. Denn es wird niemand zugeben, daß er ohne irgend einen Schein der Wahrheit geirrt habe, der vielleicht auch einen Scharfsinnigern hätte täuschen können, weil es hierbei auf subjective Gründe ankommt. Ein Irrthum, wo der Schein auch dem gemeinen Verstande (_sensus communis_) offenbar ist, heißt eine Abgeschmacktheit oder Ungereimtheit. Der Vorwurf der Absurdität ist immer ein persönlicher Tadel, den man vermeiden muß, insbesondre bei Widerlegung der Irrthümer. Denn demjenigen, welcher eine Ungereimtheit behauptet, ist selbst doch der Schein, der dieser offenbaren Falschheit zum Grunde liegt, nicht offenbar. Man muß ihm diesen Schein erst offenbar machen. Beharrt er auch alsdann noch dabei, so ist er freilich abgeschmackt; aber dann ist auch weiter nichts mehr mit ihm anzufangen. Er hat sich dadurch aller weitern Zurechtweisung und Widerlegung eben so unfähig als unwürdig gemacht. Denn man kann eigentlich Keinem beweisen, daß er ungereimt sei; hierbei wäre alles Vernünfteln vergeblich. Wenn man die Ungereimtheit beweist, so redet man nicht mehr mit dem Irrenden, sondern mit dem Vernünftigen. Aber da ist die Aufdeckung der Ungereimtheit (_deductio ad absurdum_) nicht nöthig. Einen abgeschmackten Irrthum kann man auch einen solchen nennen, dem nichts, auch nicht einmal der Schein zur Entschuldigung dient; so wie ein grober Irrthum ein Irrthum ist, welcher Unwissenheit im gemeinen Erkenntnisse oder Verstoß wider gemeine Aufmerksamkeit beweist. Irrthum in Principien ist größer als in ihrer Anwendung."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Ein äußeres Merkmal oder ein äußerer Probirstein der Wahrheit ist die Vergleichung unserer eigenen mit Anderer Urtheilen, weil das Subjective nicht allen Andern auf gleiche Art beiwohnen wird, mithin der Schein dadurch erklärt werden kann. Die Unvereinbarkeit Anderer Urtheile mit den unsrigen ist daher als ein äußeres Merkmal des Irrthums und als ein Wink anzusehen, unser Verfahren im Urtheilen zu untersuchen, aber darum nicht sofort zu verwerfen. Denn man kann doch vielleicht recht haben in der Sache und nur unrecht in der Manier, d.i. dem Vortrage. Der gemeine Menschenverstand (_sensus communis_) ist auch an sich ein Probirstein, um die Fehler des künstlichen Verstandesgebrauchs zu entdecken. Das heißt: sich im Denken oder im speculativen Vernunftgebrauche durch den gemeinen Verstand orientiren, wenn man den gemeinen Verstand als Probe zur Beurtheilung der Richtigkeit des speculativen gebraucht."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Allgemeine Regeln und Bedingungen der Vermeidung des Irrthums überhaupt sind: 1) selbst zu denken, 2) sich in der Stelle eines Andern zu denken, und 3) jederzeit mit sich selbst einstimmig zu denken. Die Maxime des Selbstdenkens kann man die aufgeklärte; die Maxime sich in Anderer Gesichtspunkte im Denken zu versetzen, die erweiterte; und die Maxime, jederzeit mit sich selbst einstimmig zu denken, die consequente oder bündige Denkart nennen."}], "markers": [{"system": "AA", "band": "IX", "page": 57, "ref": "IX57"}], "running_header": "VII. B) Logische Vollkommenheit des Erkenntnisses der Relation nach"}, {"page_pdf": 2763, "page_book": 58, "page_kind": "body", "sigel": "AA IX, 58", "units": [{"type": "heading", "text": "[Einleitung.]", "level": 2}, {"type": "paragraph", "text": "VIII. _C_) Logische Vollkommenheit des Erkenntnisses der Qualität nach. – Klarheit. – Begriff eines Merkmals überhaupt. – Verschiedene Arten der Merkmale. – Bestimmung des logischen Wesens einer Sache. – Unterschied desselben vom Realwesen. – Deutlichkeit, ein höherer Grad der Klarheit. – Ästhetische und logische Deutlichkeit. – Unterschied zwischen analytischer und synthetischer Deutlichkeit. Das menschliche Erkennen ist von Seiten des Verstandes discursiv, d.h. es geschieht durch Vorstellungen, die das, was mehreren Dingen gemein ist, zum Erkenntnißgrunde machen, mithin durch Merkmale als solche. Wir erkennen also Dinge nur durch Merkmale und das heißt eben Erkennen, welches von Kennen herkommt. Ein Merkmal ist dasjenige an einem Dinge, was einen Theil der Erkenntniß desselben ausmacht, oder – welches dasselbe ist – eine Partialvorstellung, sofern sie als Erkenntnißgrund der ganzen Vorstellung betrachtet wird. Alle unsre Begriffe sind demnach Merkmale und alles Denken ist nichts anders als ein Vorstellen durch Merkmale. Ein jedes Merkmal läßt sich von zwei Seiten betrachten: Erstlich, als Vorstellung an sich selbst; Zweitens, als gehörig wie ein Theilbegriff zu der ganzen Vorstellung eines Dinges und dadurch als Erkenntnißgrund dieses Dinges selbst. Alle Merkmale, als Erkenntnißgründe betrachtet, sind von zwiefachem Gebrauche, entweder einem innerlichen oder einem äußerlichen. Der innere Gebrauch besteht in der Ableitung, um durch Merkmale, als ihre Erkenntnißgründe, die Sache selbst zu erkennen. Der äußere Gebrauch besteht in der Vergleichung, sofern wir durch Merkmale ein Ding mit andern nach den Regeln der Identität oder Diversität vergleichen können."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Es giebt unter den Merkmalen mancherlei specifische Unterschiede, auf die sich folgende Classification derselben gründet. 1) Analytische oder synthetische Merkmale. Jene sind Theilbegriffe meines wirklichen Begriffs (die ich darin schon denke), diese dagegen sind Theilbegriffe des bloß möglichen ganzen Begriffs, (der also durch eine Synthesis mehrerer Theile erst werden soll). Erstere sind alle Vernunftbegriffe, die letztern können Erfahrungsbegriffe sein. 2) Coordinirte oder subordinirte. Diese Eintheilung der Merkmale betrifft ihre Verknüpfung nach oder unter einander. Coordinirt sind die Merkmale, sofern ein jedes derselben als ein unmittelbares Merkmal der Sache vorgestellt wird, und subordinirt, sofern ein Merkmal nur vermittelst des andern an dem Dinge vorgestellt wird. Die Verbindung coordinirter Merkmale zum Ganzen des Begriffs heißt ein Aggregat, die Verbindung subordinirter Merkmale eine Reihe. Jene, die Aggregation coordinirter Merkmale macht die Totalität des Begriffs aus, die aber in Ansehung synthetischer empirischer Begriffe nie vollendet sein kann, sondern einer geraden Linie ohne Grenzen gleicht. Die Reihe subordinirter Merkmale stößt _a parte ante,_ oder auf Seiten der Gründe, an unauflösliche Begriffe, die sich ihrer Einfachheit wegen nicht weiter zergliedern lassen, _a parte _ _post,_ oder in Ansehung der Folgen hingegen, ist sie unendlich, weil wir zwar ein höchstes _genus_, aber keine unterste _species_ haben. Mit der Synthesis jedes neuen Begriffs in der Aggregation coordinirter Merkmale wächst die extensive oder ausgebreitete Deutlichkeit, so wie mit der weitern Analysis der Begriffe in der Reihe subordinirter Merkmale die intensive oder tiefe Deutlichkeit. Diese letztere Art der"}], "markers": [{"system": "AA", "band": "IX", "page": 58, "ref": "IX58"}, {"system": "AA", "band": "IX", "page": 59, "ref": "IX59"}], "running_header": "VIII. C) Logische Vollkommenheit des Erkenntnisses der Qualität nach"}, {"page_pdf": 2764, "page_book": 60, "page_kind": "body", "sigel": "AA IX, 60", "units": [{"type": "paragraph", "text": "Deutlichkeit, da sie nothwendig zur Gründlichkeit und Bündigkeit des Erkenntnisses dient, ist darum hauptsächlich Sache der Philosophie und wird insbesondre in metaphysischen Untersuchungen am höchsten getrieben. 3) Bejahende oder verneinende Merkmale. Durch jene erkennen wir, was das Ding ist, durch diese, was es nicht ist. Die verneinenden Merkmale dienen dazu, uns von Irrthümern abzuhalten. Daher sind sie unnöthig, da wo es unmöglich ist zu irren, und nur nöthig und von Wichtigkeit in denjenigen Fällen, wo sie uns von einem wichtigen Irrthume abhalten, in den wir leicht gerathen können. So sind z.B. in Ansehung des Begriffs von einem Wesen, wie Gott, die verneinenden Merkmale sehr nöthig und wichtig. Durch bejahende Merkmale wollen wir also etwas verstehen, durch verneinende – in die man alle Merkmale insgesammt verwandeln kann – nur nicht mißverstehen oder darin nur nicht irren, sollten wir auch nichts davon kennen lernen. 4) Wichtige und fruchtbare oder leere und unwichtige Merkmale. Ein Merkmal ist wichtig und fruchtbar, wenn es ein Erkenntnißgrund von großen und zahlreichen Folgen ist, theils in Ansehung seines innern Gebrauchs, des Gebrauchs in der Ableitung, sofern es hinreichend ist, um dadurch sehr viel an der Sache selbst zu erkennen, theils in Rücksicht auf seinen äußern Gebrauch, den Gebrauch in der Vergleichung, sofern es dazu dient, sowohl die Ähnlichkeit eines Dinges mit vielen andern als auch die Verschiedenheit desselben von vielen andern zu erkennen. Übrigens müssen wir hier die logische Wichtigkeit und Fruchtbarkeit von der praktischen, der Nützlichkeit und Brauchbarkeit unterscheiden. 5) Zureichende und nothwendige oder unzureichende und zufällige Merkmale. Ein Merkmal ist zureichend, sofern es hinreicht, das Ding jederzeit von allen andern zu unterscheiden; widrigenfalls ist es unzureichend, wie z.B. das Merkmal des Bellens vom Hunde. Die Hinlänglichkeit der Merkmale ist aber so gut wie ihre Wichtigkeit nur in einem relativen Sinne zu bestimmen, in Beziehung auf die Zwecke, welche durch ein Erkenntniß beabsichtigt werden. Nothwendige Merkmale sind endlich diejenigen, die jederzeit bei der vorgestellten Sache müssen anzutreffen sein. Dergleichen Merkmale heißen auch wesentliche und sind den außerwesentlichen und zufälligen entgegengesetzt, die von dem Begriffe des Dinges getrennt werden können. Unter den nothwendigen Merkmalen giebt es aber noch einen Unterschied. Einige derselben kommen dem Dinge zu als Gründe andrer Merkmale von Einer und derselben Sache, andre dagegen nur als Folgen von andern Merkmalen. Die erstern sind primitive und constitutive Merkmale (_constitutiva, essentialia in sensu _ _strictissimo_), die andern heißen Attribute (_consectaria, rationata_) und gehören zwar auch zum Wesen des Dinges, aber nur, sofern sie aus jenen wesentlichen Stücken desselben erst abgeleitet werden müssen; wie z.B. die drei Winkel im Begriffe eines Triangels aus den drei Seiten. Die außerwesentlichen Merkmale sind auch wieder von zwiefacher Art, sie betreffen entweder innere Bestimmungen eines Dinges (_modi_) oder dessen äußere Verhältnisse (_relationes_). So bezeichnet z.B. das Merkmal der Gelehrsamkeit eine innere Bestimmung des Menschen, Herr oder Knecht sein, nur ein äußeres Verhältniß desselben."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Der Inbegriff aller wesentlichen Stücke eines Dinges oder die Hinlänglichkeit der Merkmale desselben der Coordination oder der Subordination nach, ist das Wesen (_complexus notarum _"}], "markers": [{"system": "AA", "band": "IX", "page": 60, "ref": "IX60"}, {"system": "AA", "band": "IX", "page": 61, "ref": "IX61"}], "running_header": "VIII. C) Logische Vollkommenheit des Erkenntnisses der Qualität nach"}, {"page_pdf": 2765, "page_book": 62, "page_kind": "body", "sigel": "AA IX, 62", "units": [{"type": "paragraph", "text": "_primitivarum, interne conceptui dato sufficientium; s. complexus notarum, conceptum aliquem _ _primitive constituentium_). Bei dieser Erklärung müssen wir aber hier ganz und gar nicht an das Real- oder Natur-Wesen der Dinge denken, das wir überall nicht einzusehen vermögen. Denn da die Logik von allem Inhalte des Erkenntnisses, folglich auch von der Sache selbst abstrahirt: so kann in dieser Wissenschaft lediglich nur von dem logischen Wesen der Dinge die Rede sein. Und dieses können wir leicht einsehen. Denn dazu gehört weiter nichts als die Erkenntniß aller der Prädicate, in Ansehung deren ein Object durch seinen Begriff bestimmt ist; anstatt daß zum Real-Wesen des Dinges (_esse rei_) die Erkenntniß derjenigen Prädicate erfordert wird, von denen alles, was zu seinem Dasein gehört, als Bestimmungsgründen, abhängt. Wollen wir z.B. das logische Wesen des Körpers bestimmen: so haben wir gar nicht nöthig die Data hierzu in der Natur aufzusuchen; wir dürfen unsre Reflexion nur auf die Merkmale richten, die als wesentliche Stücke (_constitutiva, rationes_) den Grundbegriff desselben ursprünglich constituiren. Denn das logische Wesen ist ja selbst nichts anders als der erste Grundbegriff aller nothwendigen Merkmale eines Dinges (_esse conceptus_)."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Die erste Stufe der Vollkommenheit unsers Erkenntnisses der Qualität nach ist also die Klarheit desselben. Eine zweite Stufe, oder ein höherer Grad der Klarheit, ist die Deutlichkeit. Diese besteht in der Klarheit der Merkmale. Wir müssen hier zuvörderst die logische Deutlichkeit überhaupt von der ästhetischen unterscheiden. Die logische beruht auf der objectiven, die ästhetische auf der subjectiven Klarheit der Merkmale. Jene ist eine Klarheit durch Begriffe, diese eine Klarheit durch Anschauung. Die letztere Art der Deutlichkeit besteht also in einer bloßen Lebhaftigkeit und Verständlichkeit, d.h. in einer bloßen Klarheit durch Beispiele _in concreto_, (denn verständlich kann vieles sein, was doch nicht deutlich ist, und umgekehrt kann Vieles deutlich sein, was doch schwer zu verstehen ist, weil es bis auf entfernte Merkmale zurückgeht, deren Verknüpfung mit der Anschauung nur durch eine lange Reihe möglich ist). Die objective Deutlichkeit verursacht öfters subjective Dunkelheit und umgekehrt. Daher ist die logische Deutlichkeit nicht selten nur zum Nachtheil der ästhetischen möglich und umgekehrt wird oft die ästhetische Deutlichkeit durch Beispiele und Gleichnisse, die nicht genau passen, sondern nur nach einer Analogie genommen werden, der logischen Deutlichkeit schädlich. Überdies sind auch Beispiele überhaupt keine Merkmale und gehören nicht als Theile zum Begriffe, sondern als Anschauungen nur zum Gebrauche des Begriffs. Eine Deutlichkeit durch Beispiele, die bloße Verständlichkeit, ist daher von ganz anderer Art als die Deutlichkeit durch Begriffe als Merkmale. In der Verbindung beider, der ästhetischen oder populären mit der scholastischen oder logischen Deutlichkeit, besteht die Helligkeit. Denn unter einem hellen Kopfe denkt man sich das Talent einer lichtvollen, der Fassungskraft des gemeinen Verstandes angemessenen Darstellung abstracter und gründlicher Erkenntnisse. Was nun hiernächst insbesondre die logische Deutlichkeit betrifft: so ist sie eine vollständige Deutlichkeit zu nennen, sofern alle Merkmale, die zusammen genommen den ganzen Begriff ausmachen, bis zur Klarheit gekommen sind. Ein vollständig oder complet deutlicher Begriff kann es nun hinwiederum sein, entweder in Ansehung der Totalität seiner coordinirten oder in Rücksicht auf die Totalität seiner subordinirten Merkmale. In der totalen Klarheit der coordinirten Merkmale besteht die extensiv vollständige oder zureichende Deutlichkeit eines Begriffs, die auch die Ausführlichkeit heißt. Die totale Klarheit der subordinirten Merkmale macht die intensiv vollständige Deutlichkeit aus, die Profundität. Die erstere Art der logischen Deutlichkeit kann auch die äußere Vollständigkeit (_completudo externa_), so wie die andre, die innere Vollständigkeit (_completudo interna_) der"}], "markers": [{"system": "AA", "band": "IX", "page": 62, "ref": "IX62"}, {"system": "AA", "band": "IX", "page": 63, "ref": "IX63"}], "running_header": "VIII. C) Logische Vollkommenheit des Erkenntnisses der Qualität nach"}, {"page_pdf": 2766, "page_book": 64, "page_kind": "body", "sigel": "AA IX, 64", "units": [{"type": "paragraph", "text": "Klarheit der Merkmale genannt werden. Die letztere läßt sich nur von reinen Vernunftbegriffen und von willkürlichen Begriffen, nicht aber von empirischen erlangen. Die extensive Größe der Deutlichkeit, sofern sie nicht abundant ist, heißt Präcision (Abgemessenheit). Die Ausführlichkeit (_completudo_) und Abgemessenheit (_praecisio_) zusammen machen die Angemessenheit aus (_cognitionem, quae rem adaequat_); und in der intensiv adäquaten Erkenntniß, in der Profundität, verbunden mit der extensiv adäquaten in der Ausführlichkeit und Präcision, besteht (der Qualität nach) die vollendete Vollkommenheit eines Erkenntnisses (_consummata cognitionis perfectio_)."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Da es, wie wir bemerkt haben, das Geschäft der Logik ist, klare Begriffe deutlich zu machen, so frägt es sich nun: Auf welche Art sie dieselben deutlich mache? Die Logiker aus der Wolffischen Schule setzen alle Deutlichmachung der Erkenntnisse in die bloße Zergliederung derselben. Allein nicht alle Deutlichkeit beruht auf der Analysis eines gegebenen Begriffs. Dadurch entsteht sie nur in Ansehung derjenigen Merkmale, die wir schon in dem Begriffe dachten, keinesweges aber in Rücksicht auf die Merkmale, die zum Begriffe erst hinzukommen, als Theile des ganzen möglichen Begriffs. Diejenige Art der Deutlichkeit, die nicht durch Analysis, sondern durch Synthesis der Merkmale entspringt, ist die synthetische Deutlichkeit. Und es ist also ein wesentlicher Unterschied zwischen den beiden Sätzen: Einen deutlichen Begriff machen und einen Begriff deutlich machen. Denn wenn ich einen deutlichen Begriff mache: so fange ich von den Theilen an und gehe von diesen zum Ganzen fort. Es sind hier noch keine Merkmale vorhanden; ich erhalte dieselben erst durch die Synthesis. Aus diesem synthetischen Verfahren geht also die synthetische Deutlichkeit hervor, welche meinen Begriff durch das, was über denselben in der (reinen oder empirischen) Anschauung als Merkmal hinzukommt, dem Inhalte nach wirklich erweitert. Dieses synthetischen Verfahrens in Deutlichmachung der Begriffe bedient sich der Mathematiker und auch der Naturphilosoph. Denn alle Deutlichkeit des eigentlich mathematischen so wie alles Erfahrungserkenntnisses beruht auf einer solchen Erweiterung desselben durch Synthesis der Merkmale. Wenn ich aber einen Begriff deutlich mache: so wächst durch diese bloße Zergliederung mein Erkenntniß ganz und gar nicht dem Inhalte nach. Dieser bleibt derselbe, nur die Form wird verändert, indem ich das, was in dem gegebenen Begriffe schon lag, nur besser unterscheiden oder mit klärerem Bewußtsein erkennen lerne. So wie durch die bloße Illumination einer Karte zu ihr selbst nichts weiter hinzukommt: so wird auch durch die bloße Aufhellung eines gegebenen Begriffs vermittelst der Analysis seiner Merkmale dieser Begriff selbst nicht im mindesten vermehrt. Zur Synthesis gehört die Deutlichmachung der Objecte, zur Analysis die Deutlichmachung der Begriffe. Hier geht das Ganze den Theilen, dort gehen die Theile dem Ganzen vorher. Der Philosoph macht nur gegebene Begriffe deutlich. Zuweilen verfährt man synthetisch, auch wenn der Begriff, den man auf diese Art deutlich machen will, schon gegeben ist. Dieses findet oft statt bei Erfahrungssätzen, wofern man mit den in einem gegebenen Begriffe schon gedachten Merkmalen noch nicht zufrieden ist. Das analytische Verfahren, Deutlichkeit zu erzeugen, womit sich die Logik allein beschäftigen kann, ist das erste und hauptsächlichste Erforderniß bei der Deutlichmachung unseres Erkenntnisses. Denn je deutlicher unser Erkenntniß von einer Sache ist: um so stärker und wirksamer kann es auch sein. Nur muß die Analysis nicht so weit gehen, daß darüber der Gegenstand selbst am Ende verschwindet. Wären wir uns alles dessen bewußt, was wir wissen, so müßten wir über die große Menge"}], "markers": [{"system": "AA", "band": "IX", "page": 64, "ref": "IX64"}], "running_header": "VIII. C) Logische Vollkommenheit des Erkenntnisses der Qualität nach"}, {"page_pdf": 2767, "page_book": 65, "page_kind": "body", "sigel": "AA IX, 65", "units": [{"type": "paragraph", "text": "unserer Erkenntnisse erstaunen."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "In Ansehung des objectiven Gehaltes unserer Erkenntniß überhaupt lassen sich folgende Grade denken, nach welchen dieselbe in dieser Rücksicht kann gesteigert werden: Der erste Grad der Erkenntniß ist: sich etwas vorstellen; Der zweite: sich mit Bewußtsein etwas vorstellen oder wahrnehmen (_percipere_); Der dritte: etwas kennen (_noscere_) oder sich etwas in der Vergleichung mit andern Dingen vorstellen sowohl der Einerleiheit als der Verschiedenheit nach; Der vierte: mit Bewußtsein etwas kennen, d.h. erkennen (_cognoscere_). Die Thiere kennen auch Gegenstände, aber sie erkennen sie nicht. Der fünfte: etwas verstehen (_intelligere_), d.h. durch den Verstand vermöge der Begriffe erkennen oder concipiren. Dieses ist vom Begreifen sehr unterschieden. Concipiren kann man Vieles, obgleich man es nicht begreifen kann, z.B. ein _perpetuum mobile,_ dessen Unmöglichkeit in der Mechanik gezeigt wird. Der sechste: etwas durch die Vernunft erkennen oder einsehen (_perspicere_). Bis dahin gelangen wir in wenigen Dingen und unsre Erkenntnisse werden der Zahl nach immer geringer, je mehr wir sie dem Gehalte nach vervollkommnen wollen. Der siebente endlich: etwas begreifen (_comprehendere_), d.h. in dem Grade durch die Vernunft oder _a priori_ erkennen, als zu unsrer Absicht hinreichend ist. Denn alles unser Begreifen ist nur relativ, d.h. zu einer gewissen Absicht hinreichend, schlechthin begreifen wir gar nichts. Nichts kann mehr begriffen werden, als was der Mathematiker demonstrirt, z.B. daß alle Linien im Cirkel proportional sind. Und doch begreift er nicht: wie es zugehe, daß eine so einfache Figur diese Eigenschaften habe. Das Feld des Verstehens oder des Verstandes ist daher überhaupt weit größer als das Feld des Begreifens oder der Vernunft."}], "markers": [{"system": "AA", "band": "IX", "page": 65, "ref": "IX65"}], "running_header": "VIII. C) Logische Vollkommenheit des Erkenntnisses der Qualität nach"}, {"page_pdf": 2768, "page_book": 65, "page_kind": "body", "sigel": "AA IX, 65", "units": [{"type": "heading", "text": "[Einleitung.]", "level": 2}, {"type": "paragraph", "text": "IX. _D_) Logische Vollkommenheit des Erkenntnisses der Modalität nach. Gewißheit. – Begriff des Fürwahrhaltens überhaupt. – Modi des Fürwahrhaltens: Meinen, Glauben, Wissen. – Überzeugung und Überredung. – Zurückhalten und Aufschieben eines Urtheils. – Vorläufige Urtheile. – Vorurtheile, deren Quellen und Hauptarten. Wahrheit ist objective Eigenschaft der Erkenntniß, das Urtheil, wodurch etwas als wahr vorgestellt wird; die Beziehung auf einen Verstand und also auf ein besonderes Subject ist subjectiv das Fürwahrhalten. Das Fürwahrhalten ist überhaupt von zwiefacher Art, ein gewisses oder ein ungewisses. Das gewisse Fürwahrhalten oder die Gewißheit ist mit dem Bewußtsein der Nothwendigkeit verbunden, das ungewisse dagegen oder die Ungewißheit, mit dem Bewußtsein der Zufälligkeit oder der Möglichkeit des Gegentheils. Das letztere ist hinwiederum entweder sowohl subjectiv als objectiv unzureichend, oder zwar objectiv unzureichend, aber subjectiv zureichend. Jenes heißt Meinung, dieses muß Glaube genannt werden. Es giebt hiernach drei Arten oder Modi des Fürwahrhaltens: Meinen, Glauben und Wissen. Das Meinen ist ein problematisches, das Glauben ein assertorisches und das Wissen ein apodiktisches Urtheilen. Denn was ich bloß meine, das halte ich im Urtheilen mit Bewußtsein nur für problematisch; was ich glaube, für assertorisch, aber nicht als objectiv, sondern nur als subjectiv nothwendig (nur für mich geltend); was ich endlich weiß, für apodiktisch gewiß, d.i. für allgemein und objectiv nothwendig (für Alle geltend), gesetzt auch, daß der Gegenstand selbst, auf den sich dieses gewisse Fürwahrhalten bezieht, eine bloß empirische Wahrheit wäre. Denn diese Unterscheidung des Fürwahrhaltens nach den so eben genannten drei _modis_ betrifft nur die Urtheilskraft in Ansehung der subjectiven Kriterien der Subsumtion eines Urtheils unter objective Regeln. So wäre z.B. unser Fürwahrhalten der Unsterblichkeit bloß problematisch; wofern wir nur so handeln, als ob wir unsterblich wären, assertorisch aber, sofern wir glauben, daß wir unsterblich sind, und apodiktisch endlich: sofern wir Alle wüßten, daß es ein anderes Leben nach diesem giebt. Zwischen Meinen, Glauben und Wissen findet demnach ein wesentlicher Unterschied statt, den wir hier noch genauer und ausführlicher auseinandersetzen wollen. 1) Meinen.Das Meinen oder das Fürwahrhalten aus einem Erkenntnißgrunde, der weder subjectiv noch objectiv hinreichend ist, kann als ein vorläufiges Urtheilen (_sub conditione _ _suspensiva ad interim_) angesehen werden, dessen man nicht leicht entbehren kann. Man muß erst meinen, ehe man annimmt und behauptet, sich dabei aber auch hüten, eine Meinung für etwas mehr als bloße Meinung zu halten. Vom Meinen fangen wir größtentheils bei allem unserm Erkennen an. Zuweilen haben wir ein dunkles Vorgefühl von der Wahrheit, eine Sache scheint uns Merkmale der Wahrheit zu enthalten; wir ahnen ihre Wahrheit schon, noch ehe wir sie mit bestimmter Gewißheit erkennen. Wo findet nun aber das bloße Meinen eigentlich statt? In keinen Wissenschaften, welche Erkenntnisse _a priori_ enthalten, also weder in der Mathematik, noch in der Metaphysik, noch in der Moral, sondern lediglich in empirischen Erkenntnissen: in der Physik, der Psychologie u.dgl. Denn es ist an sich ungereimt, _a priori_ zu meinen. Auch könnte in der That nichts lächerlicher sein, als z.B. in der Mathematik nur zu meinen. Hier, so wie in der Metaphysik und Moral, gilt es: entweder zu wissen oder nicht zu wissen. Meinungssachen können daher immer nur Gegenstände einer Erfahrungserkenntniß sein, die an sich zwar möglich, aber nur für uns unmöglich ist nach den empirischen Einschränkungen und Bedingungen unsers Erfahrungsvermögens und dem davon abhängenden Grade dieses Vermögens, den wir besitzen."}], "markers": [{"system": "AA", "band": "IX", "page": 65, "ref": "IX65"}, {"system": "AA", "band": "IX", "page": 66, "ref": "IX66"}, {"system": "AA", "band": "IX", "page": 67, "ref": "IX67"}], "running_header": "IX. D) Logische Vollkommenheit des Erkenntnisses der Modalität nach"}, {"page_pdf": 2769, "page_book": 68, "page_kind": "body", "sigel": "AA IX, 68", "units": [{"type": "paragraph", "text": "So ist z.B. der Äther der neuern Physiker eine bloße Meinungssache. Denn von dieser, so wie von jeder Meinung überhaupt, welche sie auch immer sein möge, sehe ich ein: daß das Gegentheil doch vielleicht könnte bewiesen werden. Mein Fürwahrhalten ist also hier objectiv sowohl als subjectiv unzureichend, obgleich es an sich betrachtet, vollständig werden kann. 2) Glauben. Das Glauben oder das Fürwahrhalten aus einem Grunde, der zwar objectiv unzureichend, aber subjectiv zureichend ist, bezieht sich auf Gegenstände, in Ansehung deren man nicht allein nichts wissen, sondern auch nichts meinen, ja auch nicht einmal Wahrscheinlichkeit vorwenden, sondern bloß gewiß sein kann, daß es nicht widersprechend ist, sich dergleichen Gegenstände so zu denken, wie man sie sich denkt. Das Übrige hierbei ist ein freies Fürwahrhalten, welches nur in praktischer, _a priori_ gegebener Absicht nöthig ist, also ein Fürwahrhalten dessen, was ich aus moralischen Gründen annehme und zwar so, daß ich gewiß bin, das Gegentheil könne nie bewiesen werden.*[1] Sachen des Glaubens sind also I) keine Gegenstände des empirischen Erkenntnisses. Der sogenannte historische Glaube kann daher eigentlich auch nicht Glaube genannt und als solcher dem Wissen entgegengesetzt werden, da er selbst ein Wissen sein kann. Das Fürwahrhalten auf ein Zeugniß ist weder dem Grade noch der Art nach vom Fürwahrhalten durch eigene Erfahrung unterschieden. II) auch keine Objecte des Vernunfterkenntnisses (Erkenntnisses _a priori_), weder des theoretischen, z.B. in der Mathematik und Metaphysik, noch des praktischen in der Moral. Mathematische Vernunftwahrheiten kann man auf Zeugnisse zwar glauben, weil Irrthum hier theils nicht leicht möglich ist, theils auch leicht entdeckt werden kann, aber man kann sie auf diese Art doch nicht wissen. Philosophische Vernunftwahrheiten lassen sich aber auch nicht einmal glauben, sie müssen lediglich gewußt werden; denn Philosophie leidet in sich keine bloße Überredung. Und was insbesondre die Gegenstände des praktischen Vernunfterkenntnisses in der Moral, die Rechte und Pflichten, betrifft: so kann in Ansehung dieser eben so wenig ein bloßes Glauben stattfinden. Man muß völlig gewiß sein: ob etwas recht oder unrecht, pflichtmäßig oder pflichtwidrig, erlaubt oder unerlaubt sei. Auf’s Ungewisse kann man in moralischen Dingen nichts wagen, nichts auf die Gefahr des Verstoßes gegen das Gesetz beschließen. So ist es z.B. für den Richter nicht genug, daß er bloß glaube, der eines Verbrechens wegen Angeklagte habe dieses Verbrechen wirklich begangen. Er muß es (juridisch) wissen, oder handelt gewissenlos. III) Nur solche Gegenstände sind Sachen des Glaubens, bei denen das Fürwahrhalten nothwendig frei, d.h. nicht durch objective, von der Natur und dem Interesse des Subjects unabhängige Gründe der Wahrheit bestimmt ist. Das Glauben giebt daher auch wegen der bloß subjectiven Gründe keine Überzeugung, die sich mittheilen läßt und allgemeine Beistimmung gebietet, wie die Überzeugung, die aus dem Wissen kommt. Ich selbst kann nur von der Gültigkeit und Unveränderlichkeit meines praktischen Glaubens gewiß sein und mein Glaube an die Wahrheit eines Satzes oder die Wirklichkeit eines Dinges ist das, was in Beziehung auf mich nur die Stelle eines Erkenntnisses vertritt, ohne selbst ein Erkenntniß zu sein. Moralisch ungläubig ist der, welcher nicht dasjenige annimmt, was zu wissen zwar unmöglich, aber vorauszusetzen, moralisch nothwendig ist. Dieser Art des Unglaubens liegt immer Mangel an moralischem Interesse zum Grunde. Je größer die moralische Gesinnung eines Menschen ist: desto fester und lebendiger wird auch sein Glaube sein an alles dasjenige, was er aus dem moralischen Interesse in praktisch nothwendiger Absicht anzunehmen und vorauszusetzen sich genöthigt fühlt. 3) Wissen. Das Fürwahrhalten aus einem Erkenntnißgrunde, der sowohl objectiv als subjectiv zureichend ist, oder die Gewißheit ist entweder empirisch oder rational, je nachdem sie entweder auf Erfahrung – die eigene sowohl als die fremde mitgetheilte – oder auf Vernunft sich gründet. Diese Unterscheidung bezieht sich also auf die beiden Quellen, woraus"}], "markers": [{"system": "AA", "band": "IX", "page": 68, "ref": "IX68"}, {"system": "AA", "band": "IX", "page": 69, "ref": "IX69"}, {"system": "AA", "band": "IX", "page": 70, "ref": "IX70"}], "running_header": "IX. D) Logische Vollkommenheit des Erkenntnisses der Modalität nach"}, {"page_pdf": 2770, "page_book": 71, "page_kind": "body", "sigel": "AA IX, 71", "units": [{"type": "paragraph", "text": "unser gesammtes Erkenntniß geschöpft wird: die Erfahrung und die Vernunft . Die rationale Gewißheit ist hinwiederum entweder mathematische oder philosophische Gewißheit. Jene ist intuitiv, diese discursiv. Die mathematische Gewißheit heißt auch Evidenz, weil ein intuitives Erkenntniß klärer ist als ein discursives. Obgleich also beides, das mathematische und das philosophische Vernunfterkenntniß an sich gleich gewiß ist: so ist doch die Art der Gewißheit in beiden verschieden. Die empirische Gewißheit ist eine ursprüngliche (_originarie empirica_), sofern ich von etwas aus eigener Erfahrung, und eine abgeleitete (_derivative empirica_), sofern ich durch fremde Erfahrung wovon gewiß werde. Diese letztere pflegt auch die historische Gewißheit genannt zu werden. Die rationale Gewißheit unterscheidet sich von der empirischen durch das Bewußtsein der Nothwendigkeit, das mit ihr verbunden ist, sie ist also eine apodiktische, die empirische dagegen nur eine assertorische Gewißheit. Rational gewiß ist man von dem, was man auch ohne alle Erfahrung _a priori_ würde eingesehen haben. Unsre Erkenntnisse können daher Gegenstände der Erfahrung betreffen und die Gewißheit davon kann doch empirisch und rational zugleich sein, sofern wir nämlich einen empirisch gewissen Satz aus Principien _a priori_ erkennen. Rationale Gewißheit können wir nicht von Allem haben, aber da, wo wir sie haben können, müssen wir sie der empirischen vorziehen. Alle Gewißheit ist entweder eine unvermittelte oder eine vermittelte, d.h. sie bedarf entweder eines Beweises, oder ist keines Beweises fähig und bedürftig. Wenn auch noch so Vieles in unserm Erkenntnisse nur mittelbar, d.h. nur durch einen Beweis gewiß ist: so muß es doch auch etwas Indemonstrables oder unmittelbar Gewisses geben und unser gesammtes Erkenntniß muß von unmittelbar gewissen Sätzen ausgehen. Die Beweise, auf denen alle vermittelte oder mittelbare Gewißheit eines Erkenntnisses beruht, sind entweder directe oder indirecte d.h. apagogische Beweise. Wenn ich eine Wahrheit aus ihren Gründen beweise, so führe ich einen directen Beweis für dieselbe, und wenn ich von der Falschheit des Gegentheils auf die Wahrheit eines Satzes schließe, einen apagogischen. Soll aber dieser letztere Gültigkeit haben, so müssen sich die Sätze contradictorisch oder diametraliter entgegengesetzt sein. Denn zwei einander bloß conträr entgegengesetzte Sätze (_contrarie opposita_) können beide falsch sein. Ein Beweis, welcher der Grund mathematischer Gewißheit ist, heißt Demonstration und der der Grund philosophischer Gewißheit ist, ein akroamatischer Beweis. Die wesentlichen Stücke eines jeden Beweises überhaupt sind die Materie und die Form desselben, oder der Beweisgrund und die Consequenz. Vom Wissen kommt Wissenschaft her, worunter der Inbegriff einer Erkenntniß als System zu verstehen ist. Sie wird der gemeinen Erkenntniß entgegengesetzt, d.i. dem Inbegriff einer Erkenntniß als bloßem Aggregate. Das System beruht auf einer Idee des Ganzen, welche den Theilen vorangeht, beim gemeinen Erkenntnisse dagegen oder dem bloßen Aggregate von Erkenntnissen gehen die Theile dem Ganzen vorher. Es giebt historische und Vernunft wissenschaften. In einer Wissenschaft wissen wir oft nur die Erkenntnisse, aber nicht die dadurch vorgestellten Sachen; also kann es eine Wissenschaft von demjenigen geben, wovon unsre Erkenntniß kein Wissen ist."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Aus den bisherigen Bemerkungen über die Natur und die Arten des Fürwahrhaltens können wir nun das allgemeine Resultat ziehen: daß also alle unsre Überzeugung entweder logisch oder praktisch sei. Nämlich wenn wir wissen, daß wir frei sind von allen subjectiven Gründen und doch das Fürwahrhalten zureichend ist, so sind wir überzeugt und zwar logisch oder aus"}], "markers": [{"system": "AA", "band": "IX", "page": 71, "ref": "IX71"}, {"system": "AA", "band": "IX", "page": 72, "ref": "IX72"}], "running_header": "IX. D) Logische Vollkommenheit des Erkenntnisses der Modalität nach"}, {"page_pdf": 2771, "page_book": 73, "page_kind": "body", "sigel": "AA IX, 73", "units": [{"type": "paragraph", "text": "objectiven Gründen überzeugt (das Object ist gewiß). Das complete Fürwahrhalten aus subjectiven Gründen, die in praktischer Beziehung so viel als objective gelten, ist aber auch Überzeugung, nur nicht logische, sondern praktische (ich bin gewiß). Und diese praktische Überzeugung oder dieser moralische Vernunftglaube ist oft fester als alles Wissen. Beim Wissen hört man noch auf Gegengründe, aber beim Glauben nicht, weil es hierbei nicht auf objective Gründe, sondern auf das moralische Interesse des Subjects ankommt.*[2] Der Überzeugung steht die Überredung entgegen, ein Fürwahrhalten aus unzureichenden Gründen, von denen man nicht weiß, ob sie bloß subjectiv oder auch objectiv sind. Die Überredung geht oft der Überzeugung vorher. Wir sind uns vieler Erkenntnisse nur so bewußt, daß wir nicht urtheilen können, ob die Gründe unsers Fürwahrhaltens objectiv oder subjectiv sind. Wir müssen daher, um von der bloßen Überredung zur Überzeugung gelangen zu können, zuvörderst überlegen, d.h. sehen, zu welcher Erkenntnißkraft ein Erkenntniß gehöre, und sodann untersuchen, d.i. prüfen, ob die Gründe in Ansehung des Objects zureichend oder unzureichend sind. Bei Vielen bleibt es bei der Überredung. Bei Einigen kommt es zur Überlegung, bei Wenigen zur Untersuchung. Der da weiß, was zur Gewißheit gehört, wird Überredung und Überzeugung nicht leicht verwechseln und sich also auch nicht leicht überreden lassen. Es giebt einen Bestimmungsgrund zum Beifall, der aus objectiven und subjectiven Gründen zusammengesetzt ist, und diese vermischte Wirkung setzen die mehresten Menschen nicht aus einander. Obgleich jede Überredung der Form nach (_formaliter_) falsch ist, sofern nämlich hierbei eine ungewisse Erkenntniß gewiß zu sein scheint: so kann sie doch der Materie nach (_materialiter_) wahr sein. Und so unterscheidet sie sich denn auch von der Meinung, die eine ungewisse Erkenntniß ist, sofern sie für ungewiß gehalten wird. Die Zulänglichkeit des Fürwahrhaltens (im Glauben) läßt sich auf die Probe stellen durch Wetten oder durch Schwören. Zu dem ersten ist comparative, zum zweiten absolute Zulänglichkeit objectiver Gründe nöthig, statt deren, wenn sie nicht vorhanden sind, dennoch ein schlechterdings subjectiv zureichendes Fürwahrhalten gilt."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Man pflegt sich oft der Ausdrücke zu bedienen: Seinem Urtheile beipflichten, sein Urtheil zurückhalten, aufschieben oder aufgeben. Diese und ähnliche Redensarten scheinen anzudeuten, daß in unserm Urtheilen etwas Willkürliches sei, indem wir etwas für wahr halten, weil wir es für wahr halten wollen. Es frägt sich demnach hier: Ob das Wollen einen Einfluß auf unsre Urtheile habe? Unmittelbar hat der Wille keinen Einfluß auf das Fürwahrhalten; dies wäre auch sehr ungereimt. Wenn es heißt: Wir glauben gern, was wir wünschen, so bedeutet das nur unsre gutartigen Wünsche, z.B. die des Vaters von seinen Kindern. Hätte der Wille einen unmittelbaren Einfluß auf unsre Überzeugung von dem, was wir wünschen: so würden wir uns beständig Chimären von einem glücklichen Zustande machen und sie sodann auch immer für wahr halten. Der Wille kann aber nicht wider überzeugende Beweise von Wahrheiten streiten, die seinen Wünschen und Neigungen zuwider sind. Sofern aber der Wille den Verstand entweder zur Nachforschung einer Wahrheit antreibt oder davon abhält, muß man ihm einen Einfluß auf den Gebrauch des Verstandes und mithin auch mittelbar auf die Überzeugung selbst zugestehen, da diese so sehr von dem Gebrauche des Verstandes abhängt. Was aber insbesondre die Aufschiebung oder Zurückhaltung unsers Urtheils betrifft: so besteht dieselbe in dem Vorsatze, ein bloß vorläufiges Urtheil nicht zu einem bestimmenden"}], "markers": [{"system": "AA", "band": "IX", "page": 73, "ref": "IX73"}, {"system": "AA", "band": "IX", "page": 74, "ref": "IX74"}], "running_header": "IX. D) Logische Vollkommenheit des Erkenntnisses der Modalität nach"}, {"page_pdf": 2772, "page_book": 75, "page_kind": "body", "sigel": "AA IX, 75", "units": [{"type": "paragraph", "text": "werden zu lassen. Ein vorläufiges Urtheil ist ein solches, wodurch ich mir vorstelle, daß zwar mehr Gründe für die Wahrheit einer Sache, als wider dieselbe da sind, daß aber diese Gründe noch nicht zureichen zu einem bestimmenden oder definitiven Urtheile, dadurch ich geradezu für die Wahrheit entscheide. Das vorläufige Urtheilen ist also ein mit Bewußtsein bloß problematisches Urtheilen. Die Zurückhaltung des Urtheils kann in zwiefacher Absicht geschehen: entweder, um die Gründe des bestimmenden Urtheils aufzusuchen, oder um niemals zu urtheilen. Im erstern Falle heißt die Aufschiebung des Urtheils eine kritische (_suspensio judicii indagatoria_), im letztern eine skeptische (_suspensio judicii sceptica_). Denn der Skeptiker thut auf alles Urtheilen Verzicht, der wahre Philosoph dagegen suspendirt bloß sein Urtheil, wofern er noch nicht genugsame Gründe hat, etwas für wahr zu halten. Sein Urtheil nach Maximen zu suspendiren, dazu wird eine geübte Urtheilskraft erfordert, die sich nur bei zunehmendem Alter findet. Überhaupt ist die Zurückhaltung unsers Beifalls eine sehr schwere Sache, theils weil unser Verstand so begierig ist durch Urtheilen sich zu erweitern und mit Kenntnissen zu bereichern, theils weil unser Hang immer auf gewisse Sachen mehr gerichtet ist als auf andre. Wer aber seinen Beifall oft hat zurücknehmen müssen und dadurch klug und vorsichtig geworden ist, wird ihn nicht so schnell geben, aus Furcht, sein Urtheil in der Folge wieder zurücknehmen zu müssen. Dieser Widerruf ist immer eine Kränkung und eine Ursache, auf alle andren Kenntnisse ein Mißtrauen zu setzen. Noch bemerken wir hier: daß es etwas anders ist, sein Urtheil _in dubio,_ als es _in suspenso_ zu lassen. Bei diesem habe ich immer ein Interesse für die Sache, bei jenem ist es nicht immer meinem Zwecke und Interesse gemäß zu entscheiden, ob die Sache wahr sei oder nicht. Die vorläufigen Urtheile sind sehr nöthig, ja unentbehrlich für den Gebrauch des Verstandes bei allem Meditiren und Untersuchen. Denn sie dienen dazu, den Verstand bei seinen Nachforschungen zu leiten und ihm hierzu verschiedene Mittel an die Hand zu geben. Wenn wir über einen Gegenstand meditiren, müssen wir immer schon vorläufig urtheilen und das Erkenntniß gleichsam schon wittern, das uns durch die Meditation zu Theil werden wird. Und wenn man auf Erfindungen oder Entdeckungen ausgeht, muß man sich immer einen vorläufigen Plan machen, sonst gehen die Gedanken bloß aufs Ohngefähr. Man kann sich daher unter vorläufigen Urtheilen Maximen denken zur Untersuchung einer Sache. Auch Anticipationen könnte man sie nennen, weil man sein Urtheil von einer Sache schon anticipirt, noch ehe man das bestimmende hat. Dergleichen Urtheile haben also ihren guten Nutzen und es ließen sich sogar Regeln darüber geben, wie wir vorläufig über ein Object urtheilen sollen."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Von den vorläufigen Urtheilen müssen die Vorurtheile unterschieden werden. Vorurtheile sind vorläufige Urtheile, in so fern sie als Grundsätze angenommen werden. Ein jedes Vorurtheil ist als ein Princip irriger Urtheile anzusehen und aus Vorurtheilen entspringen nicht Vorurtheile, sondern irrige Urtheile. Man muß daher die falsche Erkenntniß, die aus dem Vorurtheil entspringt, von ihrer Quelle, dem Vorurtheil selbst, unterscheiden. So ist z.B. die Bedeutung der Träume an sich selbst kein Vorurtheil, sondern ein Irrthum, der aus der angenommenen allgemeinen Regel entspringt: Was einigemal eintrifft, trifft immer ein oder ist immer für wahr zu halten. Und dieser Grundsatz, unter welchen die Bedeutung der Träume mit gehört, ist ein Vorurtheil. Zuweilen sind die Vorurtheile wahre vorläufige Urtheile, nur daß sie uns als Grundsätze oder als bestimmende Urtheile gelten, ist unrecht. Die Ursache von dieser Täuschung ist darin zu suchen, daß subjective Gründe fälschlich für objective gehalten werden, aus Mangel an Überlegung, die allem Urtheilen vorhergehen"}], "markers": [{"system": "AA", "band": "IX", "page": 75, "ref": "IX75"}, {"system": "AA", "band": "IX", "page": 76, "ref": "IX76"}], "running_header": "IX. D) Logische Vollkommenheit des Erkenntnisses der Modalität nach"}, {"page_pdf": 2773, "page_book": 77, "page_kind": "body", "sigel": "AA IX, 77", "units": [{"type": "paragraph", "text": "muß. Denn können wir auch manche Erkenntnisse, z.B. die unmittelbar gewissen Sätze, annehmen, ohne sie zu untersuchen, d.h. ohne die Bedingungen ihrer Wahrheit zu prüfen: so können und dürfen wir doch über nichts urtheilen, ohne zu überlegen, d.h. ohne ein Erkenntniß mit der Erkenntnißkraft, woraus es entspringen soll, (der Sinnlichkeit oder dem Verstande) zu vergleichen. Nehmen wir nun ohne diese Überlegung, die auch da nöthig ist, wo keine Untersuchung stattfindet, Urtheile an: so entstehen daraus Vorurtheile, oder Principien zu urtheilen aus subjectiven Ursachen, die fälschlich für objective Gründe gehalten werden. Die Hauptquellen der Vorurtheile sind: Nachahmung, Gewohnheit und Neigung. Die Nachahmung hat einen allgemeinen Einfluß auf unsere Urtheile, denn es ist ein starker Grund, das für wahr zu halten, was Andre dafür ausgegeben haben. Daher das Vorurtheil: was alle Welt thut, ist Recht. Was die Vorurtheile betrifft, die aus der Gewohnheit entsprungen sind, so können sie nur durch die Länge der Zeit ausgerottet werden, indem der Verstand, durch Gegengründe nach und nach im Urtheilen aufgehalten und verzögert, dadurch allmählig zu einer entgegengesetzten Denkart gebracht wird. Ist aber ein Vorurtheil der Gewohnheit zugleich durch Nachahmung entstanden: so ist der Mensch, der es besitzt, davon schwerlich zu heilen. Ein Vorurtheil aus Nachahmung kann man auch den Hang zum passiven Gebrauch der Vernunft nennen, oder zum Mechanism der Vernunft statt der Spontaneität derselben unter Gesetzen. Vernunft ist zwar ein thätiges Princip, das nichts von bloßer Autorität Anderer, auch nicht einmal, wenn es ihren reinen Gebrauch gilt, von der Erfahrung entlehnen soll. Aber die Trägheit sehr vieler Menschen macht, daß sie lieber in Anderer Fußtapfen treten als ihre eigenen Verstandeskräfte anstrengen. Dergleichen Menschen können immer nur Copien von Andern werden, und wären alle von der Art, so würde die Welt ewig auf einer und derselben Stelle bleiben. Es ist daher höchst nöthig und wichtig: die Jugend nicht, wie es gewöhnlich geschieht, zum bloßen Nachahmen anzuhalten. Es giebt so manche Dinge, die dazu beitragen, uns die Maxime der Nachahmung anzugewöhnen und dadurch die Vernunft zu einem fruchtbaren Boden von Vorurtheilen zu machen. Zu dergleichen Hülfsmitteln der Nachahmung gehören 1) Formeln. Dieses sind Regeln, deren Ausdruck zum Muster der Nachahmung dient. Sie sind übrigens ungemein nützlich zur Erleichterung bei verwickelten Sätzen und der erleuchtetste Kopf sucht daher dergleichen zu erfinden. 2) Sprüche, deren Ausdruck eine große Abgemessenheit eines prägnanten Sinnes hat, so daß es scheint, man könne den Sinn nicht mit weniger Worten umfassen. Dergleichen Aussprüche (_dicta_), die immer von Andern entlehnt werden müssen, denen man eine gewisse Unfehlbarkeit zutraut, dienen, um dieser Autorität willen, zur Regel und zum Gesetz. Die Aussprüche der Bibel heißen Sprüche kat) Êxocðhn. 3) Sentenzen, d.i. Sätze, die sich empfehlen und ihr Ansehen oft Jahrhunderte hindurch erhalten, als Producte einer reifen Urtheilskraft durch den Nachdruck der Gedanken, die darin liegen. 4) _Canones._ Dieses sind allgemeine Lehrsprüche, die den Wissenschaften zur Grundlage dienen und etwas Erhabenes und Durchdachtes andeuten. Man kann sie noch auf eine sententiöse Art ausdrücken, damit sie desto mehr gefallen. 5) Sprüchwörter (_proverbia_). Dieses sind populäre Regeln des gemeinen Verstandes oder Ausdrücke zu Bezeichnung der populären Urtheile desselben. Da dergleichen bloß provinziale Sätze nur dem gemeinen Pöbel zu Sentenzen und Canonen dienen: so sind sie bei Leuten von feinerer Erziehung nicht anzutreffen."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Aus den vorhin angegebenen drei allgemeinen Quellen der Vorurtheile, und insbesondere aus"}], "markers": [{"system": "AA", "band": "IX", "page": 77, "ref": "IX77"}], "running_header": "IX. D) Logische Vollkommenheit des Erkenntnisses der Modalität nach"}, {"page_pdf": 2774, "page_book": 78, "page_kind": "body", "sigel": "AA IX, 78", "units": [{"type": "paragraph", "text": "der Nachahmung, entspringen nun so manche besondre Vorurtheile, unter denen wir folgende, als die gewöhnlichsten, hier berühren wollen. 1) Vorurtheile des Ansehens. Zu diesen ist zu rechnen: _a_) das Vorurtheil des Ansehens der Person. Wenn wir in Dingen, die auf Erfahrung und Zeugnissen beruhen, unsre Erkenntniß auf das Ansehen andrer Personen bauen: so machen wir uns dadurch keiner Vorurtheile schuldig, denn in Sachen dieser Art muß, da wir nicht alles selbst erfahren und mit unserm eigenen Verstande umfassen können, das Ansehen der Person die Grundlage unsrer Urtheile sein. Wenn wir aber das Ansehen Anderer zum Grunde unsers Fürwahrhaltens in Absicht auf Vernunfterkenntnisse machen: so nehmen wir diese Erkenntnisse auf bloßes Vorurtheil an. Denn Vernunftwahrheiten gelten anonymisch; hier ist nicht die Frage: Wer hat es gesagt, sondern Was hat er gesagt? Es liegt nichts daran, ob ein Erkenntniß von edler Herkunft ist; aber dennoch ist der Hang zum Ansehen großer Männer sehr gemein, theils wegen der Eingeschränktheit eigner Einsicht, theils aus Begierde, dem nachzuahmen, was uns als groß beschrieben wird. Hierzu kommt noch: daß das Ansehen der Person dazu dient, unsrer Eitelkeit auf eine indirecte Weise zu schmeicheln. So wie nämlich die Unterthanen eines mächtigen Despoten stolz darauf sind, daß sie nur alle gleich von ihm behandelt werden, indem der Geringste mit dem Vornehmsten in so fern sich gleich dünken kann, als sie beide gegen die unumschränkte Macht ihres Beherrschers nichts sind, so beurtheilen sich auch die Verehrer eines großen Mannes als gleich, sofern die Vorzüge, die sie unter einander selbst haben mögen, gegen die Verdienste des großen Mannes betrachtet, für unbedeutend zu achten sind. Die hochgepriesenen großen Männer thun daher dem Hange zum Vorurtheile des Ansehens der Person aus mehr als einem Grunde keinen geringen Vorschub. _b_) Das Vorurtheil des Ansehens der Menge. Zu diesem Vorurtheil ist hauptsächlich der Pöbel geneigt. Denn da er die Verdienste, die Fähigkeiten und Kenntnisse der Person nicht zu beurtheilen vermag: so hält er sich lieber an das Urtheil der Menge, unter der Voraussetzung, daß das, was Alle sagen, wohl wahr sein müsse. Indessen bezieht sich dieses Vorurtheil bei ihm nur auf historische Dinge, in Religionssachen, bei denen er selbst interessirt ist, verläßt er sich auf das Urtheil der Gelehrten. Es ist überhaupt merkwürdig, daß der Unwissende ein Vorurtheil für die Gelehrsamkeit hat und der Gelehrte dagegen wiederum ein Vorurtheil für den gemeinen Verstand. Wenn dem Gelehrten, nachdem er den Kreis der Wissenschaften schon ziemlich durchgelaufen ist, alle seine Bemühungen nicht die gehörige Genugthuung verschaffen: so bekommt er zuletzt ein Mißtrauen gegen die Gelehrsamkeit, insbesondre in Ansehung solcher Speculationen, wo die Begriffe nicht sinnlich gemacht werden können, und deren Fundamente schwankend sind, wie z.B. in der Metaphysik. Da er aber doch glaubt, der Schlüssel zur Gewißheit über gewisse Gegenstände müsse irgendwo zu finden sein: so sucht er ihn nun beim gemeinen Verstande, nachdem er ihn so lange vergebens auf dem Wege des wissenschaftlichen Nachforschens gesucht hatte. Allein diese Hoffnung ist sehr trüglich, denn wenn das cultivirte Vernunftvermögen in Absicht auf die Erkenntniß gewisser Dinge nichts ausrichten kann, so wird es das uncultivirte sicherlich eben so wenig. In der Metaphysik ist die Berufung auf die Aussprüche des gemeinen Verstandes überall ganz unzulässig, weil hier kein Fall _in concreto_ kann dargestellt werden. Mit der Moral hat es aber freilich eine andre Bewandtniß. Nicht nur können in der Moral alle Regeln _in concreto_ gegeben werden, sondern die praktische Vernunft offenbart sich auch überhaupt klärer und richtiger durch das Organ des gemeinen als durch das des speculativen Verstandesgebrauchs. Daher der gemeine Verstand über Sachen der Sittlichkeit und Pflicht oft richtiger urtheilt als der speculative. _c_) Das Vorurtheil des Ansehens des Zeitalters. Hier ist das Vorurtheil des Alterthums eines der bedeutendsten. Wir haben zwar allerdings Grund vom Alterthum"}], "markers": [{"system": "AA", "band": "IX", "page": 78, "ref": "IX78"}, {"system": "AA", "band": "IX", "page": 79, "ref": "IX79"}], "running_header": "IX. D) Logische Vollkommenheit des Erkenntnisses der Modalität nach"}, {"page_pdf": 2775, "page_book": 80, "page_kind": "body", "sigel": "AA IX, 80", "units": [{"type": "paragraph", "text": "günstig zu urtheilen, aber das ist nur ein Grund zu einer gemäßigten Achtung, deren Grenzen wir nur zu oft dadurch überschreiten, daß wir die Alten zu Schatzmeistern der Erkenntnisse und Wissenschaften machen, den relativen Werth ihrer Schriften zu einem absoluten erheben und ihrer Leitung uns blindlings anvertrauen. Die Alten so übermäßig schätzen, heißt: den Verstand in seine Kinderjahre zurückführen und den Gebrauch des selbsteigenen Talentes vernachlässigen. Auch würden wir uns sehr irren, wenn wir glaubten, daß Alle aus dem Alterthum so classisch geschrieben hätten, wie die, deren Schriften bis auf uns gekommen sind. Da nämlich die Zeit alles sichtet und nur das sich erhält, was einen innern Werth hat: so dürfen wir nicht ohne Grund annehmen, daß wir nur die besten Schriften der Alten besitzen. Es giebt mehrere Ursachen, durch die das Vorurtheil des Alterthums erzeugt und unterhalten wird. Wenn etwas die Erwartung nach einer allgemeinen Regel übertrifft: so verwundert man sich anfangs darüber und diese Verwunderung geht sodann oft in Bewunderung über. Dieses ist der Fall mit den Alten, wenn man bei ihnen etwas findet, was man, in Rücksicht auf die Zeitumstände, unter welchen sie lebten, nicht suchte. Eine andre Ursache liegt in dem Umstande, daß die Kenntniß von den Alten und dem Alterthum eine Gelehrsamkeit und Belesenheit beweist, die sich immer Achtung erwirbt, so gemein und unbedeutend die Sachen an sich selbst sein mögen, die man aus dem Studium der Alten geschöpft hat. Eine dritte Ursache ist die Dankbarkeit, die wir den Alten dafür schuldig sind, daß sie uns die Bahn zu vielen Kenntnissen gebrochen. Es scheint billig zu sein, ihnen dafür eine besondre Hochschätzung zu beweisen, deren Maaß wir aber oft überschreiten. Eine vierte Ursache ist endlich zu suchen in einem gewissen Neide gegen die Zeitgenossen. Wer es mit den Neuern nicht aufnehmen kann, preist auf Unkosten derselben die Alten hoch, damit sich die Neuern nicht über ihn erheben können. Das entgegengesetzte von diesem ist das Vorurtheil der Neuigkeit. Zuweilen fiel das Ansehen des Alterthums und das Vorurtheil zu Gunsten desselben, insbesondre im Anfange dieses Jahrhunderts, als der berühmte Fontenelle sich auf die Seite der Neuern schlug. Bei Erkenntnissen, die einer Erweiterung fähig sind, ist es sehr natürlich, daß wir in die Neuern mehr Zutrauen setzen als in die Alten. Aber dieses Urtheil hat auch nur Grund als ein bloßes vorläufiges Urtheil. Machen wir es zu einem bestimmenden: so wird es Vorurtheil. 2) Vorurtheile aus Eigenliebe oder logischem Egoismus, nach welchem man die Übereinstimmung des eigenen Urtheils mit den Urtheilen Anderer für ein entbehrliches Kriterium der Wahrheit hält. Sie sind den Vorurtheilen des Ansehens entgegengesetzt, da sie sich in einer gewissen Vorliebe für das äußern, was ein Product des eigenen Verstandes ist, z.B. des eigenen Lehrgebäudes."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Ob es gut und rathsam sei, Vorurtheile stehen zu lassen oder sie wohl gar zu begünstigen? Es ist zum Erstaunen, daß in unserm Zeitalter dergleichen Fragen, besonders die wegen Begünstigung der Vorurtheile, noch können aufgegeben werden. Jemandes Vorurtheile begünstigen, heißt eben so viel als Jemanden in guter Absicht betrügen. Vorurtheile unangetastet lassen, ginge noch an; denn wer kann sich damit beschäftigen, eines Jeden Vorurtheile aufzudecken und wegzuschaffen. Ob es aber nicht rathsam sein sollte, an ihrer Ausrottung mit allen Kräften zu arbeiten, das ist doch eine andre Frage. Alte und eingewurzelte Vorurtheile sind freilich schwer zu bekämpfen, weil sie sich selbst verantworten und gleichsam ihre eigenen Richter sind. Auch sucht man das Stehenlassen der Vorurtheile damit zu entschuldigen, daß aus ihrer Ausrottung Nachtheile entstehen würden. Aber man lasse diese Nachtheile nur immer zu, in der Folge werden sie desto mehr Gutes bringen."}], "markers": [{"system": "AA", "band": "IX", "page": 80, "ref": "IX80"}, {"system": "AA", "band": "IX", "page": 81, "ref": "IX81"}], "running_header": "IX. D) Logische Vollkommenheit des Erkenntnisses der Modalität nach"}, {"page_pdf": 2776, "page_book": 80, "page_kind": "body", "sigel": "AA IX, 80", "units": [{"type": "paragraph", "text": "Anmerkungen: *[1] Das Glauben ist kein besonderer Erkenntnißquell. Es ist eine Art des mit Bewußtsein unvollständigen Fürwahrhaltens und unterscheidet sich, wenn es, als auf besondre Art Objecte (die nur für’s Glauben gehören) restringirt, betrachtet wird, vom Meinen nicht durch den Grad, sondern durch das Verhältniß, was es als Erkenntniß zum Handeln hat. So bedarf z.B. der Kaufmann, um einen Handel einzuschlagen, daß er nicht bloß meine, es werde dabei was zu gewinnen sein, sondern //IX68// daß er’s glaube, d.i. daß seine Meinung zur Unternehmung auf’s Ungewisse zureichend sei. Nun haben wir theoretische Erkenntnisse (vom Sinnlichen), darin wir es zur Gewißheit bringen können und in Ansehung alles dessen, was wir menschliches Erkenntniß nennen können, muß das Letztere möglich sein. Eben solche gewisse Erkenntnisse und zwar gänzlich _a priori_ haben wir in praktischen Gesetzen, allein diese gründen sich auf ein übersinnliches Princip (der Freiheit) und zwar in uns selbst, als ein Princip der praktischen Vernunft. Aber diese praktische Vernunft ist eine Causalität in Ansehung eines gleichfalls übersinnlichen Objects, des höchsten Guts, welches in der Sinnenwelt durch unser Vermögen nicht möglich ist. Gleichwohl muß die Natur als Object unsrer theoretischen Vernunft dazu zusammenstimmen, denn es soll in der Sinnenwelt die Folge oder Wirkung von dieser Idee angetroffen werden. Wir sollen also handeln, um diesen Zweck wirklich zu machen. Wir finden in der Sinnenwelt auch Spuren einer Kunstweisheit, und nun glauben wir: die Weltursache wirke auch mit moralischer Weisheit zum höchsten Gut. Dieses ist ein Fürwahrhalten, welches genug ist zum Handeln, d.i. ein Glaube. Nun bedürfen wir diesen nicht zum Handeln nach moralischen Gesetzen, denn die werden durch praktische Vernunft allein gegeben, aber wir bedürfen der Annahme einer höchsten Weisheit zum Object unsers moralischen Willens, worauf wir außer der bloßen Rechtmäßigkeit unserer Handlungen nicht umhin können, unsre Zwecke zu richten. Obgleich dieses objectiv keine nothwendige Beziehung unsrer Willkür wäre: so ist das höchste Gut doch subjectiv nothwendig das Object eines guten (selbst menschlichen) Willens, und der Glaube an die Erreichbarkeit desselben wird dazu nothwendig vorausgesetzt. Zwischen der Erwerbung einer Erkenntniß durch Erfahrung (_a posteriori_) und durch die Vernunft (_a priori_) giebt es kein Mittleres. Aber zwischen der Erkenntniß eines Objects und der bloßen Voraussetzung der Möglichkeit desselben giebt es ein Mittleres, nämlich einen empirischen oder einen Vernunftgrund die letztere anzunehmen in Beziehung auf eine nothwendige Erweiterung des Feldes möglicher Objecte über diejenige, deren Erkenntniß uns möglich ist. Diese Nothwendigkeit findet nur in Ansehung dessen statt, da das Object als praktisch und durch Vernunft praktisch nothwendig erkannt wird, denn zum Behuf der bloßen Erweiterung der theoretischen Erkenntniß etwas anzunehmen, ist jederzeit zufällig. Diese praktisch nothwendige Voraussetzung eines Objects ist die der Möglichkeit des höchsten Guts als Objects der Willkür, mithin auch der Bedingung dieser Möglichkeit (Gott, Freiheit und Unsterblichkeit). Dieses ist eine subjective Nothwendigkeit, die Realität des Objects um der nothwendigen Willensbestimmung halber anzunehmen. Dies ist der _casus _ _extraordinarius,_ ohne welchen die praktische Vernunft sich nicht in Ansehung ihres nothwendigen Zwecks erhalten kann, und es kommt ihr hier _favor necessitatis_ zu statten in ihrem eigenen Urtheil. Sie kann kein Object logisch erwerben, sondern sich nur //IX69// allein dem widersetzen, was sie im Gebrauch dieser Idee, die ihr praktisch angehört, hindert. Dieser Glaube ist die Nothwendigkeit, die objective Realität eines Begriffs (vom höchsten Gut) d.i. die Möglichkeit seines Gegenstandes, als _a priori_ nothwendigen Objects der Willkür anzunehmen. Wenn wir bloß auf Handlungen sehen, so haben wir diesen Glauben nicht nöthig. Wollen wir aber durch Handlungen uns zum Besitz des dadurch möglichen Zwecks erweitern: so müssen wir annehmen, daß dieser durchaus möglich sei. Ich kann also nur sagen: Ich sehe mich durch meinen Zweck nach Gesetzen der Freiheit genöthigt, ein höchstes Gut in der Welt als möglich anzunehmen, aber ich kann keinen Andern durch Gründe nöthigen (der Glaube ist frei). Der Vernunftglaube kann also nie auf’s theoretische Erkenntniß gehen, denn da ist das objectiv unzureichende Fürwahrhalten bloß Meinung. Er ist bloß eine Voraussetzung der Vernunft in subjectiver, aber absolutnothwendiger praktischer Absicht. Die Gesinnung nach moralischen Gesetzen führt auf ein Object der durch reine Vernunft bestimmbaren Willkür. Das Annehmen der Thunlichkeit dieses Objects und also auch der Wirklichkeit der Ursache dazu ist ein moralischer Glaube oder ein freies und in moralischer Absicht der Vollendung seiner Zwecke nothwendiges Fürwahrhalten."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "_Fides_ ist eigentlich Treue im _pacto_ oder subjectives Zutrauen zu einander, daß einer dem Andern sein"}], "running_header": "IX. D) Logische Vollkommenheit des Erkenntnisses der Modalität nach"}, {"page_pdf": 2777, "page_book": 80, "page_kind": "body", "sigel": "AA IX, 80", "units": [{"type": "paragraph", "text": "Versprechen halten werde, Treue und Glauben. Das erste, wenn das _pactum_ gemacht ist, das zweite, wenn man es schließen soll. Nach der Analogie ist die praktische Vernunft gleichsam der Promittent, der Mensch der Promissarius, das erwartete Gute aus der That das Promissum. *[2] Diese praktische Überzeugung ist also der moralische Vernunftglaube , der allein im eigentlichsten Verstande ein Glaube genannt und als solcher dem Wissen und aller theoretischen oder logischen Überzeugung überhaupt entgegengesetzt werden muß, weil er nie zum Wissen sich erheben kann. Der sogenannte historische Glaube dagegen darf, wie schon bemerkt, nicht von dem Wissen unterschieden werden, da er, als eine Art des theoretischen oder logischen Fürwahrhaltens, selbst ein Wissen sein kann. Wir können mit derselben Gewißheit eine empirische Wahrheit auf das Zeugniß Anderer annehmen, als wenn wir durch Facta der eigenen Erfahrung dazu gelangt wären. Bei der erstern Art des empirischen Wissens ist etwas Trügliches, aber auch bei der letztern. Das historische oder mittelbare empirische Wissen beruht auf der Zuverlässigkeit der Zeugnisse. Zu den Erfordernissen eines unverwerflichen Zeugen gehört: Authenticität (Tüchtigkeit) und Integrität."}], "running_header": "IX. D) Logische Vollkommenheit des Erkenntnisses der Modalität nach"}, {"page_pdf": 2778, "page_book": 81, "page_kind": "body", "sigel": "AA IX, 81", "units": [{"type": "heading", "text": "[Einleitung.]", "level": 2}, {"type": "paragraph", "text": "X. Wahrscheinlichkeit. – Erklärung des Wahrscheinlichen. – Unterschied der Wahrscheinlichkeit von der Scheinbarkeit. – Mathematische und philosophische Wahrscheinlichkeit. – Zweifel – subjectiver und objectiver. – Skeptische, dogmatische und kritische Denkart oder Methode des Philosophirens. – Hypothesen. Zur Lehre von der Gewißheit unsers Erkenntnisses gehört auch die Lehre von der Erkenntniß des Wahrscheinlichen, das als eine Annäherung zur Gewißheit anzusehen ist. Unter Wahrscheinlichkeit ist ein Fürwahrhalten aus unzureichenden Gründen zu verstehen, die aber zu den zureichenden ein größeres Verhältniß haben, als die Gründe des Gegentheils. Durch diese Erklärung unterscheiden wir die Wahrscheinlichkeit (_probabilitas_) von der bloßen Scheinbarkeit (_verisimilitudo_), einem Fürwahrhalten aus unzureichenden Gründen, in so fern dieselben größer sind als die Gründe des Gegentheils. Der Grund des Fürwahrhaltens kann nämlich entweder objectiv oder subjectiv größer sein als der des Gegentheils. Welches von beiden er sei, das kann man nur dadurch ausfindig machen, daß man die Gründe des Fürwahrhaltens mit den zureichenden vergleicht; denn alsdenn sind die Gründe des Fürwahrhaltens größer, als die Gründe des Gegentheils sein können. Bei der Wahrscheinlichkeit ist also der Grund des Fürwahrhaltens objectiv gültig, bei der bloßen Scheinbarkeit dagegen nur subjectiv gültig. Die Scheinbarkeit ist bloß Größe der Überredung, die Wahrscheinlichkeit ist eine Annäherung zur Gewißheit. Bei der Wahrscheinlichkeit muß immer ein Maßstab da sein, wonach ich sie schätzen kann. Dieser Maßstab ist die Gewißheit. Denn indem ich die unzureichenden Gründe mit den zureichenden vergleichen soll, muß ich wissen, wie viel zur Gewißheit gehört. Ein solcher Maßstab fällt aber bei der bloßen Scheinbarkeit weg, da ich hier die unzureichenden Gründe nicht mit den zureichenden, sondern nur mit den Gründen des Gegentheils vergleiche. Die Momente der Wahrscheinlichkeit können entweder gleichartig oder ungleichartig sein. Sind sie gleichartig, wie im mathematischen Erkenntnisse: so müssen sie numerirt werden; sind sie ungleichartig, wie im philosophischen Erkenntnisse: so müssen sie ponderirt, d.i. nach der Wirkung geschätzt werden; diese aber nach der Überwältigung der Hindernisse im Gemüthe. Letztere geben kein Verhältniß zur Gewißheit, sondern nur einer Scheinbarkeit zur andern. Hieraus folgt: daß nur der Mathematiker das Verhältniß unzureichender Gründe zum zureichenden Grunde bestimmen kann, der Philosoph muß sich mit der Scheinbarkeit, einem bloß subjectiv und praktisch hinreichenden Fürwahrhalten begnügen. Denn im philosophischen Erkenntnisse läßt sich wegen der Ungleichartigkeit der Gründe die Wahrscheinlichkeit nicht schätzen; die Gewichte sind hier, so zu sagen, nicht alle gestempelt. Von der mathematischen Wahrscheinlichkeit kann man daher auch eigentlich nur sagen: daß sie mehr als die Hälfte der Gewißheit sei. Man hat viel von einer Logik der Wahrscheinlichkeit (_logica probabilium_) geredet. Allein diese ist nicht möglich; denn wenn sich das Verhältniß der unzureichenden Gründe zum zureichenden nicht mathematisch erwägen läßt: so helfen alle Regeln nichts. Auch kann man überall keine allgemeinen Regeln der Wahrscheinlichkeit geben, außer daß der Irrthum nicht auf einerlei Seite treffen werde, sondern ein Grund der Einstimmung sein müsse im Object; ingleichen: daß, wenn von zwei entgegengesetzten Seiten in gleicher Menge und in gleichem Grade geirrt wird, im Mittel die Wahrheit sei."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Zweifel ist ein Gegengrund oder ein bloßes Hinderniß des Fürwahrhaltens, das entweder"}], "markers": [{"system": "AA", "band": "IX", "page": 81, "ref": "IX81"}, {"system": "AA", "band": "IX", "page": 82, "ref": "IX82"}, {"system": "AA", "band": "IX", "page": 83, "ref": "IX83"}], "running_header": "X. Wahrscheinlichkeit"}, {"page_pdf": 2779, "page_book": 84, "page_kind": "body", "sigel": "AA IX, 84", "units": [{"type": "paragraph", "text": "subjectiv oder objectiv betrachtet werden kann. Subjectiv nämlich wird Zweifel bisweilen genommen als ein Zustand eines unentschlossenen Gemüths, und objectiv als die Erkenntniß der Unzulänglichkeit der Gründe zum Fürwahrhalten. In der letztern Rücksicht heißt er ein Einwurf, das ist: ein objectiver Grund, ein für wahr gehaltenes Erkenntniß für falsch zu halten. Ein bloß subjectiv gültiger Gegengrund des Fürwahrhaltens ist ein Scrupel. Beim Scrupel weiß man nicht: ob das Hinderniß des Fürwahrhaltens objectiv oder nur subjectiv, z.B. nur in der Neigung, der Gewohnheit u.dgl.m. gegründet sei. Man zweifelt, ohne sich über den Grund des Zweifelns deutlich und bestimmt erklären und ohne einsehen zu können: ob dieser Grund im Object selbst oder nur im Subjecte liege. Sollen nun solche Scrupel hinweggenommen werden können: so müssen sie zur Deutlichkeit und Bestimmtheit eines Einwurfs erhoben werden. Denn durch Einwürfe wird die Gewißheit zur Deutlichkeit und Vollständigkeit gebracht, und keiner kann von einer Sache gewiß sein, wenn nicht Gegengründe rege gemacht worden, wodurch bestimmt werden kann: wie weit man noch von der Gewißheit entfernt, oder wie nahe man noch derselben sei. Auch ist es nicht genug: daß ein jeder Zweifel bloß beantwortet werde, man muß ihn auch auflösen, das heißt: begreiflich machen, wie der Scrupel entstanden ist. Geschieht dieses nicht: so wird der Zweifel nur abgewiesen, aber nicht aufgehoben, der Same des Zweifelns bleibt dann immer noch übrig. In vielen Fällen können wir freilich nicht wissen: ob das Hinderniß des Fürwahrhaltens in uns nur subjective oder objective Gründe habe und also den Scrupel nicht heben durch Aufdeckung des Scheines, da wir unsere Erkenntnisse nicht immer mit dem Object, sondern oft nur unter einander selbst vergleichen können. Es ist daher Bescheidenheit, seine Einwürfe nur als Zweifel vorzutragen."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Es giebt einen Grundsatz des Zweifelns, der in der Maxime besteht, Erkenntnisse in der Absicht zu behandeln, daß man sie ungewiß macht und die Unmöglichkeit zeigt, zur Gewißheit zu gelangen. Diese Methode des Philosophirens ist die skeptische Denkart oder der Skepticismus. Sie ist der dogmatischen Denkart oder dem Dogmatismus entgegengesetzt, der ein blindes Vertrauen ist auf das Vermögen der Vernunft, ohne Kritik sich _a priori_ durch bloße Begriffe zu erweitern, bloß um des scheinbaren Gelingens willen. Beide Methoden sind, wenn sie allgemein werden, fehlerhaft. Denn es giebt viele Kenntnisse, in Ansehung deren wir nicht dogmatisch verfahren können, und von der andern Seite vertilgt der Skepticism, indem er auf alle behauptende Erkenntniß Verzicht thut, alle unsre Bemühungen zum Besitz einer Erkenntniß des Gewissen zu gelangen. So schädlich nun aber auch dieser Skepticism ist: so nützlich und zweckmäßig ist doch die skeptische Methode, wofern man darunter nichts weiter als nur die Art versteht, etwas als ungewiß zu behandeln und auf die höchste Ungewißheit zu bringen, in der Hoffnung, der Wahrheit auf diesem Wege auf die Spur zu kommen. Diese Methode ist also eigentlich eine bloße Suspension des Urtheilens. Sie ist dem kritischen Verfahren sehr nützlich, worunter diejenige Methode des Philosophirens zu verstehen ist, nach welcher man die Quellen seiner Behauptungen oder Einwürfe untersucht, und die Gründe, worauf dieselben beruhen; eine Methode, welche Hoffnung giebt, zur Gewißheit zu gelangen. In der Mathematik und Physik findet der Skepticism nicht statt. Nur diejenige Erkenntniß hat ihn veranlassen können, die weder mathematisch noch empirisch ist: die rein philosophische. Der absolute Skepticism giebt alles für Schein aus. Er unterscheidet also Schein von Wahrheit und muß mithin doch ein Merkmal des Unterschiedes haben, folglich ein Erkenntniß der Wahrheit voraussetzen, wodurch er sich selbst widerspricht."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Wir bemerkten oben von der Wahrscheinlichkeit, daß sie eine bloße Annäherung zur"}], "markers": [{"system": "AA", "band": "IX", "page": 84, "ref": "IX84"}], "running_header": "X. Wahrscheinlichkeit"}, {"page_pdf": 2780, "page_book": 85, "page_kind": "body", "sigel": "AA IX, 85", "units": [{"type": "paragraph", "text": "Gewißheit sei. Dieses ist nun insbesondre auch der Fall mit den Hypothesen, durch die wir nie zu einer apodiktischen Gewißheit, sondern immer nur zu einem bald größern, bald geringern Grade der Wahrscheinlichkeit in unserm Erkenntnisse gelangen können. Eine Hypothese ist ein Fürwahrhalten des Urtheils von der Wahrheit eines Grundes um der Zulänglichkeit der Folgen willen, oder kürzer; das Fürwahrhalten einer Voraussetzung als Grundes. Alles Fürwahrhalten in Hypothesen gründet sich demnach darauf, daß die Voraussetzung, als Grund, hinreichend ist, andre Erkenntnisse, als Folgen, daraus zu erklären. Denn wir schließen hier von der Wahrheit der Folge auf die Wahrheit des Grundes. Da aber diese Schlußart, wie oben bereits bemerkt worden, nur dann ein hinreichendes Kriterium der Wahrheit giebt und zu einer apodiktischen Gewißheit führen kann, wenn alle möglichen Folgen eines angenommenen Grundes wahr sind: so erhellt hieraus, daß, da wir nie alle möglichen Folgen bestimmen können, Hypothesen immer Hypothesen bleiben, das heißt: Voraussetzungen, zu deren völliger Gewißheit wir nie gelangen können. Demohngeachtet kann die Wahrscheinlichkeit einer Hypothese doch wachsen und zu einem Analogon der Gewißheit sich erheben, wenn nämlich alle Folgen, die uns bis jetzt vorgekommen sind, aus dem vorausgesetzten Grunde sich erklären lassen. Denn in einem solchen Falle ist kein Grund da, warum wir nicht annehmen sollten, daß sich daraus alle möglichen Folgen werden erklären lassen. Wir ergeben uns also in diesem Falle der Hypothese, als wäre sie völlig gewiß, obgleich sie es nur durch Induction ist. Und etwas muß doch auch in jeder Hypothese apodiktisch gewiß sein, nämlich 1) die Möglichkeit der Voraussetzung selbst. Wenn wir z.B. zu Erklärung der Erdbeben und Vulcane ein unterirdisches Feuer annehmen: so muß ein solches Feuer doch möglich sein, wenn auch eben nicht als ein flammender, doch als ein hitziger Körper. Aber zum Behuf gewisser andrer Erscheinungen die Erde zu einem Thiere zu machen, in welchem die Circulation der inneren Säfte die Wärme bewirke, heißt eine bloße Erdichtung und keine Hypothese aufstellen. Denn Wirklichkeiten lassen sich wohl erdichten, nicht aber Möglichkeiten; diese müssen gewiß sein. 2) Die Consequenz.Aus dem angenommenen Grunde müssen die Folgen richtig herfließen; sonst wird aus der Hypothese eine bloße Chimäre. 3) Die Einheit. Es ist ein wesentliches Erforderniß einer Hypothese, daß sie nur Eine sei und keiner Hülfshypothesen zu ihrer Unterstützung bedürfe. Müssen wir bei einer Hypothese schon mehrere andre zu Hülfe nehmen: so verliert sie dadurch sehr viel von ihrer Wahrscheinlichkeit. Denn je mehr Folgen aus einer Hypothese sich ableiten lassen, um so wahrscheinlicher ist sie, je weniger, desto unwahrscheinlicher. So reichte z.B. die Hypothese des Tycho _de_ Brahe zu Erklärung vieler Erscheinungen nicht zu; er nahm daher zur Ergänzung mehrere neue Hypothesen an. Hier ist nun schon zu errathen, daß die angenommene Hypothese der ächte Grund nicht sein könne. Dagegen ist das Copernikanische System eine Hypothese, aus der sich Alles, was daraus erklärt werden soll, soweit es uns bis jetzt vorgekommen ist, erklären läßt. Wir brauchen hier keine Hülfshypothesen (_hypotheses subsidiarias_). Es giebt Wissenschaften, die keine Hypothesen erlauben, wie z.B. die Mathematik und Metaphysik. Aber in der Naturlehre sind sie nützlich und unentbehrlich."}], "markers": [{"system": "AA", "band": "IX", "page": 85, "ref": "IX85"}, {"system": "AA", "band": "IX", "page": 86, "ref": "IX86"}], "running_header": "X. Wahrscheinlichkeit"}, {"page_pdf": 2781, "page_book": 86, "page_kind": "body", "sigel": "AA IX, 86", "units": [{"type": "heading", "text": "[Einleitung.]", "level": 2}, {"type": "paragraph", "text": "Anhang. Von dem Unterschiede des theoretischen und des praktischen Erkenntnisses. Ein Erkenntniß wird praktisch genannt im Gegensatze des theoretischen, aber auch im Gegensatze des speculativen Erkenntnisses. Praktische Erkenntnisse sind nämlich entweder: 1) Imperative und in so fern den theoretischen Erkenntnissen entgegengesetzt; oder sie enthalten 2) die Gründe zu möglichen Imperativen und werden in so fern den speculativen Erkenntnissen entgegengesetzt. Unter Imperativ überhaupt ist jeder Satz zu verstehen, der eine mögliche freie Handlung aussagt, wodurch ein gewisser Zweck wirklich gemacht werden soll. Eine jede Erkenntniß also, die Imperative enthält, ist praktisch, und zwar im Gegensatze des theoretischen Erkenntnisses praktisch zu nennen. Denn theoretische Erkenntnisse sind solche, die da aussagen: nicht, was sein soll, sondern was ist, also kein Handeln, sondern ein Sein zu ihrem Object haben. Setzen wir dagegen praktische Erkenntnisse den speculativen entgegen: so können sie auch theoretisch sein, wofern aus ihnen nur Imperative können abgeleitet werden. Sie sind alsdann, in dieser Rücksicht betrachtet, dem Gehalte nach (_in potentia_) oder objectiv praktisch. Unter speculativen Erkenntnissen nämlich verstehen wir solche, aus denen keine Regeln des Verhaltens können hergeleitet werden, oder die keine Gründe zu möglichen Imperativen enthalten. Solcher bloß speculativen Sätze giebt es z.B. in der Theologie die Menge. Dergleichen speculative Erkenntnisse sind also immer theoretisch, aber nicht umgekehrt ist jede theoretische Erkenntniß speculativ; sie kann, in einer andern Rücksicht betrachtet, auch zugleich praktisch sein. Alles läuft zuletzt auf das Praktische hinaus, und in dieser Tendenz alles Theoretischen und aller Speculation in Ansehung ihres Gebrauchs besteht der praktische Werth unsers Erkenntnisses. Dieser Werth ist aber nur alsdann ein unbedingter, wenn der Zweck, worauf der praktische Gebrauch des Erkenntnisses gerichtet ist, ein unbedingter Zweck ist. Der einige, unbedingte und letzte Zweck (Endzweck), worauf aller praktische Gebrauch unsers Erkenntnisses zuletzt sich beziehen muß, ist die Sittlichkeit, die wir um deswillen auch das schlechthin oder absolut Praktische nennen. Und derjenige Theil der Philosophie, der die Moralität zum Gegenstande hat, würde demnach praktische Philosophie kat) Êxocðhn heißen müssen; obgleich jede andre philosophische Wissenschaft immer auch ihren praktischen Theil haben, d.h. von den aufgestellten Theorien eine Anweisung zum praktischen Gebrauche derselben für die Realisirung gewisser Zwecke enthalten kann."}, {"type": "paragraph", "text": "——————"}], "markers": [{"system": "AA", "band": "IX", "page": 86, "ref": "IX86"}, {"system": "AA", "band": "IX", "page": 87, "ref": "IX87"}], "running_header": "Anhang. Von dem Unterschiede des theoretischen und des praktischen Erkenntnisses"}, {"page_pdf": 2782, "page_book": 89, "page_kind": "title_page", "sigel": "AA IX, 89", "units": [{"type": "paragraph", "text": "I. Allgemeine Elementarlehre."}], "markers": [{"system": "AA", "band": "IX", "page": 89, "ref": "IX89"}]}, {"page_pdf": 2783, "page_book": 91, "page_kind": "body", "sigel": "AA IX, 91", "units": [{"type": "paragraph", "text": "Erster Abschnitt. Von den Begriffen. [§§ 1-16] §. 1. Begriff überhaupt und dessen Unterschied von der Anschauung. Alle Erkenntnisse, das heißt: alle mit Bewußtsein auf ein Object bezogene Vorstellungen sind entweder Anschauungen oder Begriffe. Die Anschauung ist eine einzelne Vorstellung (_repraesentatio singularis_), der Begriff eine allgemeine (_repraesentatio per notas communes_) oder reflectirte Vorstellung (_repraesentatio discursiva_). Die Erkenntniß durch Begriffe heißt das Denken (_cognitio discursiva_)."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. Der Begriff ist der Anschauung entgegengesetzt, denn er ist eine allgemeine Vorstellung oder eine Vorstellung dessen, was mehreren Objecten gemein ist, also eine Vorstellung, sofern sie in verschiedenen enthalten sein kann. 2. Es ist eine bloße Tautologie, von allgemeinen oder gemeinsamen Begriffen zu reden, – ein Fehler, der sich auf eine unrichtige Eintheilung der Begriffe in allgemeine, besondre und einzelne gründet. Nicht die Begriffe selbst, nur ihr Gebrauch kann so eingetheilt werden."}, {"type": "paragraph", "text": "§. 2. Materie und Form der Begriffe. An jedem Begriffe ist Materie und Form zu unterscheiden. Die Materie der Begriffe ist der Gegenstand, die Form derselben die Allgemeinheit. §. 3. Empirischer und reiner Begriff. Der Begriff ist entweder ein empirischer oder ein reiner Begriff (_vel empiricus vel_ _intellectualis_). Ein reiner Begriff ist ein solcher, der nicht von der Erfahrung abgezogen ist, sondern auch dem Inhalte nach aus dem Verstande entspringt. Die Idee ist ein Vernunftbegriff, deren Gegenstand gar nicht in der Erfahrung kann angetroffen werden."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. Der empirische Begriff entspringt aus den Sinnen durch Vergleichung der Gegenstände der Erfahrung und erhält durch den Verstand bloß die Form der Allgemeinheit. Die Realität dieser Begriffe beruht auf der wirklichen Erfahrung, woraus sie, ihrem Inhalte nach, geschöpft sind. Ob es aber reine Verstandesbegriffe (_conceptus puri_) gebe, die, als solche, unabhängig von aller Erfahrung lediglich aus dem Verstande entspringen, muß die Metaphysik untersuchen. 2. Die Vernunftbegriffe oder Ideen können gar nicht auf wirkliche Gegenstände führen, weil diese alle in einer möglichen Erfahrung enthalten sein müssen. Aber sie dienen doch dazu, durch Vernunft in Ansehung der Erfahrung und des Gebrauchs der Regeln derselben in der größten Vollkommenheit, den Verstand zu leiten oder auch zu zeigen, daß nicht alle mögliche Dinge Gegenstände der Erfahrung seien, und daß die Principien der Möglichkeit der letztern nicht von Dingen an sich selbst, auch nicht von Objecten der Erfahrung als Dingen an sich selbst gelten. Die Idee enthält das Urbild des Gebrauchs des Verstandes, z.B. die Idee vom Weltganzen, welche nothwendig sein muß, nicht als constitutives Princip zum empirischen Verstandesgebrauche, sondern nur als regulatives Princip zum Behuf des durchgängigen Zusammenhanges unsers empirischen Verstandesgebrauchs. Sie ist also als ein nothwendiger Grundbegriff anzusehen, um die Verstandeshandlungen der Subordination entweder objectiv zu vollenden oder als unbegrenzt anzusehen. – Auch läßt sich die Idee nicht durch Zusammensetzung erhalten, denn das Ganze ist eher als der Theil. Indessen giebt es doch Ideen, zu denen eine Annäherung stattfindet. Dieses ist der Fall mit den mathematischen oder den Ideen der"}], "markers": [{"system": "AA", "band": "IX", "page": 91, "ref": "IX91"}, {"system": "AA", "band": "IX", "page": 92, "ref": "IX92"}], "running_header": "1. Abschnitt. Von den Begriffen [§§ 1 - 16]"}, {"page_pdf": 2784, "page_book": 93, "page_kind": "body", "sigel": "AA IX, 93", "units": [{"type": "paragraph", "text": "mathematischen Erzeugung eines Ganzen, die sich wesentlich von den dynamischen unterscheiden, welche allen concreten Begriffen gänzlich heterogen sind, weil das Ganze nicht der Größe (wie bei den mathematischen), sondern der Art nach von den concreten Begriffen verschieden ist. Man kann keiner theoretischen Idee objective Realität verschaffen oder dieselbe beweisen, als nur der Idee von der Freiheit, und zwar, weil diese die Bedingung des moralischen Gesetzes ist, dessen Realität ein Axiom ist. Die Realität der Idee von Gott kann nur durch diese und also nur in praktischer Absicht, d.i. so zu handeln, als ob ein Gott sei, also nur für diese Absicht bewiesen werden. In allen Wissenschaften, vornehmlich denen der Vernunft, ist die Idee der Wissenschaft der allgemeine Abriß oder Umriß derselben, also der Umfang aller Kenntnisse, die zu ihr gehören. Eine solche Idee des Ganzen – das Erste, worauf man bei einer Wissenschaft zu sehen und was man zu suchen hat, ist architektonisch, wie z.B. die Idee der Rechtswissenschaft. Die Idee der Menschheit, die Idee einer vollkommenen Republik, eines glückseligen Lebens u.dgl.m. fehlt den meisten Menschen. Viele Menschen haben keine Idee von dem, was sie wollen, daher verfahren sie nach Instinct und Autorität."}, {"type": "paragraph", "text": "§. 4. Gegebene (_a priori_ oder _a posteriori_) und gemachte Begriffe. Alle Begriffe sind der Materie nach entweder gegebene (_conceptus dati_) oder gemachte Begriffe (_conceptus factitii_). Die erstern sind entweder _a priori_ oder _a posteriori_ gegeben. Alle empirisch oder _a posteriori_ gegebenen Begriffe heißen Erfahrungsbegriffe, _a _ _priori_ gegebene, Notionen."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Die Form eines Begriffs als einer discursiven Vorstellung ist jederzeit gemacht."}, {"type": "paragraph", "text": "§. 5. Logischer Ursprung der Begriffe. Der Ursprung der Begriffe der bloßen Form nach beruht auf Reflexion und auf der Abstraction von dem Unterschiede der Dinge, die durch eine gewisse Vorstellung bezeichnet sind. Und es entsteht also hier die Frage: Welche Handlungen des Verstandes einen Begriff ausmachen oder – welches dasselbe ist – zu Erzeugung eines Begriffes aus gegebenen Vorstellungen gehören?"}, {"type": "paragraph", "text": "—————— Anmerkung 1. Da die allgemeine Logik von allem Inhalte des Erkenntnisses durch Begriffe, oder von aller Materie des Denkens abstrahirt: so kann sie den Begriff nur in Rücksicht seiner Form, d.h. nur subjectivisch erwägen; nicht wie er durch ein Merkmal ein Object bestimmt, sondern nur, wie er auf mehrere Objecte kann bezogen werden. Die allgemeine Logik hat also nicht die Quelle der Begriffe zu untersuchen; nicht wie Begriffe als Vorstellungen entspringen, sondern lediglich, wie gegebene Vorstellungen im Denken zu Begriffen werden; diese Begriffe mögen übrigens etwas enthalten, was von der Erfahrung hergenommen ist, oder auch etwas Erdichtetes, oder von der Natur des Verstandes Entlehntes. – Dieser logische Ursprung der Begriffe – der Ursprung ihrer bloßen Form nach – besteht in der Reflexion, wodurch eine mehreren Objecten gemeine Vorstellung (_conceptus _ _communis_) entsteht, als diejenige Form, die zur Urtheilskraft erfordert wird. Also wird in der Logik bloß der Unterschied der Reflexion an den Begriffen betrachtet. 2. Der Ursprung der Begriffe in Ansehung ihrer Materie, nach welcher ein Begriff entweder empirisch oder willkürlich oder intellectuell ist, wird in der Metaphysik erwogen."}, {"type": "paragraph", "text": "§. 6. Logische Actus der Comparation, Reflexion und Abstraction."}], "markers": [{"system": "AA", "band": "IX", "page": 93, "ref": "IX93"}, {"system": "AA", "band": "IX", "page": 94, "ref": "IX94"}], "running_header": "1. Abschnitt. Von den Begriffen [§§ 1 - 16]"}, {"page_pdf": 2785, "page_book": 95, "page_kind": "body", "sigel": "AA IX, 95", "units": [{"type": "paragraph", "text": "Die logischen Verstandes-Actus, wodurch Begriffe ihrer Form nach erzeugt werden, sind: 1) die Comparation, d.i. die Vergleichung der Vorstellungen unter einander im Verhältnisse zur Einheit des Bewußtseins; 2) die Reflexion, d.i. die Überlegung, wie verschiedene Vorstellungen in Einem Bewußtsein begriffen sein können; und endlich 3) Die Abstraction oder die Absonderung alles Übrigen, worin die gegebenen Vorstellungen sich unterscheiden."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. Um aus Vorstellungen Begriffe zu machen, muß man also compariren, reflectiren und abstrahiren können, denn diese drei logischen Operationen des Verstandes sind die wesentlichen und allgemeinen Bedingungen zu Erzeugung eines jeden Begriffs überhaupt. Ich sehe z.B. eine Fichte, eine Weide und eine Linde. Indem ich diese Gegenstände zuvörderst unter einander vergleiche, bemerke ich, daß sie von einander verschieden sind in Ansehung des Stammes, der Äste, der Blätter u.dgl.m.; nun reflectire ich aber hiernächst nur auf das, was sie unter sich gemein haben, den Stamm, die Äste, die Blätter selbst und abstrahire von der Größe, der Figur derselben u.s.w.; so bekomme ich einen Begriff vom Baume. 2. Man braucht in der Logik den Ausdruck Abstraction nicht immer richtig. Wir müssen nicht sagen: Etwas abstrahiren (_abstrahere aliquid_), sondern von Etwas abstrahiren (_abstrahere ab aliquo_). Wenn ich z.B. beim Scharlach-Tuche nur die rothe Farbe denke: so abstrahire ich vom Tuche, abstrahire ich auch von diesem und denke mir den Scharlach als einen materiellen Stoff überhaupt: so abstrahire ich von noch mehreren Bestimmungen, und mein Begriff ist dadurch noch abstracter geworden. Denn je mehrere Unterschiede der Dinge aus einem Begriffe weggelassen sind oder, von je mehreren Bestimmungen in demselben abstrahirt worden: desto abstracter ist der Begriff. Abstracte Begriffe sollte man daher eigentlich abstrahirende (_conceptus abstrahentes_) nennen, d.h. solche, in denen mehrere Abstractionen vorkommen. So ist z.B. der Begriff Körper eigentlich kein abstracter Begriff, denn vom Körper selbst kann ich ja nicht abstrahiren, ich würde sonst nicht den Begriff von ihm haben. Aber wohl muß ich von der Größe, der Farbe, der Härte oder Flüssigkeit, kurz: von allen speciellen Bestimmungen besondrer Körper abstrahiren. Der abstracteste Begriff ist der, welcher mit keinem von ihm verschiedenen etwas gemein hat. Dieses ist der Begriff von Etwas, denn das von ihm Verschiedene ist Nichts, und hat also mit dem Etwas nichts gemein. 3. Die Abstraction ist nur die negative Bedingung, unter welcher allgemeingültige Vorstellungen erzeugt werden können, die positive ist die Comparation und Reflexion. Denn durchs Abstrahiren wird kein Begriff, die Abstraction vollendet ihn nur und schließt ihn in seine bestimmten Grenzen ein."}, {"type": "paragraph", "text": "§. 7. Inhalt und Umfang der Begriffe. Ein jeder Begriff, als Theilbegriff, ist in der Vorstellung der Dinge enthalten, als Erkenntnißgrund, d.i. als Merkmal sind diese Dinge unter ihm enthalten. In der erstern Rücksicht hat jeder Begriff einen Inhalt, in der andern einen Umfang. Inhalt und Umfang eines Begriffes stehen gegen einander in umgekehrtem Verhältnisse. Je mehr nämlich ein Begriff unter sich enthält, desto weniger enthält er in sich und umgekehrt."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Die Allgemeinheit oder Allgemeingültigkeit des Begriffes beruht nicht darauf, daß der Begriff ein Theilbegriff, sondern daß er ein Erkenntnißgrund ist. §. 8. Größe des Umfanges der Begriffe. Der Umfang oder die Sphäre eines Begriffes ist um so größer, je mehr Dinge unter ihm stehen und durch ihn gedacht werden können."}, {"type": "paragraph", "text": "——————"}], "markers": [{"system": "AA", "band": "IX", "page": 95, "ref": "IX95"}, {"system": "AA", "band": "IX", "page": 96, "ref": "IX96"}], "running_header": "1. Abschnitt. Von den Begriffen [§§ 1 - 16]"}, {"page_pdf": 2786, "page_book": 97, "page_kind": "body", "sigel": "AA IX, 97", "units": [{"type": "paragraph", "text": "Anmerkung. So wie man von einem Grunde überhaupt sagt, daß er die Folge unter sich enthalte: so kann man auch von dem Begriffe sagen, daß er als Erkenntnißgrund alle diejenigen Dinge unter sich enthalte, von denen er abstrahirt worden, z.B. der Begriff Metall das Gold, Silber, Kupfer u.s.w. Denn da jeder Begriff, als eine allgemeingültige Vorstellung, dasjenige enthält, was mehreren Vorstellungen von verschiedenen Dingen gemein ist: so können alle diese Dinge, die in so fern unter ihm enthalten sind, durch ihn vorgestellt werden. Und eben dies macht die Brauchbarkeit eines Begriffs aus. Je mehr Dinge nun durch einen Begriff können vorgestellt werden: desto größer ist die Sphäre desselben. So hat z.B. der Begriff Körper einen größeren Umfang als der Begriff Metall."}, {"type": "paragraph", "text": "§. 9. Höhere und niedere Begriffe. Begriffe heißen höhere (_conceptus superiores_), sofern sie andre Begriffe unter sich haben, die im Verhältnisse zu ihnen niedere Begriffe genannt werden. Ein Merkmal vom Merkmal – ein entferntes Merkmal – ist ein höherer Begriff, der Begriff in Beziehung auf ein entferntes Merkmal, ein niederer."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Da höhere und niedere Begriffe nur beziehungsweise (_respective_) so heißen: so kann also Ein und derselbe Begriff in verschiedenen Beziehungen, zugleich ein höherer und ein niederer sein. So ist z.B. der Begriff Mensch in Beziehung auf den Begriff Neger ein höherer, in Beziehung auf den Begriff Thier aber ein niederer."}, {"type": "paragraph", "text": "§. 10. Gattung und Art. Der höhere Begriff heißt in Rücksicht seines niederen Gattung (_genus_), der niedere Begriff in Ansehung seines höheren Art (_species_). So wie höhere und niedere, so sind also auch Gattungs- und Artbegriffe nicht ihrer Natur nach, sondern nur in Ansehung ihres Verhältnisses zu einander (_termini a quo_ oder _ad quod_) in der logischen Subordination unterschieden."}, {"type": "paragraph", "text": "§. 11. Höchste Gattung und niedrigste Art. Die höchste Gattung ist die, welche keine Art ist (_genus summum non est species_), sowie die niedrigste Art die, welche keine Gattung ist (_species, quae non est genus, est_ _infima_). Dem Gesetze der Stetigkeit zufolge kann es indessen weder eine niedrigste, noch eine nächste Art geben."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Denken wir uns eine Reihe von mehreren einander subordinirten Begriffen, z.B. Eisen, Metall, Körper, Substanz, Ding: so können wir hier immer höhere Gattungen erhalten, – denn eine jede Species ist immer zugleich als Genus zu betrachten in Ansehung ihres niederen Begriffes, z.B. der Begriff Gelehrter in Ansehung des Begriffs Philosoph – bis wir endlich auf ein Genus kommen, das nicht wieder Species sein kann. Und zu einem solchen müssen wir zuletzt gelangen können, weil es doch am Ende einen höchsten Begriff (_conceptum summum_) geben muß, von dem sich, als solchem nichts weiter abstrahiren läßt, ohne daß der ganze Begriff verschwindet. – Aber einen niedrigsten Begriff (_conceptum infimum_) oder eine niedrigste Art, worunter kein anderer mehr enthalten wäre, giebt es in der Reihe der Arten und Gattungen nicht, weil ein solcher sich unmöglich bestimmen läßt. Denn haben wir auch einen Begriff, den wir unmittelbar auf Individuen anwenden: so können in Ansehung desselben doch noch specifische Unterschiede vorhanden sein, die wir entweder nicht bemerken, oder die wir aus der Acht lassen. Nur comparativ für den Gebrauch giebt es niedrigste Begriffe, die gleichsam durch Convention diese Bedeutung erhalten haben, sofern man übereingekommen ist, hierbei nicht tiefer zu gehen."}], "markers": [{"system": "AA", "band": "IX", "page": 97, "ref": "IX97"}], "running_header": "1. Abschnitt. Von den Begriffen [§§ 1 - 16]"}, {"page_pdf": 2787, "page_book": 98, "page_kind": "body", "sigel": "AA IX, 98", "units": [{"type": "paragraph", "text": "In Absicht auf die Bestimmung der Art- und Gattungsbegriffe gilt also folgendes allgemeine Gesetz: Es giebt ein Genus, das nicht mehr Species sein kann, aber es giebt keine Species, die nicht wieder sollte Genus sein können. §. 12. Weiterer und engerer Begriff. – Wechselbegriffe. Der höhere Begriff heißt auch ein weiterer; der niedere ein engerer Begriff. Begriffe, die einerlei Sphäre haben, werden Wechselbegriffe (_conceptus reciproci_) genannt."}, {"type": "paragraph", "text": "§. 13. Verhältniß des niederen zum höhern, des weitern zum engeren Begriffe. Der niedere Begriff ist nicht in dem höhern enthalten, denn er enthält mehr in sich als der höhere; aber er ist doch unter demselben enthalten, weil der höhere den Erkenntnißgrund des niederen enthält. Ferner ist ein Begriff nicht weiter als der andre, darum weil er mehr unter sich enthält – denn das kann man nicht wissen –, sondern sofern er den andern Begriff, und außer demselben noch mehr, unter sich enthält."}, {"type": "paragraph", "text": "§. 14. Allgemeine Regeln in Absicht auf die Subordination der Begriffe. In Ansehung des logischen Umfanges der Begriffe gelten folgende allgemeine Regeln: 1) Was den höhern Begriffen zukommt oder widerspricht, das kommt auch zu oder widerspricht allen niedrigern Begriffen, die unter jenen höhern enthalten sind; und 2) umgekehrt: Was allen niedrigern Begriffen zukommt oder widerspricht, das kommt auch zu oder widerspricht ihrem höhern Begriffe."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Weil das, worin Dinge übereinkommen, aus ihren allgemeinen Eigenschaften, und das, worin sie von einander verschieden sind, aus ihren besondern Eigenschaften herfließt, so kann man nicht schließen: Was einem niedrigern Begriffe zukommt oder widerspricht, das kommt auch zu oder widerspricht andern niedrigeren Begriffen, die mit jenem zu Einem höhern Begriffe gehören. So kann man z.B. nicht schließen: Was dem Menschen nicht zukommt, das kommt auch den Engeln nicht zu."}, {"type": "paragraph", "text": "§. 15. Bedingungen der Entstehung höherer und niederer Begriffe: Logische Abstraction und logische Determination. Durch fortgesetzte logische Abstraction entstehen immer höhere, so wie dagegen durch fortgesetzte logische Determination immer niedrigere Begriffe. Die größte mögliche Abstraction giebt den höchsten oder abstractesten Begriff – den, von dem sich keine Bestimmung weiter wegdenken läßt. Die höchste vollendete Determination würde einen durchgängig bestimmten Begriff (_conceptum omnimode determinatum_) d.i. einen solchen geben, zu dem sich keine weitere Bestimmung mehr hinzu denken ließe."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Da nur einzelne Dinge oder Individuen durchgängig bestimmt sind: so kann es auch nur durchgängig bestimmte Erkenntnisse als Anschauungen, nicht aber als Begriffe, geben; in Ansehung der letztern kann die logische Bestimmung nie als vollendet angesehen werden (§. 11. Anm.)."}, {"type": "paragraph", "text": "§. 16. Gebrauch der Begriffe _in abstracto_ und _in concreto_. Ein jeder Begriff kann allgemein und besonders (_in abstracto_ und _in concreto_) gebraucht"}], "markers": [{"system": "AA", "band": "IX", "page": 98, "ref": "IX98"}, {"system": "AA", "band": "IX", "page": 99, "ref": "IX99"}], "running_header": "1. Abschnitt. Von den Begriffen [§§ 1 - 16]"}, {"page_pdf": 2788, "page_book": 100, "page_kind": "body", "sigel": "AA IX, 100", "units": [{"type": "paragraph", "text": "werden. _In abstracto_ wird der niedere Begriff in Ansehung seines höhern, _in concreto_ der höhere Begriff in Ansehung seines niederen gebraucht."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. Die Ausdrücke des Abstracten und Concreten beziehen sich also nicht sowohl auf die Begriffe an sich selbst – denn jeder Begriff ist ein abstracter Begriff – als vielmehr nur auf ihren Gebrauch. Und dieser Gebrauch kann hinwiederum verschiedene Grade haben, je nachdem man einen Begriff bald mehr bald weniger abstract oder concret behandelt, d.h. bald mehr bald weniger Bestimmungen entweder wegläßt oder hinzusetzt. Durch den abstracten Gebrauch kommt ein Begriff der höchsten Gattung, durch den concreten Gebrauch dagegen dem Individuum näher. 2. Welcher Gebrauch der Begriffe, der abstracte oder der concrete, hat vor dem andern einen Vorzug? Hierüber läßt sich nichts entscheiden. Der Werth des einen ist nicht geringer zu schätzen, als der Werth des andern. Durch sehr abstracte Begriffe erkennen wir an vielen Dingen wenig, durch sehr concrete Begriffe erkennen wir an wenigen Dingen viel; was wir also auf der einen Seite gewinnen, das verlieren wir wieder auf der andern. Ein Begriff, der eine große Sphäre hat, ist in so fern sehr brauchbar, als man ihn auf viele Dinge anwenden kann; aber es ist auch dafür um so weniger in ihm enthalten. In dem Begriffe Substanz denke ich z.B. nicht so viel als in dem Begriffe Kreide. 3. Das Verhältniß zu treffen zwischen der Vorstellung _in abstracto_ und _in concreto_ in derselben Erkenntniß, also der Begriffe und ihrer Darstellung, wodurch das Maximum der Erkenntniß, dem Umfange sowohl als dem Inhalte nach, erreicht wird, darin besteht die Kunst der Popularität."}, {"type": "paragraph", "text": "——————"}], "markers": [{"system": "AA", "band": "IX", "page": 100, "ref": "IX100"}], "running_header": "1. Abschnitt. Von den Begriffen [§§ 1 - 16]"}, {"page_pdf": 2789, "page_book": 101, "page_kind": "body", "sigel": "AA IX, 101", "units": [{"type": "paragraph", "text": "Zweiter Abschnitt. Von den Urtheilen. [§§ 17-40] §. 17. Erklärung eines Urtheils überhaupt. Ein Urtheil ist die Vorstellung der Einheit des Bewußtseins verschiedener Vorstellungen oder die Vorstellung des Verhältnisses derselben, sofern sie einen Begriff ausmachen."}, {"type": "paragraph", "text": "§. 18. Materie und Form der Urtheile. Zu jedem Urtheile gehören als wesentliche Bestandstücke desselben Materie und Form. In den gegebenen, zur Einheit des Bewußtseins im Urtheile verbundenen Erkenntnissen besteht die Materie, in der Bestimmung der Art und Weise, wie die verschiedenen Vorstellungen, als solche, zu Einem Bewußtsein gehören, die Form des Urtheils."}, {"type": "paragraph", "text": "§. 19. Gegenstand der logischen Reflexion die bloße Form der Urtheile. Da die Logik von allem realen oder objectiven Unterschiede des Erkenntnisses abstrahirt: so kann sie sich mit der Materie der Urtheile so wenig als mit dem Inhalte der Begriffe beschäftigen. Sie hat also lediglich den Unterschied der Urtheile in Ansehung ihrer bloßen Form in Erwägung zu ziehen. §. 20. Logische Formen der Urtheile: Quantität, Qualität, Relation und Modalität. Die Unterschiede der Urtheile in Rücksicht auf ihre Form lassen sich auf die vier Hauptmomente der Quantität, Qualität, Relation und Modalität zurückführen, in Ansehung deren eben so viele verschiedene Arten von Urtheilen bestimmt sind."}, {"type": "paragraph", "text": "§. 21. Quantität der Urtheile: Allgemeine, Besondre, Einzelne. Der Quantität nach sind die Urtheile entweder allgemeine oder besondre oder einzelne, je nachdem das Subject im Urtheile entweder ganz von der Notion des Prädicats ein- oder ausgeschlossen, oder davon zum Theil nur ein- zum Theil ausgeschlossen ist. Im allgemeinen Urtheile wird die Sphäre eines Begriffs ganz innerhalb der Sphäre eines andern beschlossen; im particularen wird ein Theil des erstern unter die Sphäre des andern, und im einzelnen Urtheile endlich wird ein Begriff, der gar keine Sphäre hat, mithin bloß als Theil unter die Sphäre eines andern beschlossen."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. Die einzelnen Urtheile sind der logischen Form nach im Gebrauche den allgemeinen gleich zu schätzen, denn bei beiden gilt das Prädicat vom Subject ohne Ausnahme. In dem einzelnen Satze: z.B. Cajus ist sterblich, kann auch so wenig eine Ausnahme stattfinden als in dem allgemeinen: Alle Menschen sind sterblich. Denn es giebt nur Einen Cajus. 2. In Absicht auf die Allgemeinheit eines Erkenntnisses findet ein realer Unterschied statt zwischen generalen und universalen Sätzen, der aber freilich die Logik nichts angeht. Generale Sätze nämlich sind solche, die bloß etwas von dem Allgemeinen gewisser Gegenstände und folglich nicht hinreichende Bedingungen der Subsumtion enthalten, z.B. der Satz: man muß die Beweise gründlich machen. Universale Sätze sind die, welche von einem Gegenstande etwas allgemein behaupten. 3. Allgemeine Regeln sind entweder analytisch oder synthetisch allgemein. Jene abstrahiren von den Verschiedenheiten, diese attendiren auf die Unterschiede und bestimmen folglich doch auch in Ansehung ihrer. Je einfacher ein Object gedacht wird, desto eher ist analytische Allgemeinheit zufolge eines Begriffs möglich."}], "markers": [{"system": "AA", "band": "IX", "page": 101, "ref": "IX101"}, {"system": "AA", "band": "IX", "page": 102, "ref": "IX102"}, {"system": "AA", "band": "IX", "page": 103, "ref": "IX103"}], "running_header": "2. Abschnitt. Von den Urtheilen [§§ 17 - 40]"}, {"page_pdf": 2790, "page_book": 104, "page_kind": "body", "sigel": "AA IX, 104", "units": [{"type": "paragraph", "text": "4. Wenn allgemeine Sätze, ohne sie _in concreto_ zu kennen, in ihrer Allgemeinheit nicht können eingesehen werden, so können sie nicht zur Richtschnur dienen und also nicht heuristisch in der Anwendung gelten, sondern sind nur Aufgaben zu Untersuchung der allgemeinen Gründe zu dem, was in besondern Fällen zuerst bekannt worden. Der Satz zum Beispiel: Wer kein Interesse hat zu lügen und die Wahrheit weiß, der spricht Wahrheit, – dieser Satz ist in seiner Allgemeinheit nicht einzusehen, weil wir die Einschränkung auf die Bedingung des Uninteressirten nur durch Erfahrung kennen, nämlich daß Menschen aus Interesse lügen können, welches daher kommt, daß sie nicht fest an der Moralität hängen. Eine Beobachtung, die uns die Schwäche der menschlichen Natur kennen lehrt. 5. Von den besondern Urtheilen ist zu merken, daß, wenn sie durch die Vernunft sollen können eingesehen werden und also eine rationale, nicht bloß intellectuale (abstrahirte) Form haben: so muß das Subject ein weiterer Begriff (_conceptus latior_) als das Prädicat sein. Es sei das Prädicat jederzeit = O, das Subject *Y*, so ist"}, {"type": "paragraph", "text": "_a_ _b_"}, {"type": "paragraph", "text": "ein besonderes Urtheil, denn einiges unter _a_ Gehörige ist _b_, einiges nicht _b_, – das folgt aus der Vernunft. Aber es sei"}, {"type": "paragraph", "text": "_a_ _ b_"}, {"type": "paragraph", "text": "so kann zum wenigsten alles _a_ unter _b_ enthalten sein, wenn es kleiner ist, aber nicht wenn es größer ist, also ist es nur zufälliger Weise particular."}, {"type": "paragraph", "text": "§. 22. Qualität der Urtheile: Bejahende, Verneinende, Unendliche. Der Qualität nach sind die Urtheile entweder bejahende oder verneinende oder unendliche. Im bejahenden Urtheile wird das Subject unter der Sphäre eines Prädicats gedacht, im verneinenden wird es außer der Sphäre des letztern gesetzt, und im unendlichen wird es in die Sphäre eines Begriffs, die außerhalb der Sphäre eines andern liegt, gesetzt."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. Das unendliche Urtheil zeigt nicht bloß an, daß ein Subject unter der Sphäre eines Prädicats nicht enthalten sei, sondern daß es außer der Sphäre desselben in der unendlichen Sphäre irgendwo liege; folglich stellt dieses Urtheil die Sphäre des Prädicats als beschränkt vor. Alles Mögliche ist entweder _A_ oder _non A_. Sage ich also: etwas ist _non A_, z.B. die menschliche Seele ist nicht-sterblich, einige Menschen sind Nichtgelehrte u.dgl.m., so ist dies ein unendliches Urtheil. Denn es wird durch dasselbe über die endliche Sphäre _A_ hinaus nicht bestimmt, unter welchen Begriff das Object gehöre, sondern lediglich, daß es in die Sphäre außer _A_ gehöre, welches eigentlich gar keine Sphäre ist, sondern nur die Angrenzung einer Sphäre an das Unendliche oder die Begrenzung selbst. Obgleich nun die Ausschließung eine Negation ist: so ist doch die Beschränkung eines Begriffs eine positive Handlung. Daher sind Grenzen positive Begriffe beschränkter Gegenstände. 2. Nach dem Principium der Ausschließung jedes Dritten (_exclusi tertii_) ist die Sphäre eines Begriffs relativ auf eine andre entweder ausschließend oder einschließend. Da nun die Logik bloß mit der Form des Urtheils, nicht mit den Begriffen ihrem Inhalte nach, es zu thun hat: so ist die Unterscheidung der unendlichen von den negativen Urtheilen nicht zu dieser Wissenschaft gehörig. 3. In verneinenden Urtheilen afficirt die Negation immer die Copula, in unendlichen wird nicht die Copula, sondern das Prädicat durch die Negation afficirt, welches sich im Lateinischen am besten ausdrücken läßt."}], "markers": [{"system": "AA", "band": "IX", "page": 104, "ref": "IX104"}], "running_header": "2. Abschnitt. Von den Urtheilen [§§ 17 - 40]"}, {"page_pdf": 2791, "page_book": 105, "page_kind": "body", "sigel": "AA IX, 105", "units": [{"type": "paragraph", "text": "§. 23. Relation der Urtheile: Kategorische, Hypothetische, Disjunctive. Der Relation nach sind die Urtheile entweder kategorische oder hypothetische oder disjunctive. Die gegebenen Vorstellungen im Urtheile sind nämlich eine der andern zur Einheit des Bewußtseins untergeordnet, entweder: als Prädicat dem Subjecte, oder: als Folge dem Grunde, oder: als Glied der Eintheilung dem eingetheilten Begriffe. Durch das erste Verhältniß sind die kategorischen, durch das zweite die hypothetischen und durch das dritte die disjunctiven Urtheile bestimmt. §. 24. Kategorische Urtheile. In den kategorischen Urtheilen machen Subject und Prädicat die Materie derselben aus, die Form, durch welche das Verhältniß (der Einstimmung oder des Widerstreits) zwischen Subject und Prädicat bestimmt und ausgedrückt wird, heißt die Copula."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Die kategorischen Urtheile machen zwar die Materie der übrigen Urtheile aus, aber darum muß man doch nicht, wie mehrere Logiker, glauben, daß die hypothetischen sowohl als die disjunctiven Urtheile weiter nichts als verschiedene Einkleidungen der kategorischen seien und sich daher insgesammt auf die letztern zurückführen ließen. Alle drei Arten von Urtheilen beruhen auf wesentlich verschiedenen logischen Functionen des Verstandes und müssen daher nach ihrer specifischen Verschiedenheit erwogen werden."}, {"type": "paragraph", "text": "§. 25. Hypothetische Urtheile. Die Materie der hypothetischen Urtheile besteht aus zwei Urtheilen, die mit einander als Grund und Folge verknüpft sind. Das eine dieser Urtheile, welches den Grund enthält, ist der Vordersatz (_antecedens, prius_), das andre, das sich zu jenem als Folge verhält, der Nachsatz (_consequens, posterius_), und die Vorstellung dieser Art von Verknüpfung beider Urtheile unter einander zur Einheit des Bewußtseins wird die Consequenz genannt, welche die Form der hypothetischen Urtheile ausmacht."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. Was für die kategorischen Urtheile die _copula_, das ist für die hypothetischen also die Consequenz – die Form derselben. 2. Einige glauben, es sei leicht, einen hypothetischen Satz in einen kategorischen zu verwandeln. Allein dieses geht nicht an, weil beide ihrer Natur nach ganz von einander verschieden sind. In kategorischen Urtheilen ist nichts problematisch, sondern alles assertorisch, in hypothetischen hingegen ist nur die Consequenz assertorisch. In den letztern kann ich daher zwei falsche Urtheile mit einander verknüpfen, denn es kommt hier nur auf die Richtigkeit der Verknüpfung – die Form der Consequenz an, worauf die logische Wahrheit dieser Urtheile beruht. Es ist ein wesentlicher Unterschied zwischen den beiden Sätzen: Alle Körper sind theilbar, und: Wenn alle Körper zusammengesetzt sind, so sind sie theilbar. In dem erstern Satze behaupte ich die Sache gerade zu, im letztern nur unter einer problematisch ausgedrückten Bedingung."}, {"type": "paragraph", "text": "§. 26. Verknüpfungsarten in den hypothetischen Urtheilen: _modus ponens_ und _modus tollens_. Die Form der Verknüpfung in den hypothetischen Urtheilen ist zwiefach: die setzende (_modus ponens_) oder die aufhebende (_modus tollens_). 1) Wenn der Grund (_antecedens_) wahr ist: so ist auch die durch ihn bestimmte Folge"}], "markers": [{"system": "AA", "band": "IX", "page": 105, "ref": "IX105"}, {"system": "AA", "band": "IX", "page": 106, "ref": "IX106"}], "running_header": "2. Abschnitt. Von den Urtheilen [§§ 17 - 40]"}, {"page_pdf": 2792, "page_book": 107, "page_kind": "body", "sigel": "AA IX, 107", "units": [{"type": "paragraph", "text": "(_consequens_) wahr; heißt der _modus ponens_. 2) Wenn die Folge (_consequens_) falsch ist: so ist auch der Grund (_antecedens_) falsch; _modus tollens_."}, {"type": "paragraph", "text": "§. 27. Disjunctive Urtheile. Ein Urtheil ist disjunctiv, wenn die Theile der Sphäre eines gegebenen Begriffs einander in dem Ganzen oder zu einem Ganzen als Ergänzungen (_complementa_) bestimmen."}, {"type": "paragraph", "text": "§. 28. Materie und Form disjunctiver Urtheile. Die mehreren gegebenen Urtheile, woraus das disjunctive Urtheil zusammengesetzt ist, machen die Materie desselben aus und werden die Glieder der Disjunction oder Entgegensetzung genannt. In der Disjunction selbst, d.h. in der Bestimmung des Verhältnisses der verschiedenen Urtheile, als sich wechselseitig einander ausschließender und einander ergänzender Glieder der ganzen Sphäre des eingetheilten Erkenntnisses, besteht die Form dieser Urtheile."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Alle disjunctiven Urtheile stellen also verschiedene Urtheile als in der Gemeinschaft einer Sphäre vor und bringen jedes Urtheil nur durch die Einschränkung der andern in Ansehung der ganzen Sphäre hervor, sie bestimmen also jedes Urtheils Verhältniß zur ganzen Sphäre, und dadurch zugleich das Verhältniß, das diese verschiedenen Trennungsglieder (_membra disjuncta_) unter einander selbst haben. Ein Glied bestimmt also hier jedes andre nur, sofern sie insgesammt als Theile einer ganzen Sphäre von Erkenntniß, außer der sich in gewisser Beziehung nichts denken läßt, in Gemeinschaft stehen."}, {"type": "paragraph", "text": "§. 29. Eigenthümlicher Charakter der disjunctiven Urtheile. Der eigenthümliche Charakter aller disjunctiven Urtheile, wodurch ihr specifischer Unterschied dem Momente der Relation nach von den übrigen, insbesondre von den kategorischen Urtheilen bestimmt ist, besteht darin: daß die Glieder der Disjunction insgesammt problematische Urtheile sind, von denen nichts anders gedacht wird, als daß sie, wie Theile der Sphäre einer Erkenntniß, jedes des andern Ergänzung zum Ganzen (_complementum ad totum_), zusammengenommen, der Sphäre des ersten gleich seien. Und hieraus folgt: daß in Einem dieser problematischen Urtheile die Wahrheit enthalten sein oder – welches dasselbe ist –, daß Eines von ihnen assertorisch gelten müsse, weil außer ihnen die Sphäre der Erkenntniß unter den gegebenen Bedingungen nichts mehr befaßt und eine der andern entgegengesetzt ist, folglich weder außer ihnen etwas anders, noch auch unter ihnen mehr als Eines wahr sein kann."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. In einem kategorischen Urtheile wird das Ding, dessen Vorstellung als ein Theil von der Sphäre einer andern subordinirten Vorstellung betrachtet wird, als enthalten unter dieses seinem obern Begriffe betrachtet, also wird hier in der Subordination der Sphären der Theil vom Theile mit dem Ganzen verglichen. Aber in disjunctiven Urtheilen gehe ich vom Ganzen auf alle Theile zusammengenommen. Was unter der Sphäre eines Begriffs enthalten ist, das ist auch unter einem der Theile dieser Sphäre enthalten. Darnach muß erstlich die Sphäre eingetheilt werden. Wenn ich z.B. das disjunctive Urtheil fälle: Ein Gelehrter ist entweder ein historischer oder ein Vernunftgelehrter, so bestimme ich damit, daß diese Begriffe der Sphäre nach Theile der Sphäre der Gelehrten sind, aber keineswegs Theile von einander, und daß sie alle zusammengenommen complet sind. Daß in den disjunctiven Urtheilen nicht die Sphäre des eingetheilten Begriffs, als enthalten in der Sphäre der Eintheilungen, sondern das, was unter dem eingetheilten Begriffe enthalten ist, als enthalten"}], "markers": [{"system": "AA", "band": "IX", "page": 107, "ref": "IX107"}, {"system": "AA", "band": "IX", "page": 108, "ref": "IX108"}], "running_header": "2. Abschnitt. Von den Urtheilen [§§ 17 - 40]"}, {"page_pdf": 2793, "page_book": 109, "page_kind": "body", "sigel": "AA IX, 109", "units": [{"type": "paragraph", "text": "unter einem der Glieder der Eintheilung, betrachtet werde, mag folgendes Schema der Vergleichung zwischen kategorischen und disjunctiven Urtheilen anschaulicher machen. In kategorischen Urtheilen ist _x_, was unter _b_ enthalten ist, auch unter _a_: _b_ _a_ _x_"}, {"type": "paragraph", "text": "In disjunctiven ist _x_, was unter _a_ enthalten ist, entweder unter _b_ oder _c_ u.s.w. enthalten: _a_ _ a c_ _ d e_"}, {"type": "paragraph", "text": "Also zeigt die Division in disjunctiven Urtheilen die Coordination nicht der Theile des ganzen Begriffs, sondern alle Theile seiner Sphäre an. Hier denke ich viel Dinge durch einen Begriff, dort ein Ding durch viel Begriffe, z.B. das Definitum durch alle Merkmale der Coordination."}, {"type": "paragraph", "text": "§. 30. Modalität der Urtheile: Problematische, assertorische, apodiktische. Der Modalität nach, durch welches Moment das Verhältniß des ganzen Urtheils zum Erkenntnißvermögen bestimmt ist, sind die Urtheile entweder problematische oder assertorische oder apodiktische. Die problematischen sind mit dem Bewußtsein der bloßen Möglichkeit, die assertorischen mit dem Bewußtsein der Wirklichkeit, die apodiktischen endlich mit dem Bewußtsein der Nothwendigkeit des Urtheilens begleitet."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. Dieses Moment der Modalität zeigt also nur die Art und Weise an, wie im Urtheile etwas behauptet oder verneint wird: ob man über die Wahrheit oder Unwahrheit eines Urtheils nichts ausmacht, wie in dem problematischen Urtheile: die Seele des Menschen mag unsterblich sein; oder ob man darüber etwas bestimmt, wie in dem assertorischen Urtheile: die menschliche Seele ist unsterblich; oder endlich, ob man die Wahrheit eines Urtheils sogar mit der Dignität der Nothwendigkeit ausdrückt, wie in dem apodiktischen Urtheile: die Seele des Menschen muß unsterblich sein. Diese Bestimmung der bloß möglichen oder wirklichen oder nothwendigen Wahrheit betrifft also nur das Urtheil selbst, keineswegs die Sache, worüber geurtheilt wird. 2. In problematischen Urtheilen, die man auch für solche erklären kann, deren Materie gegeben ist mit dem möglichen Verhältniß zwischen Prädicat und Subject, muß das Subject jederzeit eine kleinere Sphäre haben als das Prädicat. 3. Auf dem Unterschiede zwischen problematischem und assertorischem Urtheilen beruht der wahre Unterschied zwischen Urtheilen und Sätzen, den man sonst fälschlich in den bloßen Ausdruck durch Worte, ohne die man ja überall nicht urtheilen könnte, zu setzen pflegt. Im Urtheile wird das Verhältniß verschiedener Vorstellungen zur Einheit des Bewußtseins bloß als problematisch gedacht, in einem Satze hingegen als assertorisch. Ein problematischer Satz ist eine _contradictio in adjecto_. Ehe ich einen Satz habe, muß ich doch erst urtheilen; und ich urtheile über vieles, was ich nicht ausmache, welches ich aber thun muß, sobald ich ein Urtheil als Satz bestimme. Es ist übrigens gut, erst problematisch zu urtheilen, ehe man das Urtheil als assertorisch annimmt, um es auf diese Art zu prüfen. Auch ist es nicht allemal zu unsrer Absicht nöthig, assertorische Urtheile zu haben."}, {"type": "paragraph", "text": "§. 31. Exponible Urtheile. Urtheile, in denen eine Bejahung und Verneinung zugleich, aber versteckter Weise, enthalten ist, so daß die Bejahung zwar deutlich, die Verneinung aber versteckt geschieht, sind exponible"}], "markers": [{"system": "AA", "band": "IX", "page": 109, "ref": "IX109"}], "running_header": "2. Abschnitt. Von den Urtheilen [§§ 17 - 40]"}, {"page_pdf": 2794, "page_book": 110, "page_kind": "body", "sigel": "AA IX, 110", "units": [{"type": "paragraph", "text": "Sätze."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. In dem exponiblen Urtheile, z.B. wenige Menschen sind gelehrt, liegt 1), aber auf eine versteckte Weise, das negative Urtheil: viele Menschen sind nicht gelehrt, und 2) das affirmative: einige Menschen sind gelehrt. Da die Natur der exponiblen Sätze lediglich von Bedingungen der Sprache abhängt, nach welchen man zwei Urtheile auf einmal in der Kürze ausdrücken kann: so gehört die Bemerkung, daß es in unsrer Sprache Urtheile geben könne, die exponirt werden müssen, nicht in die Logik, sondern in die Grammatik. §. 32. Theoretische und praktische Sätze. Theoretische Sätze heißen die, welche sich auf den Gegenstand beziehen und bestimmen, was demselben zukomme oder nicht zukomme; praktische Sätze hingegen sind die, welche die Handlung aussagen, wodurch, als nothwendige Bedingung desselben, ein Object möglich wird."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Die Logik hat nur von praktischen Sätzen der Form nach, die in so fern den theoretischen entgegengesetzt sind, zu handeln. Praktische Sätze, dem Inhalte nach, und in so fern von den speculativen unterschieden, gehören in die Moral."}, {"type": "paragraph", "text": "§. 33. Indemonstrable und demonstrable Sätze. Demonstrable Sätze sind die, welche eines Beweises fähig sind; die keines Beweises fähig sind, werden indemonstrable genannt. Unmittelbar gewisse Urtheile sind indemonstrabel und also als Elementar-Sätze anzusehen."}, {"type": "paragraph", "text": "§. 34. Grundsätze. Unmittelbar gewisse Urtheile _a priori_ können Grundsätze heißen, sofern andre Urtheile aus ihnen erwiesen, sie selbst aber keinem andern subordinirt werden können. Sie werden um deswillen auch Principien (Anfänge) genannt."}, {"type": "paragraph", "text": "§. 35. Intuitive und discursive Grundsätze: Axiome und Akroame. Grundsätze sind entweder intuitive oder discursive. Die erstern können in der Anschauung dargestellt werden und heißen Axiome (_axiomata_), die letztern lassen sich nur durch Begriffe ausdrücken und können Akroame (_acroamata_) genannt werden. §. 36. Analytische und synthetische Sätze. Analytische Sätze heißen solche, deren Gewißheit auf Identität der Begriffe (des Prädicats mit der Notion des Subjects) beruht. Sätze, deren Wahrheit sich nicht auf Identität der Begriffe gründet, müssen synthetische genannt werden."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. Alles _x_, welchem der Begriff des Körpers (_a+b_) zukommt, dem kommt auch die Ausdehnung (_b_) zu, ist ein Exempel eines analytischen Satzes. Alles _x_, welchem der Begriff des Körpers (a+b) zukommt, dem kommt auch die Anziehung (_c_) zu, ist ein Exempel eines synthetischen Satzes. Die synthetischen Sätze vermehren das Erkenntniß _materialiter_, die analytischen bloß _formaliter_. Jene enthalten Bestimmungen (_determinationes_), diese nur logische Prädicate."}], "markers": [{"system": "AA", "band": "IX", "page": 110, "ref": "IX110"}, {"system": "AA", "band": "IX", "page": 111, "ref": "IX111"}], "running_header": "2. Abschnitt. Von den Urtheilen [§§ 17 - 40]"}, {"page_pdf": 2795, "page_book": 112, "page_kind": "body", "sigel": "AA IX, 112", "units": [{"type": "paragraph", "text": "2. Analytische Principien sind nicht Axiome, denn sie sind discursiv. Und synthetische Principien sind auch nur dann Axiome, wenn sie intuitiv sind."}, {"type": "paragraph", "text": "§. 37. Tautologische Sätze. Die Identität der Begriffe in analytischen Urtheilen kann entweder eine ausdrückliche (_explicita_) oder eine nicht-ausdrückliche (_implicita_) sein. Im erstern Falle sind die analytischen Sätze tautologisch."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. Tautologische Sätze sind _virtualiter_ leer oder folgeleer, denn sie sind ohne Nutzen und Gebrauch. Dergleichen ist z.B. der tautologische Satz: der Mensch ist Mensch. Denn wenn ich vom Menschen nichts weiter zu sagen weiß, als daß er ein Mensch ist: so weiß ich gar weiter nichts von ihm. _Implicite_ identische Sätze sind dagegen nicht folge- oder fruchtleer, denn sie machen das Prädicat, welches im Begriffe des Subjects unentwickelt (_implicite_) lag, durch Entwickelung (_explicatio_) klar. 2. Folgeleere Sätze müssen von sinnleeren unterschieden werden, die darum leer an Verstand sind, weil sie die Bestimmung sogenannter verborgener Eigenschaften (_qualitates occultae_) betreffen. §. 38. Postulat und Problem. Ein Postulat ist ein praktischer, unmittelbar gewisser Satz oder ein Grundsatz, der eine mögliche Handlung bestimmt, bei welcher vorausgesetzt wird, daß die Art sie auszuführen, unmittelbar gewiß sei. Probleme (_problemata_) sind demonstrable, einer Anweisung bedürftige Sätze, oder solche, die eine Handlung aussagen, deren Art der Ausführung nicht unmittelbar gewiß ist."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. Es kann auch theoretische Postulate geben zum Behuf der praktischen Vernunft. Dieses sind theoretische, in praktischer Vernunftabsicht nothwendige Hypothesen, wie die des Daseins Gottes, der Freiheit und einer andern Welt. 2. Zum Problem gehört 1) die Quästion, die das enthält, was geleistet werden soll, 2) die Resolution, die die Art und Weise enthält, wie das zu leistende könne ausgeführt werden, und 3) die Demonstration, daß, wenn ich so werde verfahren haben, das Geforderte geschehen werde."}, {"type": "paragraph", "text": "§. 39. Theoreme, Corollarien, Lehnsätze und Scholien. Theoreme sind theoretische, eines Beweises fähige und bedürftige Sätze. Corollarien sind unmittelbare Folgen aus einem der vorhergehenden Sätze. Lehnsätze (_lemmata_) heißen Sätze, die in der Wissenschaft, worin sie als erwiesen vorausgesetzt werden, nicht einheimisch, sondern aus andern Wissenschaften entlehnt sind. Scholien endlich sind bloße Erläuterungssätze, die also nicht als Glieder zum Ganzen des Systems gehören."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Wesentliche und allgemeine Momente eines jeden Theorems sind die Thesis und die Demonstration. Den Unterschied zwischen Theoremen und Corollarien kann man übrigens auch darin setzen, daß diese unmittelbar geschlossen, jene dagegen durch eine Reihe von Folgen aus unmittelbar gewissen Sätzen gezogen werden. §. 40. Wahrnehmungs- und Erfahrungsurtheile. Ein Wahrnehmungsurtheil ist bloß subjectiv, ein objectives Urtheil aus Wahrnehmungen ist ein Erfahrungsurtheil."}], "markers": [{"system": "AA", "band": "IX", "page": 112, "ref": "IX112"}, {"system": "AA", "band": "IX", "page": 113, "ref": "IX113"}], "running_header": "2. Abschnitt. Von den Urtheilen [§§ 17 - 40]"}, {"page_pdf": 2796, "page_book": 112, "page_kind": "body", "sigel": "AA IX, 112", "units": [{"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Ein Urtheil aus bloßen Wahrnehmungen ist nicht wohl möglich als nur dadurch, daß ich meine Vorstellung, als Wahrnehmung, aussage: Ich, der ich einen Thurm wahrnehme, nehme an ihm die rothe Farbe wahr. Ich kann aber nicht sagen: er ist roth. Denn dieses wäre nicht bloß ein empirisches, sondern auch ein Erfahrungsurtheil, d.i. ein empirisches Urtheil, dadurch ich einen Begriff vom Object bekomme. Z.B. Bei der Berührung des Steins empfinde ich Wärme, ist ein Wahrnehmungsurtheil, hingegen: der Stein ist warm, ein Erfahrungsurtheil. Es gehört zum letztern, daß ich das, was bloß in meinem Subject ist, nicht zum Object rechne, denn ein Erfahrungsurtheil ist die Wahrnehmung, woraus ein Begriff vom Object entspringt; z.B. ob im Monde lichte Punkte sich bewegen oder in der Luft oder in meinem Auge."}, {"type": "paragraph", "text": "——————"}], "running_header": "2. Abschnitt. Von den Urtheilen [§§ 17 - 40]"}, {"page_pdf": 2797, "page_book": 114, "page_kind": "body", "sigel": "AA IX, 114", "units": [{"type": "paragraph", "text": "Dritter Abschnitt. Von den Schlüssen. [§§ 41-43] §. 41. Schluß überhaupt. Unter Schließen ist diejenige Function des Denkens zu verstehen, wodurch ein Urtheil aus einem andern hergeleitet wird. Ein Schluß überhaupt ist also die Ableitung eines Urtheils aus dem andern."}, {"type": "paragraph", "text": "§. 42. Unmittelbare und mittelbare Schlüsse. Alle Schlüsse sind entweder unmittelbare oder mittelbare. Ein unmittelbarer Schluß (_consequentia immediata_) ist die Ableitung (_deductio_) eines Urtheils aus dem andern ohne ein vermittelndes Urtheil (_judicium intermedium_). Mittelbar ist ein Schluß, wenn man außer dem Begriffe, den ein Urtheil in sich enthält, noch andre braucht, um ein Erkenntniß daraus herzuleiten."}, {"type": "paragraph", "text": "§. 43. Verstandesschlüsse, Vernunftschlüsse und Schlüsse der Urtheilskraft. Die unmittelbaren Schlüsse heißen auch Verstandesschlüsse, alle mittelbaren Schlüsse hingegen sind entweder Vernunftschlüsse oder Schlüsse der Urtheilskraft. Wir handeln hier zuerst von den unmittelbaren oder den Verstandesschlüssen."}], "markers": [{"system": "AA", "band": "IX", "page": 114, "ref": "IX114"}], "running_header": "3. Abschnitt. Von den Schlüssen [§§ 41 - 43]"}, {"page_pdf": 2798, "page_book": 115, "page_kind": "body", "sigel": "AA IX, 115", "units": [{"type": "heading", "text": "[Dritter Abschnitt. Von den Schlüssen.]", "level": 2}, {"type": "paragraph", "text": "I. Verstandesschlüsse. [§§ 44-55] §. 44. Eigenthümliche Natur der Verstandesschlüsse. Der wesentliche Charakter aller unmittelbaren Schlüsse und das Princip ihrer Möglichkeit besteht lediglich in einer Veränderung der bloßen Form der Urtheile, während die Materie der Urtheile, das Subject und Prädicat, unverändert dieselbe bleibt."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. Dadurch daß in den unmittelbaren Schlüssen nur die Form und keinesweges die Materie der Urtheile verändert wird, unterscheiden sich diese Schlüsse wesentlich von allen mittelbaren, in welchen die Urtheile auch der Materie nach unterschieden sind, indem hier ein neuer Begriff als vermittelndes Urtheil, oder als Mittelbegriff (_terminus medius_) hinzukommen muß, um das eine Urtheil aus dem andern zu folgern. Wenn ich z.B. schließe: Alle Menschen sind sterblich, also ist auch Cajus sterblich: so ist dies kein unmittelbarer Schluß. Denn hier brauche ich zu der Folgerung noch das vermittelnde Urtheil: Cajus ist ein Mensch; durch diesen neuen Begriff wird aber die Materie der Urtheile verändert. 2. Es läßt sich zwar auch bei den Verstandesschlüssen ein _judicium intermedium_ machen, aber alsdann ist dieses vermittelnde Urtheil bloß tautologisch. Wie z.B. in dem unmittelbaren Schlusse: Alle Menschen sind sterblich. Einige Menschen sind Menschen. Also sind einige Menschen sterblich, der Mittelbegriff ein tautologischer Satz ist."}, {"type": "paragraph", "text": "§. 45. _Modi_ der Verstandesschlüsse. Die Verstandesschlüsse gehen durch alle Klassen der logischen Functionen des Urtheilens und sind folglich in ihren Hauptarten bestimmt durch die Momente der Quantität, der Qualität, der Relation und der Modalität. Hierauf beruht die folgende Eintheilung dieser Schlüsse. §. 46. 1. Verstandesschlüsse (in Beziehung auf die Quantität der Urtheile) _per judicia subalternata_. In den Verstandesschlüssen _per judicia subalternata_ sind die beiden Urtheile der Quantität nach unterschieden, und es wird hier das besondre Urtheil aus dem allgemeinen abgeleitet, dem Grundsatze zufolge: Vom Allgemeinen gilt der Schluß auf das Besondere (_ab _ _universali ad particulare valet consequentia_)."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Ein _judicium_ heißt _subalternatum_, sofern es unter dem andern enthalten ist; wie z.B. besondre Urtheile unter allgemeinen."}, {"type": "paragraph", "text": "§. 47. 2. Verstandesschlüsse (in Beziehung auf die Qualität der Urtheile) _per judicia opposita._ Bei den Verstandesschlüssen dieser Art betrifft die Veränderung die Qualität der Urtheile und zwar in Beziehung auf die Entgegensetzung betrachtet. Da nun diese Entgegensetzung eine dreifache sein kann, so ergiebt sich hieraus folgende besondre Eintheilung des unmittelbaren Schließens: durch contradictorisch entgegengesetzte, durch conträre und durch subconträre Urtheile."}], "markers": [{"system": "AA", "band": "IX", "page": 115, "ref": "IX115"}, {"system": "AA", "band": "IX", "page": 116, "ref": "IX116"}], "running_header": "I. Verstandesschlüsse [§§ 44 - 55]"}, {"page_pdf": 2799, "page_book": 117, "page_kind": "body", "sigel": "AA IX, 117", "units": [{"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Verstandesschlüsse durch gleichgeltende Urtheile (_judicia aequipollentia_) können eigentlich keine Schlüsse genannt werden, denn hier findet keine Folge statt, sie sind vielmehr als eine bloße Substitution der Worte anzusehen, die einen und denselben Begriff bezeichnen, wobei die Urtheile selbst auch der Form nach unverändert bleiben. Z.B.: Nicht alle Menschen sind tugendhaft, und: Einige Menschen sind nicht tugendhaft. Beide Urtheile sagen ein und dasselbe."}, {"type": "paragraph", "text": "§. 48. _a_. Verstandesschlüsse _per judicia contradictorie opposita_. In Verstandesschlüssen durch Urtheile, die einander contradictorisch entgegengesetzt sind und als solche die ächte, reine Opposition ausmachen, wird die Wahrheit des einen der contradictorisch entgegengesetzten Urtheile aus der Falschheit des andern gefolgert und umgekehrt. Denn die ächte Opposition, die hier stattfindet, enthält nicht mehr noch weniger als was zur Entgegensetzung gehört. Dem Princip des ausschließenden Dritten zufolge können daher nicht beide widersprechende Urtheile wahr, aber auch [auch] eben so wenig können sie beide falsch sein. Wenn daher das eine wahr ist, so ist das andre falsch und umgekehrt."}, {"type": "paragraph", "text": "§. 49. _b_. Verstandesschlüsse _per judicia contrarie opposita._ Conträre oder widerstreitende Urtheile (_judicia contrarie opposita_) sind Urtheile, von denen das eine allgemein bejahend, das andre allgemein verneinend ist. Da nun eines derselben mehr aussagt, als das andre, und in dem Überflüssigen, das es außer der bloßen Verneinung des andern noch mehr aussagt, die Falschheit liegen kann: so können sie zwar nicht beide wahr, aber sie können beide falsch sein. In Ansehung dieser Urtheile gilt daher nur der Schluß von der Wahrheit des einen auf die Falschheit des andern, aber nicht umgekehrt."}, {"type": "paragraph", "text": "§. 50. _c_. Verstandesschlüsse _per judicia subcontrarie opposita._ Subconträre Urtheile sind solche, von denen das eine besonders (_particulariter_) bejaht oder verneint, was das andre besonders verneint oder bejaht. Da sie beide wahr, aber nicht beide falsch sein können, so gilt in Ansehung ihrer nur der folgende Schluß: Wenn der eine dieser Sätze falsch ist, so ist der andre wahr; aber nicht umgekehrt."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Bei den subconträren Urtheilen findet keine reine, strenge Opposition statt, denn es wird in dem einen nicht von denselben Objecten verneint oder bejaht, was in dem andern bejaht oder verneint wurde. In dem Schlusse z.B. Einige Menschen sind gelehrt, also sind einige Menschen nicht gelehrt, wird in dem ersten Urtheile nicht von denselben Menschen das behauptet, was im andern verneint wird. §. 51. 3. Verstandesschlüsse (in Rücksicht auf die Relation der Urtheile) _per judicia conversa sive per conversionem._ Die unmittelbaren Schlüsse durch Umkehrung betreffen die Relation der Urtheile und bestehen in der Versetzung der Subjecte und Prädicate in den beiden Urtheilen, so daß das Subject des einen Urtheils zum Prädicat des andern Urtheils gemacht wird, und umgekehrt."}], "markers": [{"system": "AA", "band": "IX", "page": 117, "ref": "IX117"}, {"system": "AA", "band": "IX", "page": 118, "ref": "IX118"}], "running_header": "I. Verstandesschlüsse [§§ 44 - 55]"}, {"page_pdf": 2800, "page_book": 119, "page_kind": "body", "sigel": "AA IX, 119", "units": [{"type": "paragraph", "text": "§. 52. Reine und veränderte Umkehrung. Bei der Umkehrung wird die Quantität der Urtheile entweder verändert oder sie bleibt unverändert. Im erstern Falle ist das Umgekehrte (_conversum_) von dem Umkehrenden (_convertente_) der Quantität nach unterschieden, und die Umkehrung heißt eine veränderte (_conversio per accidens_), im letztern Falle wird die Umkehrung eine reine (_conversio simpliciter _ _talis_) genannt."}, {"type": "paragraph", "text": "§. 53. Allgemeine Regeln der Umkehrung. In Absicht auf die Verstandesschlüsse durch die Umkehrung gelten folgende Regeln: 1) Allgemein bejahende Urtheile lassen sich nur _per accidens_ umkehren; denn das Prädicat in diesen Urtheilen ist ein weiterer Begriff, und es ist also nur Einiges von demselben in dem Begriffe des Subjects enthalten. 2) Aber alle allgemein verneinenden Urtheile lassen sich _simpliciter_ umkehren; denn hier wird das Subject aus der Sphäre des Prädicats herausgehoben. Ebenso lassen sich endlich 3) Alle particulär bejahenden Sätze _simpliciter_ umkehren; denn in diesen Urtheilen ist ein Theil der Sphäre des Subjects dem Prädicate subsumirt worden, also läßt sich auch ein Theil von der Sphäre des Prädicats dem Subjecte subsumiren."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. In allgemein bejahenden Urtheilen wird das Subject als ein _contentum_ des Prädicats betrachtet, da es unter der Sphäre desselben enthalten ist. Ich darf daher z.B. nur schließen: Alle Menschen sind sterblich, also sind einige von denen, die unter dem Begriff Sterbliche enthalten sind, Menschen. Daß aber allgemein verneinende Urtheile sich _simpliciter_ umkehren lassen, davon ist die Ursache diese: daß zwei einander allgemein widersprechende Begriffe sich in gleichem Umfange widersprechen. 2. Manche allgemein bejahenden Urtheile lassen sich zwar auch _simpliciter_ umkehren. Aber der Grund hievon liegt nicht in ihrer Form, sondern in der besondern Beschaffenheit ihrer Materie; wie z.B. die beiden Urtheile: Alles Unveränderliche ist nothwendig, und alles Nothwendige ist unveränderlich."}, {"type": "paragraph", "text": "§. 54. 4. Verstandesschlüsse (in Beziehung auf die Modalität der Urtheile) _per judicia contraposita._ Die unmittelbare Schlußart durch die Contraposition besteht in derjenigen Versetzung (_metathesis_) der Urtheile, bei welcher bloß die Quantität dieselbe bleibt, die Qualität dagegen verändert wird. Sie betreffen nur die Modalität der Urtheile, indem sie ein assertorisches in ein apodiktisches Urtheil verwandeln."}, {"type": "paragraph", "text": "§. 55. Allgemeine Regel der Contraposition. In Absicht auf die Contraposition gilt die allgemeine Regel: Alle allgemein bejahenden Urtheile lassen sich _simpliciter_ contraponiren. Denn wenn das Prädicat als dasjenige, was das Subject unter sich enthält, mithin die ganze Sphäre verneint wird: so muß auch ein Theil derselben verneint werden, d.i. das Subject."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. Die Metathesis der Urtheile durch die Conversion und die durch die Contraposition sind"}], "markers": [{"system": "AA", "band": "IX", "page": 119, "ref": "IX119"}], "running_header": "I. Verstandesschlüsse [§§ 44 - 55]"}, {"page_pdf": 2801, "page_book": 119, "page_kind": "body", "sigel": "AA IX, 119", "units": [{"type": "paragraph", "text": "also in so fern einander entgegengesetzt, als jene bloß die Quantität, diese bloß die Qualität verändert. 2. Die gedachten unmittelbaren Schlußarten beziehen sich bloß auf kategorische Urtheile."}], "running_header": "I. Verstandesschlüsse [§§ 44 - 55]"}, {"page_pdf": 2802, "page_book": 120, "page_kind": "body", "sigel": "AA IX, 120", "units": [{"type": "heading", "text": "[Dritter Abschnitt. Von den Schlüssen.]", "level": 2}, {"type": "paragraph", "text": "II. Vernunftschlüsse. [§§ 56-80] §. 56. Vernunftschluß überhaupt. Ein Vernunftschluß ist das Erkenntniß der Nothwendigkeit eines Satzes durch die Subsumtion seiner Bedingung unter eine gegebene allgemeine Regel."}, {"type": "paragraph", "text": "§. 57. Allgemeines Princip aller Vernunftschlüsse. Das allgemeine Princip, worauf die Gültigkeit alles Schließens durch die Vernunft beruht, läßt sich in folgender Formel bestimmt ausdrücken: Was unter der Bedingung einer Regel steht, das steht auch unter der Regel selbst."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Der Vernunftschluß prämittirt eine allgemeine Regel und eine Subsumtion unter die Bedingung derselben. Man erkennt dadurch die Conclusion _a priori_ nicht im Einzelnen, sondern als enthalten im Allgemeinen und als nothwendig unter einer gewissen Bedingung. Und dies, daß alles unter dem Allgemeinen stehe und in allgemeinen Regeln bestimmbar sei, ist eben das Princip der Rationalität oder der Nothwendigkeit (_principium rationalitatis sive necessitatis_)."}, {"type": "paragraph", "text": "§. 58. Wesentliche Bestandstücke des Vernunftschlusses. Zu einem jeden Vernunftschlusse gehören folgende wesentlichen drei Stücke: 1) eine allgemeine Regel, welche der Obersatz (_propositio major_) genannt wird, 2) der Satz, der ein Erkenntniß unter die Bedingung der allgemeinen Regel subsumirt und der Untersatz (_propositio minor_) heißt, und endlich 3) der Satz, welcher das Prädicat der Regel von der subsumirten Erkenntniß bejaht oder verneint: der Schlußsatz (_conclusio_). Die beiden erstern Sätze werden in ihrer Verbindung mit einander die Vordersätze oder Prämissen genannt."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Eine Regel ist eine Assertion unter einer allgemeinen Bedingung. Das Verhältniß der Bedingung zur Assertion, wie nämlich diese unter jener steht, ist der Exponent der Regel. Die Erkenntniß, daß die Bedingung (irgendwo) stattfinde, ist die Subsumtion. Die Verbindung desjenigen, was unter der Bedingung subsumirt worden, mit der Assertion der Regel, ist der Schluß."}, {"type": "paragraph", "text": "§. 59. Materie und Form der Vernunftschlüsse. In den Vordersätzen oder Prämissen besteht die Materie, und in der Conclusion, sofern sie die Consequenz enthält, die Form der Vernunftschlüsse."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. Bei jedem Vernunftschlusse ist also zuerst die Wahrheit der Prämissen und sodann die Richtigkeit der Consequenz zu prüfen. Nie muß man bei Verwerfung eines Vernunftschlusses zuerst die Conclusion verwerfen, sondern immer erst entweder die Prämissen oder die Consequenz. 2. In jedem Vernunftschlusse ist die Conclusion sogleich gegeben, so bald die Prämissen und die Consequenz gegeben sind."}], "markers": [{"system": "AA", "band": "IX", "page": 120, "ref": "IX120"}, {"system": "AA", "band": "IX", "page": 121, "ref": "IX121"}], "running_header": "II. Vernunftschlüsse [§§ 56 - 80]"}, {"page_pdf": 2803, "page_book": 122, "page_kind": "body", "sigel": "AA IX, 122", "units": [{"type": "paragraph", "text": "§. 60. Eintheilung der Vernunftschlüsse (der Relation nach) in kategorische, hypothetische und disjunctive. Alle Regeln (Urtheile) enthalten objective Einheit des Bewußtseins des Mannigfaltigen der Erkenntniß, mithin eine Bedingung, unter der ein Erkenntniß mit dem andern zu einem Bewußtsein gehört. Nun lassen sich aber nur drei Bedingungen dieser Einheit denken, nämlich: als Subject der Inhärenz der Merkmale, oder als Grund der Dependenz eines Erkenntnisses zum andern, oder endlich als Verbindung der Theile in einem Ganzen (logische Eintheilung). Folglich kann es auch nur eben so viele Arten von allgemeinen Regeln (_propositiones majores_) geben, durch welche die Consequenz eines Urtheils aus dem andern vermittelt wird. Und hierauf gründet sich die Eintheilung aller Vernunftschlüsse in kategorische, hypothetische und disjunctive."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. Die Vernunftschlüsse können weder der Quantität nach eingetheilt werden, denn jeder _major_ ist eine Regel, mithin etwas Allgemeines; noch in Ansehung der Qualität, denn es ist gleichgeltend, ob die Conclusion bejahend oder verneinend ist; noch endlich in Rücksicht auf die Modalität, denn die Conclusion ist immer mit dem Bewußtsein der Nothwendigkeit begleitet und hat folglich die Dignität eines apodiktischen Satzes. Also bleibt allein nur die Relation als einzig möglicher Eintheilungsgrund der Vernunftschlüsse übrig. 2. Viele Logiker halten nur die kategorischen Vernunftschlüsse für ordentliche, die übrigen hingegen für außerordentliche. Allein dieses ist grundlos und falsch. Denn alle drei dieser Arten sind Producte gleich richtiger, aber von einander gleich wesentlich verschiedener Functionen der Vernunft."}, {"type": "paragraph", "text": "§. 61. Eigenthümlicher Unterschied zwischen kategorischen, hypothetischen und disjunctiven Vernunftschlüssen. Das Unterscheidende unter den drei gedachten Arten von Vernunftschlüssen liegt im Obersatze. In kategorischen Vernunftschlüssen ist der Major ein kategorischer, in hypothetischen ist er ein hypothetischer oder problematischer, und in disjunctiven ein disjunctiver Satz."}, {"type": "paragraph", "text": "§. 62. 1. Kategorische Vernunftschlüsse. In einem jeden kategorischen Vernunftschlusse befinden sich drei Hauptbegriffe (_termini_), nämlich: 1) das Prädicat in der Conclusion, welcher Begriff der Oberbegriff (_terminus major_) heißt, weil er eine größere Sphäre hat als das Subject, 2) das Subject (in der Conclusion), dessen Begriff der Unterbegriff (_terminus minor_) heißt, und 3) ein vermittelndes Merkmal (_nota intermedia_), welches der Mittelbegriff (_terminus _ _medius_) heißt, weil durch denselben ein Erkenntniß unter die Bedingung der Regel subsumirt wird."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Dieser Unterschied in den gedachten _terminis_ findet nur in kategorischen Vernunftschlüssen statt, weil nur diese allein durch einen _terminum medium_ schließen; die andern dagegen nur durch die Subsumtion eines im Major problematisch und im Minor assertorisch vorgestellten Satzes."}], "markers": [{"system": "AA", "band": "IX", "page": 122, "ref": "IX122"}, {"system": "AA", "band": "IX", "page": 123, "ref": "IX123"}], "running_header": "II. Vernunftschlüsse [§§ 56 - 80]"}, {"page_pdf": 2804, "page_book": 124, "page_kind": "body", "sigel": "AA IX, 124", "units": [{"type": "paragraph", "text": "§. 63. Princip der kategorischen Vernunftschlüsse. Das Princip, worauf die Möglichkeit und Gültigkeit aller kategorischen Vernunftschlüsse beruht, ist dieses: Was dem Merkmale einer Sache zukommt, das kommt auch der Sache selbst zu; und was dem Merkmale einer Sache widerspricht, das widerspricht auch der Sache selbst (_nota notae est nota rei ipsius; repugnans notae, repugnat rei ipsi_)."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Aus dem so eben aufgestellten Princip läßt sich das sogenannte _Dictum de omni et nullo_ leicht deduciren, und es kann um deswillen nicht als das oberste Princip weder für die Vernunftschlüsse überhaupt, noch für die kategorischen insbesondre gelten. Die Gattungs- und Art-Begriffe sind nämlich allgemeine Merkmale aller der Dinge, die unter diesen Begriffen stehen. Es gilt demnach hier die Regel: Was der Gattung oder Art zukommt oder widerspricht, das kommt auch zu oder widerspricht allen den Objecten, die unter jener Gattung oder Art enthalten sind. Und diese Regel heißt eben das _Dictum de omni _ _et nullo_."}, {"type": "paragraph", "text": "§. 64. Regeln für die kategorischen Vernunftschlüsse. Aus der Natur und dem Princip der kategorischen Vernunftschlüsse fließen folgende Regeln für dieselben: 1) In jedem kategorischen Vernunftschlusse können nicht mehr noch weniger Hauptbegriffe (_termini_) enthalten sein als drei; denn ich soll hier zwei Begriffe (Subject und Prädicat) durch ein vermittelndes Merkmal verbinden. 2) Die Vordersätze oder Prämissen dürfen nicht insgesammt verneinen (_ex puris negativis _ _nihil sequitur_); denn die Subsumtion im Untersatze muß bejahend sein, als welche aussagt, daß ein Erkenntniß unter der Bedingung der Regel stehe. 3) Die Prämissen dürfen auch nicht insgesammt besondere (particulare) Sätze sein (_ex puris _ _particularibus nihil sequitur_); denn alsdann gäbe es keine Regel, d.h. keinen allgemeinen Satz, woraus ein besonderes Erkenntniß könnte gefolgert werden. 4) Die Conclusion richtet sich allemal nach dem schwächern Theile des Schlusses; d.h. nach dem verneinenden und besondern Satze in den Prämissen, als welcher der schwächere Theil des kategorischen Vernunftschlusses genannt wird (_conclusio _ _sequitur partem debiliorem_). Ist daher 5) einer von den Vordersätzen ein negativer Satz: so muß die Conclusion auch negativ sein, und 6) ist ein Vordersatz ein particularer Satz: so muß die Conclusion auch particular sein. 7) In allen kategorischen Vernunftschlüssen muß der Major ein allgemeiner (_universalis_), der Minor aber ein bejahender Satz (_affirmans_) sein, und hieraus folgt endlich, 8) daß die Conclusion in Ansehung der Qualität nach dem Obersatze, in Rücksicht auf die Quantität aber nach dem Untersatze sich richten müsse."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Daß sich die Conclusion jederzeit nach dem verneinenden und besondern Satze in den Prämissen richten müsse, ist leicht einzusehen. Wenn ich den Untersatz nur particular mache und sage: Einiges ist unter der Regel enthalten, so kann ich in der Conclusion auch nur sagen, daß das Prädicat der Regel Einigem zukomme, weil ich nicht mehr als dieses unter die Regel subsumirt habe. Und wenn ich einen verneinenden Satz zur Regel (Obersatz) habe: so muß ich die Conclusion auch verneinend machen. Denn wenn der Obersatz sagt: Von allem, was unter der Bedingung der Regel steht, muß dieses oder jenes Prädicat verneint werden: so muß"}], "markers": [{"system": "AA", "band": "IX", "page": 124, "ref": "IX124"}], "running_header": "II. Vernunftschlüsse [§§ 56 - 80]"}, {"page_pdf": 2805, "page_book": 125, "page_kind": "body", "sigel": "AA IX, 125", "units": [{"type": "paragraph", "text": "die Conclusion das Prädicat auch von dem (Subject) verneinen, was unter die Bedingung der Regel subsumirt worden."}, {"type": "paragraph", "text": "§. 65. Reine und vermischte kategorische Vernunftschlüsse. Ein kategorischer Vernunftschluß ist rein (_purus_), wenn in demselben kein unmittelbarer Schluß eingemischt, noch die gesetzmäßige Ordnung der Prämissen verändert ist; widrigenfalls wird er ein unreiner oder vermischter (_ratiocinium impurum_ oder _hybridum_) genannt."}, {"type": "paragraph", "text": "§. 66. Vermischte Vernunftschlüsse durch Umkehrung der Sätze – Figuren. Zu den vermischten Schlüssen sind diejenigen zu rechnen, welche durch die Umkehrung der Sätze entstehen und in denen also die Stellung dieser Sätze nicht die gesetzmäßige ist. Dieser Fall findet statt bei den drei letztern sogenannten Figuren des kategorischen Vernunftschlusses."}, {"type": "paragraph", "text": "§. 67. Vier Figuren der Schlüsse. Unter Figuren sind diejenigen vier Arten zu schließen zu verstehen, deren Unterschied durch die besondre Stellung der Prämissen und ihrer Begriffe bestimmt wird."}, {"type": "paragraph", "text": "§. 68. Bestimmungsgrund ihres Unterschiedes durch die verschiedene Stellung des Mittelbegriffes. Es kann nämlich der Mittelbegriff, auf dessen Stellung es hier eigentlich ankommt, entweder 1) im Obersatze die Stelle des Subjects und im Untersatze die Stelle des Prädicats, oder 2) in beiden Prämissen die Stelle des Prädicats, oder 3) in beiden die Stelle des Subjects, oder endlich 4) im Obersatze die Stelle des Prädicats und im Untersatze die Stelle des Subjects einnehmen. Durch diese vier Fälle ist der Unterschied der vier Figuren bestimmt. Es bezeichne _S_ das Subject der Conclusion, _P_ das Prädicat derselben und _M_ den _terminum medium_, so läßt sich das Schema für die gedachten vier Figuren in folgender Tafel darstellen:"}, {"type": "paragraph", "text": "_M P_ _S M_ _P M_ _S M_ _M P_ _M S_ _P M_ _M S_ _S P_ _S P_ _S P_ _S P_"}, {"type": "paragraph", "text": "§. 69. Regel für die erste Figur, als die einzig gesetzmäßige. Die Regel der ersten Figur ist: daß der Major ein allgemeiner, der Minor ein bejahender Satz sei. Und da dieses die allgemeine Regel aller kategorischen Vernunftschlüsse überhaupt sein muß: so ergiebt sich hieraus, daß die erste Figur die einzig gesetzmäßige sei, die allen übrigen zum Grunde liegt, und worauf alle übrigen, sofern sie Gültigkeit haben sollen, durch Umkehrung der Prämissen (_metathesin praemissorum_) zurückgeführt werden müssen."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Die erste Figur kann eine Conclusion von aller Quantität und Qualität haben. In den übrigen Figuren giebt es nur Conclusionen von gewisser Art; einige _modi_ derselben sind hier ausgeschlossen. Dies zeigt schon an, daß diese Figuren nicht vollkommen, sondern daß gewisse Einschränkungen dabei vorhanden sind, die es verhindern, daß die Conclusion nicht in allen _modis_, wie in der ersten Figur, stattfinden kann."}], "markers": [{"system": "AA", "band": "IX", "page": 125, "ref": "IX125"}, {"system": "AA", "band": "IX", "page": 126, "ref": "IX126"}], "running_header": "II. Vernunftschlüsse [§§ 56 - 80]"}, {"page_pdf": 2806, "page_book": 127, "page_kind": "body", "sigel": "AA IX, 127", "units": [{"type": "paragraph", "text": "§. 70. Bedingung der Reduction der drei letztern Figuren auf die erstere. Die Bedingung der Gültigkeit der drei letztern Figuren, unter welcher in einer jeden derselben ein richtiger Modus des Schließens möglich ist, läuft darauf hinaus: daß der Medius Terminus in den Sätzen eine solche Stelle erhalte, daraus durch unmittelbare Schlüsse (_consequentias immediatas_) die Stelle derselben nach den Regeln der ersten Figur entspringen kann. – Hieraus ergeben sich folgende Regeln für die drei letztern Figuren."}, {"type": "paragraph", "text": "§. 71. Regel der zweiten Figur. In der zweiten Figur steht der Minor recht, also muß der Major umgekehrt werden, und zwar so, daß er allgemein (_universalis_) bleibt. Dieses ist nur möglich, wenn er allgemein verneinend ist; ist er aber bejahend, so muß er contraponirt werden. In beiden Fällen wird die Conclusion negativ (_sequitur partem debiliorem_)."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Die Regel der zweiten Figur ist: Wem ein Merkmal eines Dinges widerspricht, das widerspricht der Sache selbst. Hier muß ich nun erst umkehren und sagen: Wem ein Merkmal widerspricht, das widerspricht diesem Merkmal, oder ich muß die Conclusion umkehren: Wem ein Merkmal eines Dinges widerspricht, dem widerspricht die Sache selbst, folglich widerspricht es der Sache."}, {"type": "paragraph", "text": "§. 72. Regel der dritten Figur. In der dritten Figur steht der Major recht, also muß der Minor umgekehrt werden; doch so, daß ein bejahender Satz daraus entspringt. Dieses aber ist nur möglich, indem der bejahende Satz particular ist, folglich ist die Conclusion particular."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Die Regel der dritten Figur ist: Was einem Merkmale zukommt oder widerspricht, das kommt auch zu oder widerspricht Einigen, unter denen dieses Merkmal enthalten ist. Hier muß ich erst sagen: Es kommt zu oder widerspricht Allen, die unter diesem Merkmal enthalten sind. §. 73. Regel der vierten Figur. Wenn in der vierten Figur der Major allgemein verneinend ist: so läßt er sich rein (_simpliciter_) umkehren, eben so der Minor als particular; also ist die Conclusion negativ. Ist hingegen der Major allgemein bejahend: so läßt er sich entweder nur _per accidens_ umkehren oder contraponiren; also ist die Conclusion entweder particular oder negativ. Soll die Conclusion nicht umgekehrt (_PS_ in _SP_ verwandelt) werden: so muß eine Versetzung der Prämissen (_metathesis praemissorum_) oder eine Umkehrung (_conversio_) beider geschehen."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. In der vierten Figur wird geschlossen: das Prädicat hängt am _medio termino_, der _medius _ _terminus_ am Subject (der Conclusion), folglich das Subject am Prädicat; welches aber gar nicht folgt, sondern allenfalls sein Umgekehrtes. Um dieses möglich zu machen, muß der _Major_ zum _Minor_ und _vice versa_ gemacht und die Conclusion umgekehrt werden, weil bei der erstern Veränderung _terminus minor_ in _majorem_ verwandelt wird."}, {"type": "paragraph", "text": "§. 74."}], "markers": [{"system": "AA", "band": "IX", "page": 127, "ref": "IX127"}, {"system": "AA", "band": "IX", "page": 128, "ref": "IX128"}], "running_header": "II. Vernunftschlüsse [§§ 56 - 80]"}, {"page_pdf": 2807, "page_book": 129, "page_kind": "body", "sigel": "AA IX, 129", "units": [{"type": "paragraph", "text": "Allgemeine Resultate über die drei letztern Figuren. Aus den angegebenen Regeln für die drei letztern Figuren erhellt, 1) daß in keiner derselben es eine allgemein bejahende Conclusion giebt, sondern daß die Conclusion immer entweder negativ oder particular ist; 2) daß in einer jeden ein unmittelbarer Schluß (_consequentia immediata_) eingemischt ist, der zwar nicht ausdrücklich bezeichnet wird, aber doch stillschweigend mit einverstanden werden muß, daß also auch um deswillen 3) alle diese drei letztern _modi_ des Schließens nicht reine, sondern unreine Schlüsse (_ratiocinia hybrida, impura_) genannt werden müssen, da jeder reine Schluß nicht mehr als drei Hauptsätze (_termini_) haben kann. §. 75. 2. Hypothetische Vernunftschlüsse. Ein hypothetischer Schluß ist ein solcher, der zum _Major_ einen hypothetischen Satz hat. Er besteht also aus zwei Sätzen, 1) einem Vordersatze (_antecedens_) und 2) einem Nachsatze (_consequens_), und es wird hier entweder nach dem _modo ponente_ oder dem _modo tollente_ gefolgert."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. Die hypothetischen Vernunftschlüsse haben also keinen _medium terminum_, sondern es wird bei denselben die Consequenz eines Satzes aus dem andern nur angezeigt. Es wird nämlich im _Major_ derselben die Consequenz zweier Sätze aus einander ausgedrückt, von denen der erste eine Prämisse, der zweite eine Conclusion ist. Der _Minor_ ist eine Verwandlung der problematischen Bedingung in einen kategorischen Satz. 2. Daraus daß der hypothetische Schluß nur aus zwei Sätzen besteht, ohne einen Mittelbegriff zu haben, ist zu ersehen: daß er eigentlich kein Vernunftschluß sei, sondern vielmehr nur ein unmittelbarer, aus einem Vordersatze und Nachsatze, der Materie oder der Form nach, zu erweisender Schluß (_consequentia _ _immediata demonstrabilis_ _[ex antecedente et consequente]_ _vel quoad materiam vel quoad formam_). Ein jeder Vernunftschluß soll ein Beweis sein. Nun führt aber der hypothetische nur den Beweis- Grund bei sich. Folglich ist auch hieraus klar, daß er kein Vernunftschluß sein könne."}, {"type": "paragraph", "text": "§. 76. Princip der hypothetischen Schlüsse. Das Princip der hypothetischen Schlüsse ist der Satz des Grundes: _A ratione ad _ _rationatum; a negatione rationati ad negationem rationis valet consequentia_."}, {"type": "paragraph", "text": "§. 77. 3. Disjunctive Vernunftschlüsse. In den disjunctiven Schlüssen ist der _Major_ ein disjunctiver Satz und muß daher, als solcher, Glieder der Eintheilung oder Disjunction haben. Es wird hier entweder 1) von der Wahrheit Eines Gliedes der Disjunction auf die Falschheit der übrigen geschlossen, oder 2) von der Falschheit aller Glieder, außer Einem, auf die Wahrheit dieses Einen. Jenes geschieht durch den _modum ponentem_ (oder _ponendo tollentem_), dieses durch den _modum tollentem_ (_tollendo ponentem_)."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. Alle Glieder der Disjunction, außer Einem, zusammengenommen, machen das contradictorische Gegentheil dieses Einen aus. Es findet also hier eine Dichotomie statt, nach welcher, wenn eines von beiden wahr ist, das andre falsch sein muß und umgekehrt. 2. Alle disjunctiven Vernunftschlüsse von mehr als zwei Gliedern der Disjunction sind also eigentlich polysyllogistisch. Denn alle wahre Disjunction kann nur _bimembris_ sein, und die logische Division"}], "markers": [{"system": "AA", "band": "IX", "page": 129, "ref": "IX129"}, {"system": "AA", "band": "IX", "page": 130, "ref": "IX130"}], "running_header": "II. Vernunftschlüsse [§§ 56 - 80]"}, {"page_pdf": 2808, "page_book": 131, "page_kind": "body", "sigel": "AA IX, 131", "units": [{"type": "paragraph", "text": "ist auch _bimembris_, aber die _membra subdividentia_ werden um der Kürze willen unter die _membra _ _dividentia_ gesetzt."}, {"type": "paragraph", "text": "§. 78. Princip der disjunctiven Vernunftschlüsse. Das Princip der disjunctiven Schlüsse ist der Grundsatz des ausschließenden Dritten: _A contradictorie oppositorum negatione unius ad affirmationem alterius_, _a positione unius ad _ _negationem alterius valet consequentia_."}, {"type": "paragraph", "text": "§. 79. Dilemma. Ein Dilemma ist ein hypothetisch-disjunctiver Vernunftschluß, oder ein hypothetischer Schluß, dessen _consequens_ ein disjunctives Urtheil ist. Der hypothetische Satz, dessen _consequens_ disjunctiv ist, ist der Obersatz; der Untersatz bejaht, daß das _consequens_ (_per omnia membra_) falsch ist, und der Schlußsatz bejaht, daß das _antecedens_ falsch sei. (_A remotione consequentis ad _ _negationem antecedentis valet consequentia_.)"}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Die Alten machten sehr viel aus dem Dilemma und nannten diesen Schluß _cornutus_. Sie wußten einen Gegner dadurch in die Enge zu treiben, daß sie alles hersagten, wo er sich hinwenden konnte und ihm dann auch alles widerlegten. Sie zeigten ihm viele Schwierigkeiten bei jeder Meinung, die er annahm. Aber es ist ein sophistischer Kunstgriff, Sätze nicht geradezu zu widerlegen, sondern nur Schwierigkeiten zu zeigen; welches denn auch bei vielen, ja bei den mehresten Dingen angeht. Wenn wir nun alles das sogleich für falsch erklären wollen, wobei sich Schwierigkeiten finden: so ist es ein leichtes Spiel, alles zu verwerfen. Zwar ist es gut, die Unmöglichkeit des Gegentheils zu zeigen, allein hierin liegt doch etwas Täuschendes, wofern man die Unbegreiflichkeit des Gegentheils für die Unmöglichkeit desselben hält. Die Dilemmata haben daher vieles Verfängliche an sich, ob sie gleich richtig schließen. Sie können gebraucht werden, wahre Sätze zu vertheidigen, aber auch wahre Sätze anzugreifen durch Schwierigkeiten, die man gegen sie aufwirft."}, {"type": "paragraph", "text": "§. 80. Förmliche und versteckte Vernunftschlüsse (_ratiocinia formalia_ und _cryptica._) Ein förmlicher Vernunftschluß ist ein solcher, der nicht nur der Materie nach alles Erforderliche enthält, sondern auch der Form nach richtig und vollständig ausgedrückt ist. Den förmlichen Vernunftschlüssen sind die versteckten (_cryptica_) entgegengesetzt, zu denen alle diejenigen können gerechnet werden, in welchen entweder die Prämissen versetzt, oder eine der Prämissen ausgelassen, oder endlich der Mittelbegriff allein mit der Conclusion verbunden ist. Ein versteckter Vernunftschluß von der zweiten Art, in welchem die eine Prämisse nicht ausgedrückt, sondern nur mit gedacht wird, heißt ein verstümmelter oder ein Enthymema. Die der dritten Art werden zusammengezogene Schlüsse genannt."}], "markers": [{"system": "AA", "band": "IX", "page": 131, "ref": "IX131"}], "running_header": "II. Vernunftschlüsse [§§ 56 - 80]"}, {"page_pdf": 2809, "page_book": 131, "page_kind": "body", "sigel": "AA IX, 131", "units": [{"type": "heading", "text": "[Dritter Abschnitt. Von den Schlüssen.]", "level": 2}, {"type": "paragraph", "text": "III. Schlüsse der Urtheilskraft. [§§ 81-93] §. 81. Bestimmende und reflectirende Urtheilskraft. Die Urtheilskraft ist zwiefach: die bestimmende oder die reflectirende Urtheilskraft. Die erstere geht vom Allgemeinen zum Besondern, die zweite vom Besondern zum Allgemeinen. Die letztere hat nur subjective Gültigkeit, denn das Allgemeine, zu welchem sie vom Besondern fortschreitet, ist nur empirische Allgemeinheit – ein bloßes Analogon der logischen."}, {"type": "paragraph", "text": "§. 82. Schlüsse der (reflectirenden) Urtheilskraft. Die Schlüsse der Urtheilskraft sind gewisse Schlußarten, aus besondern Begriffen zu allgemeinen zu kommen. Es sind also nicht Functionen der bestimmenden, sondern der reflectirenden Urtheilskraft; mithin bestimmen sie auch nicht das Object, sondern nur die Art der Reflexion über dasselbe, um zu seiner Kenntniß zu gelangen."}, {"type": "paragraph", "text": "§. 83. Princip dieser Schlüsse. Das Princip, welches den Schlüssen der Urtheilskraft zum Grunde liegt, ist dieses: daß Vieles nicht ohne einen gemeinschaftlichen Grund in Einem zusammenstimmen, sondern daß das, was Vielem auf diese Art zukommt, aus einem gemeinschaftlichen Grunde nothwendig sein werde."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Da den Schlüssen der Urtheilskraft ein solches Princip zum Grunde liegt, so können sie um deswillen nicht für unmittelbare Schlüsse gehalten werden."}, {"type": "paragraph", "text": "§. 84. Induction und Analogie – die beiden Schlußarten der Urtheilskraft. Die Urtheilskraft, indem sie vom Besondern zum Allgemeinen fortschreitet, um aus der Erfahrung, mithin nicht _a priori_ (empirisch) allgemeine Urtheile zu ziehen, schließt entweder von vielen auf alle Dinge einer Art, oder von vielen Bestimmungen und Eigenschaften, worin Dinge von einerlei Art zusammenstimmen, auf die übrigen, sofern sie zu demselben Princip gehören. Die erstere Schlußart heißt der Schluß durch Induction, die andre der Schluß nach der Analogie."}, {"type": "paragraph", "text": "—————— Anmerkung 1. Die Induction schließt also vom Besondern aufs Allgemeine (_a particulari ad universale_) nach dem Princip der Allgemeinmachung: Was vielen Dingen einer Gattung zukommt, das kommt auch den übrigen zu. Die Analogie schließt von particularer Ähnlichkeit zweier Dinge auf totale, nach dem Princip der Specification: Dinge von einer Gattung, von denen man vieles Übereinstimmende kennt, stimmen auch in dem Übrigen überein, was wir in einigen dieser Gattung kennen, an andern aber nicht wahrnehmen. Die Induction erweitert das empirisch Gegebene vom Besondern aufs Allgemeine in Ansehung vieler Gegenstände, die Analogie dagegen die gegebenen Eigenschaften eines Dinges auf mehrere eben desselben Dinges – Eines in Vielen, also in Allen: Induction, Vieles in Einem (was auch in Andern ist), also auch das Übrige in demselben: Analogie. So ist z.B. der Beweisgrund für die Unsterblichkeit aus der völligen Entwickelung der Naturanlagen eines jeden Geschöpfs ein Schluß nach der Analogie."}], "markers": [{"system": "AA", "band": "IX", "page": 131, "ref": "IX131"}, {"system": "AA", "band": "IX", "page": 132, "ref": "IX132"}, {"system": "AA", "band": "IX", "page": 133, "ref": "IX133"}], "running_header": "III. Schlüsse der Urtheilskraft [§§ 81 - 93]"}, {"page_pdf": 2810, "page_book": 134, "page_kind": "body", "sigel": "AA IX, 134", "units": [{"type": "paragraph", "text": "Bei dem Schlusse nach der Analogie wird indessen nicht die Identität des Grundes (_par ratio_) erfordert. Wir schließen nach der Analogie nur auf vernünftige Mondbewohner, nicht auf Menschen. Auch kann man nach der Analogie nicht über das _tertium comparationis_ hinaus schließen. 2. Ein jeder Vernunftschluß muß Nothwendigkeit geben. Induction und Analogie sind daher keine Vernunftschlüsse, sondern nur logische Präsumtionen oder auch empirische Schlüsse; und durch Induction bekommt man wohl generale, aber nicht universale Sätze. 3. Die gedachten Schlüsse der Urtheilskraft sind nützlich und unentbehrlich zum Behuf der Erweiterung unsers Erfahrungserkenntnisses. Da sie aber nur empirische Gewißheit geben: so müssen wir uns ihrer mit Behutsamkeit und Vorsicht bedienen."}, {"type": "paragraph", "text": "§. 85. Einfache und zusammengesetzte Vernunftschlüsse. Ein Vernunftschluß heißt einfach, wenn er nur aus einem, zusammengesetzt, wenn er aus mehreren Vernunftschlüssen besteht."}, {"type": "paragraph", "text": "§. 86. _Ratiocinatio polysyllogistica._ Ein zusammengesetzter Schluß, in welchem die mehreren Vernunftschlüsse nicht durch bloße Coordination, sondern durch Subordination, d.h. als Gründe und Folgen mit einander verbunden sind, wird eine Kette von Vernunftschlüssen genannt (_ratiocinatio polysyllogistica_)."}, {"type": "paragraph", "text": "§. 87. Prosyllogismen und Episyllogismen. In der Reihe zusammengesetzter Schlüsse kann man auf eine doppelte Art, entweder von den Gründen herab zu den Folgen, oder von den Folgen herauf zu den Gründen schließen. Das erste geschieht durch Episyllogismen, das andre durch Prosyllogismen. Ein Episyllogismus ist nämlich derjenige Schluß in der Reihe von Schlüssen, dessen Prämisse die Conclusion eines Prosyllogismus, also eines Schlusses wird, welcher die Prämisse des erstern zur Conclusion hat."}, {"type": "paragraph", "text": "§. 88. Sorites oder Kettenschluß. Ein aus mehreren abgekürzten und unter einander zu einer Conclusion verbundenen Schlüssen bestehender Schluß heißt ein Sorites oder Kettenschluß, der entweder progressiv oder regressiv sein kann; je nachdem man von den nähern Gründen zu den entferntern hinauf-, oder von den entferntern Gründen zu den nähern herabsteigt."}, {"type": "paragraph", "text": "§. 89. Kategorische und hypothetische Sorites. Die progressiven sowohl als die regressiven Kettenschlüsse können hinwiederum entweder kategorische oder hypothetische sein. Jene bestehen aus kategorischen Sätzen als einer Reihe von Prädicaten, diese aus hypothetischen, als einer Reihe von Consequenzen."}, {"type": "paragraph", "text": "§. 90. Trugschluß – Paralogismus – Sophisma. Ein Vernunftschluß, welcher der Form nach falsch ist, ob er gleich den Schein eines richtigen Schlusses für sich hat, heißt ein Trugschluß (_fallacia_). Ein solcher Schluß ist ein Paralogismus, in so fern man sich selbst dadurch hintergeht, ein Sophisma, sofern man Andre dadurch mit Absicht zu hintergehen sucht."}, {"type": "paragraph", "text": "——————"}], "markers": [{"system": "AA", "band": "IX", "page": 134, "ref": "IX134"}, {"system": "AA", "band": "IX", "page": 135, "ref": "IX135"}], "running_header": "III. Schlüsse der Urtheilskraft [§§ 81 - 93]"}, {"page_pdf": 2811, "page_book": 136, "page_kind": "body", "sigel": "AA IX, 136", "units": [{"type": "paragraph", "text": "Anmerkung. Die Alten beschäftigten sich sehr mit der Kunst, dergleichen Sophismen zu machen. Daher sind viele von der Art aufgekommen; z.B. das _Sophisma figurae dictionis,_ worin der _medius terminus_ in verschiedener Bedeutung genommen wird – _fallacia a dicto secundum quid ad dictum simpliciter_, _sophisma heterozeteseos, elenchi, ignorationis_ u.dgl.m."}, {"type": "paragraph", "text": "§. 91. Sprung im Schließen. Ein Sprung (_saltus_) im Schließen oder Beweisen ist die Verbindung einer Prämisse mit der Conclusion, so daß die andre Prämisse ausgelassen wird. Ein solcher Sprung ist rechtmäßig (_legitimus_), wenn ein Jeder die fehlende Prämisse leicht hinzudenken kann, unrechtmäßig (_illegitimus_) aber, wenn die Subsumtion nicht klar ist. Es wird hier ein entferntes Merkmal mit einer Sache ohne Zwischenmerkmal (_nota intermedia_) verknüpft."}, {"type": "paragraph", "text": "§. 92. _Petitio principii. – Circulus in probando_ . Unter einer _petitio principii_ versteht man die Annehmung eines Satzes zum Beweisgrunde als eines unmittelbar gewissen Satzes, obgleich er noch eines Beweises bedarf. Und einen Cirkel im Beweisen begeht man, wenn man denjenigen Satz, den man hat beweisen wollen, seinem eigenen Beweise zum Grunde legt."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Der Cirkel im Beweisen ist oft schwer zu entdecken, und dieser Fehler wird gerade da gemeiniglich am häufigsten begangen, wo die Beweise schwer sind. §. 93. _Probatio plus_ und _minus probans_. Ein Beweis kann zu viel, aber auch zu wenig beweisen. Im letztern Falle beweist er nur einen Theil von dem, was bewiesen werden soll, im erstern geht er auch auf das, welches falsch ist."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Ein Beweis, der zu wenig beweist, kann wahr sein und ist also nicht zu verwerfen. Beweist er aber zu viel: so beweist er mehr, als was wahr ist; und das ist denn falsch. So beweist z.B. der Beweis wider den Selbstmord: daß, wer sich nicht das Leben gegeben, es sich auch nicht nehmen könne, zu viel; denn aus diesem Grunde dürften wir auch keine Thiere tödten. Er ist also falsch."}, {"type": "paragraph", "text": "——————"}], "markers": [{"system": "AA", "band": "IX", "page": 136, "ref": "IX136"}], "running_header": "III. Schlüsse der Urtheilskraft [§§ 81 - 93]"}, {"page_pdf": 2812, "page_book": 137, "page_kind": "title_page", "sigel": "AA IX, 137", "units": [{"type": "paragraph", "text": "II. Allgemeine Methodenlehre."}], "markers": [{"system": "AA", "band": "IX", "page": 137, "ref": "IX137"}]}, {"page_pdf": 2813, "page_book": 139, "page_kind": "body", "sigel": "AA IX, 139", "units": [{"type": "paragraph", "text": "[Allgemeine Methodenlehre.] [§§ 94-98] §. 94. Manier und Methode. Alle Erkenntniß und ein Ganzes derselben muß einer Regel gemäß sein. (Regellosigkeit ist zugleich Unvernunft.) Aber diese Regel ist entweder die der Manier (frei) oder die der Methode (Zwang)."}, {"type": "paragraph", "text": "§. 95. Form der Wissenschaft. – Methode. Die Erkenntniß, als Wissenschaft, muß nach einer Methode eingerichtet sein. Denn Wissenschaft ist ein Ganzes der Erkenntniß als System und nicht bloß als Aggregat. Sie erfordert daher eine systematische, mithin nach überlegten Regeln abgefaßte Erkenntniß."}, {"type": "paragraph", "text": "§. 96. Methodenlehre. – Gegenstand und Zweck derselben. Wie die Elementarlehre in der Logik die Elemente und Bedingungen der Vollkommenheit einer Erkenntniß zu ihrem Inhalt hat: so hat dagegen die allgemeine Methodenlehre, als der andre Theil der Logik, von der Form einer Wissenschaft überhaupt, oder von der Art und Weise zu handeln, das Mannigfaltige der Erkenntniß zu einer Wissenschaft zu verknüpfen."}, {"type": "paragraph", "text": "§. 97. Mittel zu Beförderung der logischen Vollkommenheit der Erkenntniß. Die Methodenlehre soll die Art vortragen, wie wir zur Vollkommenheit des Erkenntnisses gelangen. Nun besteht eine der wesentlichsten logischen Vollkommenheiten des Erkenntnisses in der Deutlichkeit, der Gründlichkeit und systematischen Anordnung derselben zum Ganzen einer Wissenschaft. Die Methodenlehre wird demnach hauptsächlich die Mittel anzugeben haben, durch welche diese Vollkommenheiten des Erkenntnisses befördert werden."}, {"type": "paragraph", "text": "§. 98. Bedingungen der Deutlichkeit des Erkenntnisses. Die Deutlichkeit der Erkenntnisse und ihre Verbindung zu einem systematischen Ganzen hängt ab von der Deutlichkeit der Begriffe sowohl in Ansehung dessen, was in ihnen, als in Rücksicht auf das, was unter ihnen enthalten ist. Das deutliche Bewußtsein des Inhalts der Begriffe wird befördert durch Exposition und Definition derselben, das deutliche Bewußtsein ihres Umfanges dagegen durch die logische Eintheilung derselben. – Zuerst also hier von den Mitteln zu Beförderung der Deutlichkeit der Begriffe in Ansehung ihres Inhalts."}], "markers": [{"system": "AA", "band": "IX", "page": 139, "ref": "IX139"}, {"system": "AA", "band": "IX", "page": 140, "ref": "IX140"}], "running_header": "Methodenlehre [§ 94 - 98]"}, {"page_pdf": 2814, "page_book": 140, "page_kind": "body", "sigel": "AA IX, 140", "units": [{"type": "paragraph", "text": "[Allgemeine Methodenlehre.] I. Beförderung der logischen Vollkommenheit des Erkenntnisses durch Definition, Exposition und Beschreibung der Begriffe. [§§ 99-109] §. 99. Definition. Eine Definition ist ein zureichend deutlicher und abgemessener Begriff (_conceptus rei _ _adaequatus in minimis terminis,_ _complete determinatus_)."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Die Definition ist allein als ein logisch vollkommener Begriff anzusehen, denn es vereinigen sich in ihr die beiden wesentlichsten Vollkommenheiten eines Begriffs: die Deutlichkeit und die Vollständigkeit und Präcision in der Deutlichkeit (Quantität der Deutlichkeit)."}, {"type": "paragraph", "text": "§. 100. Analytische und synthetische Definition. Alle Definitionen sind entweder analytisch oder synthetisch. Die erstern sind Definitionen eines gegebenen, die letztern Definitionen eines gemachten Begriffs."}, {"type": "paragraph", "text": "§. 101. Gegebene und gemachte Begriffe _a priori_ und _a posteriori_. Die gegebenen Begriffe einer analytischen Definition sind entweder _a priori_ oder _a posteriori_ gegeben; so wie die gemachten Begriffe einer synthetischen Definition entweder _a priori_ oder _a _ _posteriori_ gemacht sind."}, {"type": "paragraph", "text": "§. 102. Synthetische Definitionen durch Exposition oder Construction. Die Synthesis der gemachten Begriffe, aus welcher die synthetischen Definitionen entspringen, ist entweder die der Exposition (der Erscheinungen) oder die der Construction. Die letztere ist die Synthesis willkürlich gemachter, die erstere, die Synthesis empirisch, – d.h. aus gegebenen Erscheinungen, als der Materie derselben, gemachter Begriffe (_conceptus factitii vel a _ _priori vel per synthesin empiricam_). Willkürlich gemachte Begriffe sind die mathematischen."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Alle Definitionen der mathematischen und – wofern anders bei empirischen Begriffen überall Definitionen stattfinden könnten – auch der Erfahrungsbegriffe, müssen also synthetisch gemacht werden. Denn auch bei den Begriffen der letztern Art, z.B. den empirischen Begriffen Wasser, Feuer, Luft u.dgl. soll ich nicht zergliedern, was in ihnen liegt, sondern durch Erfahrung kennen lernen, was zu ihnen gehört. Alle empirischen Begriffe müssen also als gemachte Begriffe angesehen werden, deren Synthesis aber nicht willkürlich, sondern empirisch ist."}, {"type": "paragraph", "text": "§. 103. Unmöglichkeit empirisch synthetischer Definitionen. Da die Synthesis der empirischen Begriffe nicht willkürlich, sondern empirisch ist und als solche niemals vollständig sein kann (weil man in der Erfahrung immer noch mehr Merkmale des Begriffs entdecken kann): so können empirische Begriffe auch nicht definirt werden."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Synthetisch lassen sich also nur willkürliche Begriffe definiren. Solche Definitionen willkürlicher Begriffe, die nicht nur immer möglich, sondern auch nothwendig sind, und vor alle dem,"}], "markers": [{"system": "AA", "band": "IX", "page": 140, "ref": "IX140"}, {"system": "AA", "band": "IX", "page": 141, "ref": "IX141"}, {"system": "AA", "band": "IX", "page": 142, "ref": "IX142"}], "running_header": "I. Befördg. d. log. Vollkommenheit d. Erkenntnisses durch Definition, Exposition und Beschreibung der Begriffe [§§ 99 -109]"}, {"page_pdf": 2815, "page_book": 143, "page_kind": "body", "sigel": "AA IX, 143", "units": [{"type": "paragraph", "text": "was vermittelst eines willkürlichen Begriffs gesagt wird, vorangehen müssen, könnte man auch Declarationen nennen, sofern man dadurch seine Gedanken declarirt oder Rechenschaft von dem giebt, was man unter einem Worte versteht. Dies ist der Fall bei den Mathematikern."}, {"type": "paragraph", "text": "§. 104. Analytische Definitionen durch Zergliederung _a priori_ oder _a posteriori_ gegebene Begriffe. Alle gegebenen Begriffe, sie mögen _a priori_ oder _a posteriori_ gegeben sein, können nur durch Analysis definirt werden. Denn gegebene Begriffe kann man nur deutlich machen, sofern man die Merkmale derselben successiv klar macht. Werden alle Merkmale eines gegebenen Begriffs klar gemacht: so wird der Begriff vollständig deutlich, enthält er auch nicht zu viel Merkmale, so ist er zugleich präcis und es entspringt hieraus eine Definition des Begriffs."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Da man durch keine Probe gewiß werden kann, ob man alle Merkmale eines gegebenen Begriffs durch vollständige Analyse erschöpft habe: so sind alle analytischen Definitionen für unsicher zu halten."}, {"type": "paragraph", "text": "§. 105. Erörterungen und Beschreibungen. Nicht alle Begriffe können also, sie dürfen aber auch nicht alle definirt werden. Es giebt Annäherungen zur Definition gewisser Begriffe; dieses sind theils Erörterungen (_expositiones_), theils Beschreibungen (_descriptiones_). Das Exponiren eines Begriffs besteht in der an einander hängenden (successiven) Vorstellung seiner Merkmale, so weit dieselben durch Analyse gefunden sind. Die Beschreibung ist die Exposition eines Begriffs, sofern sie nicht präcis ist."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. Wir können entweder einen Begriff oder die Erfahrung exponiren. Das erste geschieht durch Analysis, das zweite durch Synthesis. 2. Die Exposition findet also nur bei gegebenen Begriffen statt, die dadurch deutlich gemacht werden, sie unterscheidet sich dadurch von der Declaration, die eine deutliche Vorstellung gemachter Begriffe ist. Da es nicht immer möglich ist, die Analysis vollständig zu machen, und da überhaupt eine Zergliederung, ehe sie vollständig wird, erst unvollständig sein muß: so ist auch eine unvollständige Exposition, als Theil einer Definition, eine wahre und brauchbare Darstellung eines Begriffs. Die Definition bleibt hier immer nur die Idee einer logischen Vollkommenheit, die wir zu erlangen suchen müssen. 3. Die Beschreibung kann nur bei empirisch gegebenen Begriffen stattfinden. Sie hat keine bestimmten Regeln und enthält nur die Materialien zur Definition."}, {"type": "paragraph", "text": "§. 106. Nominal- und Real-Definitionen. Unter bloßen Namen-Erklärungen oder Nominal-Definitionen sind diejenigen zu verstehen, welche die Bedeutung enthalten, die man willkürlich einem gewissen Namen hat geben wollen, und die daher nur das logische Wesen ihres Gegenstandes bezeichnen, oder bloß zu Unterscheidung desselben von andern Objecten dienen. Sach-Erklärungen oder Real-Definitionen hingegen sind solche, die zur Erkenntniß des Objects, seinen innern Bestimmungen nach, zureichen, indem sie die Möglichkeit des Gegenstandes aus innern Merkmalen darlegen."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "but insofar as they make use of concepts given in their matter, aren’t they undeﬁnable? for example, call a unicorn a horse + a horn. both of these concepts are analyzable in indeﬁnitum; we can never be sure to have exhausted them. so even though my deifnition is perfect at the level of arbitrary stipulation, it is as obscure as its elements"}], "markers": [{"system": "AA", "band": "IX", "page": 143, "ref": "IX143"}], "running_header": "I. Befördg. d. log. Vollkommenheit d. Erkenntnisses durch Definition, Exposition und Beschreibung der Begriffe [§§ 99 -109]"}, {"page_pdf": 2816, "page_book": 144, "page_kind": "body", "sigel": "AA IX, 144", "units": [{"type": "paragraph", "text": "Anmerkung 1. Wenn ein Begriff innerlich zureichend ist, die Sache zu unterscheiden, so ist er es auch gewiß äußerlich, wenn er aber innerlich nicht zureichend ist: so kann er doch bloß in gewisser Beziehung äußerlich zureichend sein, nämlich in der Vergleichung des Definitums mit andern. Allein die unumschränkte äußere Zulänglichkeit ist ohne die innere nicht möglich. 2. Erfahrungsgegenstände erlauben bloß Nominalerklärungen. Logische Nominal-Definitionen gegebener Verstandesbegriffe sind von einem Attribut hergenommen, Real-Definitionen hingegen aus dem Wesen der Sache, dem ersten Grunde der Möglichkeit. Die letztern enthalten also das, was jederzeit der Sache zukommt – das Realwesen derselben. Bloß verneinende Definitionen können auch keine Real-Definitionen heißen, weil verneinende Merkmale wohl zur Unterscheidung einer Sache von andern eben so gut dienen können als bejahende, aber nicht zur Erkenntniß der Sache ihrer innern Möglichkeit nach. In Sachen der Moral müssen immer Real-Definitionen gesucht werden, dahin muß alles unser Bestreben gerichtet sein. Real-Definitionen giebt es in der Mathematik, denn die Definition eines willkürlichen Begriffs ist immer real. 3. Eine Definition ist genetisch, wenn sie einen Begriff giebt, durch welchen der Gegenstand _a priori_ _in _ _concreto_ kann dargestellt werden; dergleichen sind alle mathematischen Definitionen."}, {"type": "paragraph", "text": "§. 107. Haupterfordernisse der Definition. Die wesentlichen und allgemeinen Erfordernisse, die zur Vollkommenheit einer Definition überhaupt gehören, lassen sich unter den vier Hauptmomenten der Quantität, Qualität, Relation und Modalität betrachten: 1) der Quantität nach – was die Sphäre der Definition betrifft – müssen die Definition und das Definitum Wechselbegriffe (_conceptus reciproci_), und mithin die Definition weder weiter noch enger sein als ihr Definitum, 2) der Qualität nach muß die Definition ein ausführlicher und zugleich präciser Begriff sein, 3) der Relation nach muß sie nicht tautologisch, d.i. die Merkmale des Definitums müssen, als Erkenntnißgründe desselben, von ihm selbst verschieden sein, und endlich 4) der Modalität nach müssen die Merkmale nothwendig und also nicht solche sein, die durch Erfahrung hinzukommen."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Die Bedingung: daß der Gattungsbegriff und der Begriff des specifischen Unterschiedes (_genus_ und _differentia specifica_) die Definition ausmachen sollen, gilt nur in Ansehung der Nominal-Definitionen in der Vergleichung, aber nicht für die Real-Definitionen in der Ableitung."}, {"type": "paragraph", "text": "§. 108. Regeln zu Prüfung der Definitionen. Bei Prüfung der Definitionen sind vier Handlungen zu verrichten; es ist nämlich dabei zu untersuchen: ob die Definition 1) als ein Satz betrachtet, wahr sei, ob sie 2) als ein Begriff, deutlich sei, 3) ob sie als ein deutlicher Begriff auch ausführlich, und endlich 4) als ein ausführlicher Begriff zugleich bestimmt, d.i. der Sache selbst adäquat sei."}, {"type": "paragraph", "text": "§. 109. Regeln zu Verfertigung der Definitionen. Eben dieselben Handlungen, die zu Prüfung der Definition gehören, sind nun auch beim Verfertigen derselben zu verrichten. Zu diesem Zweck suche also: 1) wahre Sätze, 2) solche, deren Prädicat den Begriff der Sache nicht schon voraussetzt, 3) sammle deren mehrere und"}], "markers": [{"system": "AA", "band": "IX", "page": 144, "ref": "IX144"}, {"system": "AA", "band": "IX", "page": 145, "ref": "IX145"}], "running_header": "I. Befördg. d. log. Vollkommenheit d. Erkenntnisses durch Definition, Exposition und Beschreibung der Begriffe [§§ 99 -109]"}, {"page_pdf": 2817, "page_book": 144, "page_kind": "body", "sigel": "AA IX, 144", "units": [{"type": "paragraph", "text": "vergleiche sie mit dem Begriffe der Sache selbst, ob sie adäquat sei, und endlich 4) siehe zu, ob nicht ein Merkmal im andern liege oder demselben subordinirt sei."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. Diese Regeln gelten, wie sich auch wohl ohne Erinnerung versteht, nur von analytischen Definitionen. Da man nun hier nie gewiß sein kann, ob die Analyse vollständig gewesen: so darf man die Definition auch nur als Versuch aufstellen und sich ihrer nur so bedienen, als wäre sie keine Definition. Unter dieser Einschränkung kann man sie doch als einen deutlichen und wahren Begriff brauchen und aus den Merkmalen desselben Corollarien ziehen. Ich werde nämlich sagen können: dem der Begriff des Definitums zukommt, kommt auch die Definition zu, aber freilich nicht umgekehrt, da die Definition nicht das ganze Definitum erschöpft. 2. Sich des Begriffs vom Definitum bei der Erklärung bedienen, oder das Definitum bei der Definition zum Grunde legen, heißt durch einen Cirkel erklären (_circulus in definiendo_)."}], "running_header": "I. Befördg. d. log. Vollkommenheit d. Erkenntnisses durch Definition, Exposition und Beschreibung der Begriffe [§§ 99 -109]"}, {"page_pdf": 2818, "page_book": 146, "page_kind": "body", "sigel": "AA IX, 146", "units": [{"type": "heading", "text": "[Allgemeine Methodenlehre.]", "level": 2}, {"type": "paragraph", "text": "II. Beförderung der Vollkommenheit des Erkenntnisses durch logische Eintheilung der Begriffe. [§§ 110-120] §. 110. Begriff der logischen Eintheilung. Ein jeder Begriff enthält ein Mannigfaltiges unter sich, in so fern es übereinstimmt, aber auch, in so fern es verschieden ist. Die Bestimmung eines Begriffs in Ansehung alles Möglichen, was unter ihm enthalten ist, sofern es einander entgegengesetzt, d.i. von einander unterschieden ist, heißt die logische Eintheilung des Begriffs. Der höhere Begriff heißt der eingetheilte Begriff (_divisum_), und die niedrigern Begriffe die Glieder der Eintheilung (_membra dividentia_)."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. Einen Begriff theilen und ihn eintheilen ist also sehr verschieden. Bei der Theilung des Begriffs sehe ich, was in ihm enthalten ist (durch Analyse), bei der Eintheilung betrachte ich, was unter ihm enthalten ist. Hier theile ich die Sphäre des Begriffs, nicht den Begriff selbst ein. Weit gefehlt also, daß die Eintheilung eine Theilung des Begriffs sei: so enthalten vielmehr die Glieder der Eintheilung mehr in sich als der eingetheilte Begriff. 2. Wir gehen von niedrigern zu höhern Begriffen hinauf und nachher können wir wieder von diesen zu niedrigern herabgehen – durch Eintheilung."}, {"type": "paragraph", "text": "§. 111. Allgemeine Regeln der logischen Eintheilung. Bei jeder Eintheilung eines Begriffs ist darauf zu sehen: 1) daß die Glieder der Eintheilung sich ausschließen oder einander entgegengesetzt seien, daß sie ferner 2) unter Einen höhern Begriff (_conceptum communem_) gehören, und daß sie endlich 3) alle zusammengenommen die Sphäre des eingetheilten Begriffs ausmachen oder derselben gleich seien."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Die Glieder der Eintheilung müssen durch contradictorische Entgegensetzung, nicht durch ein bloßes Widerspiel (_contrarium_) von einander getrennt sein."}, {"type": "paragraph", "text": "§. 112. Codivision und Subdivision. Verschiedene Eintheilungen eines Begriffes, die in verschiedener Absicht gemacht werden, heißen Nebeneintheilungen, und die Eintheilung der Glieder der Eintheilung wird eine Untereintheilung (_subdivisio_) genannt."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. Die Subdivision kann ins Unendliche fortgesetzt werden, comparativ aber kann sie endlich sein. Die Codivision geht auch, besonders bei Erfahrungsbegriffen, ins Unendliche; denn wer kann alle Relationen der Begriffe erschöpfen? 2. Man kann die Codivision auch eine Eintheilung nach Verschiedenheit der Begriffe von demselben Gegenstande (Gesichtspunkte), so wie die Subdivision eine Eintheilung der Gesichtspunkte selbst nennen."}, {"type": "paragraph", "text": "§. 113. Dichotomie und Polytomie."}], "markers": [{"system": "AA", "band": "IX", "page": 146, "ref": "IX146"}, {"system": "AA", "band": "IX", "page": 147, "ref": "IX147"}], "running_header": "II. Befördg. d. Vollkommenheit d. Erkenntnisses durch logische Eintheilung der Begriffe [§§ 110 - 120]"}, {"page_pdf": 2819, "page_book": 148, "page_kind": "body", "sigel": "AA IX, 148", "units": [{"type": "paragraph", "text": "Eine Eintheilung in zwei Glieder heißt Dichotomie; wenn sie aber mehr als zwei Glieder hat, wird sie Polytomie genannt."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung 1. Alle Polytomie ist empirisch, die Dichotomie ist die einzige Eintheilung aus Principien _a _ _priori_, also die einzige primitive Eintheilung. Denn die Glieder der Eintheilung sollen einander entgegengesetzt sein und von jedem _A_ ist doch das Gegentheil nichts mehr als _non A_. 2. Polytomie kann in der Logik nicht gelehrt werden, denn dazu gehört Erkenntniß des Gegenstandes. Dichotomie aber bedarf nur des Satzes des Widerspruchs, ohne den Begriff, den man eintheilen will, dem Inhalte nach, zu kennen. Die Polytomie bedarf Anschauung; entweder _a _ _priori_, wie in der Mathematik (z.B. die Eintheilung der Kegelschnitte), oder empirische Anschauung, wie in der Naturbeschreibung. Doch hat die Eintheilung aus dem Princip der Synthesis _a priori_ Trichotomie, nämlich: 1) den Begriff als die Bedingung, 2) das Bedingte, und 3) die Ableitung des letztern aus dem erstern."}, {"type": "paragraph", "text": "§. 114. Verschiedene Eintheilungen der Methode. Was nun insbesondre noch die Methode selbst bei Bearbeitung und Behandlung wissenschaftlicher Erkenntnisse betrifft: so giebt es verschiedene Hauptarten derselben, die wir nach folgender Eintheilung hier angeben können."}, {"type": "paragraph", "text": "§. 115. 1. Scientifische oder populare Methode. Die scientifische oder scholastische Methode unterscheidet sich von der popularen dadurch, daß jene von Grund- und Elementar-Sätzen, diese hingegen vom Gewöhnlichen und Interessanten ausgeht. Jene geht auf Gründlichkeit und entfernt daher alles Fremdartige, diese zweckt auf Unterhaltung ab."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Diese beiden Methoden unterscheiden sich also der Art und nicht dem bloßen Vortrage nach, und Popularität in der Methode ist mithin etwas anders als Popularität im Vortrage."}, {"type": "paragraph", "text": "§. 116. 2. Systematische oder fragmentarische Methode. Die systematische Methode ist der fragmentarischen oder rhapsodistischen entgegengesetzt. Wenn man nach einer Methode gedacht hat, und sodann diese Methode auch im Vortrage ausgedrückt und der Übergang von einem Satze zum andern deutlich angegeben ist, so hat man ein Erkenntniß systematisch behandelt. Hat man dagegen nach einer Methode zwar gedacht, den Vortrag aber nicht methodisch eingerichtet: so ist eine solche Methode rhapsodistisch zu nennen."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Der systematische Vortrag wird dem fragmentarischen, so wie der methodische dem tumultuarischen entgegengesetzt. Der methodisch denkt, kann nämlich systematisch oder fragmentarisch vortragen. Der äußerlich fragmentarische, an sich aber methodische Vortrag ist aphoristisch."}, {"type": "paragraph", "text": "§. 117. 3. Analytische oder synthetische Methode. Die analytische Methode ist der synthetischen entgegengesetzt. Jene fängt von dem Bedingten und Begründeten an und geht zu den Principien fort (_a principiatis ad principia_), diese hingegen geht von den Principien zu den Folgen oder vom Einfachen zum Zusammengesetzten."}], "markers": [{"system": "AA", "band": "IX", "page": 148, "ref": "IX148"}, {"system": "AA", "band": "IX", "page": 149, "ref": "IX149"}], "running_header": "II. Befördg. d. Vollkommenheit d. Erkenntnisses durch logische Eintheilung der Begriffe [§§ 110 - 120]"}, {"page_pdf": 2820, "page_book": 150, "page_kind": "body", "sigel": "AA IX, 150", "units": [{"type": "paragraph", "text": "Die erstere könnte man auch die regressive, so wie die letztere die progressive nennen."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Die analytische Methode heißt auch sonst die Methode des Erfindens. Für den Zweck der Popularität ist die analytische, für den Zweck der wissenschaftlichen und systematischen Bearbeitung des Erkenntnisses aber ist die synthetische Methode angemessener."}, {"type": "paragraph", "text": "§. 118. 4. Syllogistische – Tabellarische Methode. Die syllogistische Methode ist diejenige, nach welcher in einer Kette von Schlüssen eine Wissenschaft vorgetragen wird. Tabellarisch heißt diejenige Methode, nach welcher ein schon fertiges Lehrgebäude in seinem ganzen Zusammenhange dargestellt wird."}, {"type": "paragraph", "text": "§. 119. 5. Akroamatische oder erotematische Methode. Akroamatisch ist die Methode, sofern Jemand allein lehrt, erotematisch, sofern er auch frägt. Die letztere Methode kann hinwiederum in die dialogische oder sokratische und in die katechetische eingetheilt werden, je nachdem die Fragen entweder an den Verstand, oder bloß an das Gedächtniß gerichtet sind."}, {"type": "paragraph", "text": "——————"}, {"type": "paragraph", "text": "Anmerkung. Erotematisch kann man nicht anders lehren als durch den Sokratischen Dialog, in welchem sich beide fragen und auch wechselsweise antworten müssen, so daß es scheint, als sei auch der Schüler selbst Lehrer. Der Sokratische Dialog lehrt nämlich durch Fragen, indem er den Lehrling seine eigenen Vernunftprincipien kennen lehrt und ihm die Aufmerksamkeit darauf schärft. Durch die gemeine Katechese aber kann man nicht lehren, sondern nur das, was man akroamatisch gelehrt hat, abfragen. Die katechetische Methode gilt daher auch nur für empirische und historische, die dialogische dagegen für rationale Erkenntnisse."}, {"type": "paragraph", "text": "§. 120. Meditiren. Unter Meditiren ist Nachdenken oder ein methodisches Denken zu verstehen. Das Meditiren muß alles Lesen und Lernen begleiten, und es ist hierzu erforderlich, daß man zuvörderst vorläufige Untersuchungen anstelle und sodann seine Gedanken in Ordnung bringe oder nach einer Methode verbinde."}], "markers": [{"system": "AA", "band": "IX", "page": 150, "ref": "IX150"}], "running_header": "II. Befördg. d. Vollkommenheit d. Erkenntnisses durch logische Eintheilung der Begriffe [§§ 110 - 120]"}]};
